import axiosClient from './axiosClient';

export const adminApi = {
  // Learning Paths
  getLearningPaths: async () => {
    const response = await axiosClient.get('/admin/learning-paths');
    return response.data;
  },

  getLearningPathDetails: async (pathId: number) => {
    const response = await axiosClient.get(`/admin/learning-paths/${pathId}`);
    return response.data;
  },

  deleteLearningPath: async (pathId: number) => {
    const response = await axiosClient.delete(`/admin/learning-paths/${pathId}`);
    return response.data;
  },

  getLearningPathSteps: async (pathId: number) => {
    const response = await axiosClient.get(`/admin/learning-paths/${pathId}/steps`);
    return response.data;
  },

  updateLearningStep: async (pathId: number, stepId: number, stepData: any) => {
    const response = await axiosClient.put(`/admin/learning-paths/${pathId}/steps/${stepId}`, stepData);
    return response.data;
  },

  deleteLearningStep: async (pathId: number, stepId: number) => {
    const response = await axiosClient.delete(`/admin/learning-paths/${pathId}/steps/${stepId}`);
    return response.data;
  },


  createLearningStep: async (pathId: number, stepData: any) => {
    const response = await axiosClient.post(`/admin/learning-paths/${pathId}/steps`, stepData);
    return response.data;
  },


  // Learning Resources
  getLearningResources: async (skillId?: number) => {
    const params = skillId ? { skill_id: skillId } : {};
    const response = await axiosClient.get('/admin/learning-resources', { params });
    return response.data;
  },

  createLearningResource: async (resourceData: any) => {
    const response = await axiosClient.post('/admin/learning-resources', resourceData);
    return response.data;
  },

  updateLearningResource: async (resourceId: number, resourceData: any) => {
    const response = await axiosClient.put(`/admin/learning-resources/${resourceId}`, resourceData);
    return response.data;
  },

  deleteLearningResource: async (resourceId: number) => {
    const response = await axiosClient.delete(`/admin/learning-resources/${resourceId}`);
    return response.data;
  },

  // Users
  getUsers: async (skip = 0, limit = 100) => {
    const response = await axiosClient.get('/admin/users', {
      params: { skip, limit }
    });
    return response.data;
  },

  getUserDetails: async (userId: number) => {
    const response = await axiosClient.get(`/admin/users/${userId}`);
    return response.data;
  },

  createUser: async (userData: any) => {
    const response = await axiosClient.post('/admin/users', userData);
    return response.data;
  },

  updateUser: async (userId: number, userData: any) => {
    const response = await axiosClient.put(`/admin/users/${userId}`, userData);
    return response.data;
  },

  deleteUser: async (userId: number) => {
    const response = await axiosClient.delete(`/admin/users/${userId}`);
    return response.data;
  },

  updateUserRole: async (userId: number, newRole: string) => {
    const response = await axiosClient.put(`/admin/users/${userId}/role`, null, {
      params: { new_role: newRole }
    });
    return response.data;
  },

  // Assessments
  getAssessments: async (skip = 0, limit = 100) => {
    const response = await axiosClient.get('/admin/assessments', {
      params: { skip, limit }
    });
    return response.data;
  },

  // Stats
  getStats: async () => {
    const response = await axiosClient.get('/admin/stats');
    return response.data;
  },

  getOverviewMetrics: async () => {
    const response = await axiosClient.get('/admin/overview-metrics');
    return response.data;
  },

  getHealth: async () => {
    const response = await axiosClient.get('/admin/health');
    return response.data;
  },

  getMetrics: async () => {
    const response = await axiosClient.get('/admin/metrics');
    return response.data;
  },
};

import axios from 'axios';

// Use environment variable if available, otherwise use nginx proxy path
// For Docker/Production, use relative path '/api' which nginx will proxy
const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || "http://localhost:5000";
// const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || "http://10.109.91.179:5000";



const axiosClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Request interceptor to add JWT token
axiosClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('authToken');
    const user = localStorage.getItem('user');

// Debug logging removed to reduce noise

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);


// Response interceptor for global error handling and retry
axiosClient.interceptors.response.use(
  (response) => response,
  async (error) => {
    const config = error.config as any;
    if (config && !config._retry && !error.response && error.code !== 'ECONNABORTED') {
      config._retry = true;
      // Retry once for network errors
      return axiosClient.request(config);
    }

    if (error.response?.status === 401) {
      // Token expired or invalid, redirect to login
      localStorage.removeItem('authToken');
      localStorage.removeItem('refreshToken');
      localStorage.removeItem('user');
      window.location.href = '/login';

    } else if (error.response?.status === 403) {
      // Forbidden - check if user is actually admin
      const userStr = localStorage.getItem('user');
      if (userStr) {
        try {
          const user = JSON.parse(userStr);
          console.error('Access forbidden. User role:', user.role);
          if (user.role !== 'admin') {
            console.error('User is not admin. Redirecting to dashboard.');
            window.location.href = '/dashboard';
          }
        } catch (e) {
          console.error('Failed to parse user data');
        }
      }

    } else if (error.response?.status === 404) {
      // Not found - let the API layer handle it
      // The skills.api.ts already catches 404 and returns null
    }
    return Promise.reject(error);


  }
);

export default axiosClient;

import axiosClient from './axiosClient';
import type { Certificate, OpenBadgeAssertion, OpenBadgeResponse, OpenBadgePackage } from '@/types';

export const certificateApi = {
  getUserCertificates: async (): Promise<{ certificates: Certificate[]; count: number }> => {
    const response = await axiosClient.get('/certificate/user');
    return response.data;
  },

  getCertificate: async (certificateId: number): Promise<Certificate> => {
    const response = await axiosClient.get(`/certificate/${certificateId}`);
    return response.data;
  },

  generateCertificate: async (pathId: number): Promise<{ message: string; certificate: Certificate }> => {
    const response = await axiosClient.post(`/certificate/generate/${pathId}`);
    return response.data;
  },

  getCertificateForPath: async (pathId: number): Promise<{ exists: boolean; certificate: Certificate | null }> => {
    const response = await axiosClient.get(`/certificate/path/${pathId}`);
    return response.data;
  },

  regenerateQRCode: async (certificateId: number): Promise<{ message: string; qr_code: boolean; certificate: Certificate }> => {
    const response = await axiosClient.post(`/certificate/regenerate-qr/${certificateId}`);
    return response.data;
  },

  // Open Badge 2.0 Methods
  getIssuerMetadata: async (): Promise<any> => {
    const response = await axiosClient.get('/certificate/.well-known/issuer.json');
    return response.data;
  },

  getBadgeClass: async (roleTitle: string): Promise<any> => {
    const response = await axiosClient.get(`/certificate/badge/${encodeURIComponent(roleTitle)}`);
    return response.data;
  },

  getAssertion: async (certificateId: string): Promise<OpenBadgeAssertion> => {
    const response = await axiosClient.get(`/certificate/assertions/${certificateId}`);
    return response.data;
  },

  getOpenBadgePackage: async (certificateId: number): Promise<OpenBadgeResponse> => {
    const response = await axiosClient.get(`/certificate/openbadge/${certificateId}`);
    return response.data;
  },

  downloadOpenBadgeJson: async (certificateId: number): Promise<OpenBadgeAssertion> => {
    const response = await axiosClient.get(`/certificate/openbadge/${certificateId}/download`);
    return response.data;
  },

  getCertificateMetadata: async (certificateId: number): Promise<any> => {
    const response = await axiosClient.get(`/certificate/${certificateId}/metadata`);
    return response.data;
  },

  anchorToBlockchain: async (certificateId: number, network: string = 'sepolia'): Promise<any> => {
    const response = await axiosClient.post(`/certificate/anchor/${certificateId}?network=${network}`);
    return response.data;
  },

  verifyOnBlockchain: async (certificateId: string, network: string = 'sepolia'): Promise<any> => {
    const response = await axiosClient.post(`/certificate/verify-blockchain/${certificateId}?network=${network}`);
    return response.data;
  },
};

import axiosClient from './axiosClient';
import type { LearningPath } from '@/types';

export const learningApi = {
  getPath: async (): Promise<LearningPath | null> => {
    try {
      const response = await axiosClient.get<{ paths: LearningPath[]; count: number }>('/learning/paths');
      // Return the first path if available, otherwise null
      return response.data.paths.length > 0 ? response.data.paths[0] : null;
    } catch (error: any) {
      if (error.response?.status === 404) {
        return null;
      }
      throw error;
    }
  },


  generatePath: async (roleId: number): Promise<LearningPath> => {
    const response = await axiosClient.post<LearningPath>('/learning/paths', { roleId });
    return response.data;
  },

  markStepComplete: async (pathId: number, stepId: number): Promise<LearningPath> => {
    const response = await axiosClient.post<LearningPath>(`/learning/path/${pathId}/step/${stepId}/complete`);
    return response.data;
  },

  // Check if step can be completed (sequential + assessment requirements)
  canCompleteStep: async (pathId: number, stepId: number): Promise<{
    can_complete: boolean;
    reason: string;
    previous_step_completed: boolean;
    assessment_passed: boolean;
    step_order: number;
    total_steps: number;
  }> => {
    const response = await axiosClient.get(`/learning/path/${pathId}/step/${stepId}/can-complete`);
    return response.data;
  },

  // Get assessment questions for a step
  getStepAssessment: async (pathId: number, stepId: number): Promise<{
    step_id: number;
    skill_name: string;
    target_level: string;
    questions: Array<{
      id: number;
      question: string;
      options: string[];
    }>;
    total_questions: number;
    assessment_already_passed: boolean;
  }> => {
    const response = await axiosClient.get(`/learning/path/${pathId}/step/${stepId}/assessment`);
    return response.data;
  },

  // Submit assessment answers
  submitStepAssessment: async (pathId: number, stepId: number, answers: string[]): Promise<{
    passed: boolean;
    score: number;
    correct_answers: number;
    total_questions: number;
    message: string;
  }> => {
    const response = await axiosClient.post(`/learning/path/${pathId}/step/${stepId}/assessment`, {
      answers,
    });
    return response.data;
  },
};

export default learningApi;

import apiClient from '@/api/axiosClient';
import type { ProfileResponse, ProfileUpdate } from '@/types/profile';

export const profileApi = {
  getProfile: async (): Promise<ProfileResponse> => {
    try {
      const response = await apiClient.get('/profile/');
      return response.data;
    } catch (error: any) {
      console.error('Profile get error:', error);
      const status = error.response?.status;
      if (status === 500) {
        throw new Error('Server error (500) - Profile service temporarily unavailable. Please try again.');
      } else if (status === 0 || error.message.includes('CORS')) {
        throw new Error('CORS/Network error - Check if backend is running on localhost:5000 and restart browser.');
      }
      throw error;
    }
  },

  updateProfile: async (data: ProfileUpdate): Promise<ProfileResponse> => {
    // Ensure phone is included (null explicitly)
    const updateData = data; // phone now in ProfileUpdate
    try {
      const response = await apiClient.put('/profile/', updateData);
      return response.data;
    } catch (error: any) {
      console.error('Profile update error:', error);
      const status = error.response?.status;
      if (status === 500) {
        throw new Error('Server error (500) - Profile update failed. Check backend logs.');
      } else if (status === 0 || error.message.includes('CORS')) {
        throw new Error('CORS/Network error - Verify backend running and CORS settings.');
      }
      throw error;
    }
  },

  createProfile: async (data: ProfileUpdate): Promise<ProfileResponse> => {
    const updateData = data; // phone now in ProfileUpdate
    const response = await apiClient.post('/profile/', updateData);
    return response.data;
  },

  deleteProfile: async (): Promise<{ message: string; user_id: number }> => {
    const response = await apiClient.delete('/profile/');
    return response.data;
  },

};

