import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';

import { authApi, AuthResponse } from '@/api/auth.api';

interface User {
  id: number;
  email: string;
  name: string;
  role: 'user' | 'admin';
}

interface AuthContextType {
  user: User | null;
  token: string | null;
  login: (email: string, password: string) => Promise<boolean>;
  register: (email: string, name: string, password: string) => Promise<boolean>;
  logout: () => Promise<void>;
  isAuthenticated: boolean;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

interface AuthProviderProps {
  children: ReactNode;
}

export const AuthProvider: React.FC<AuthProviderProps> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const storedToken = localStorage.getItem('authToken');
    const storedUser = localStorage.getItem('user');
    
    if (storedToken && storedUser && storedUser !== 'undefined') {
      setToken(storedToken);
      try {
        const parsedUser = JSON.parse(storedUser) as User;
        setUser(parsedUser);
      } catch (e) {
        console.error('Error parsing stored user:', e);
        localStorage.removeItem('user');
      }
      // Delay profile fetch to avoid race conditions, only if cached user lacks full profile fields
      setTimeout(() => {
        if (token) fetchProfile().catch(() => {}); // Silent fail for initial load
      }, 100);
    } else {
      setIsLoading(false);
    }
  }, []);

  const fetchProfile = async (silent = false) => {
    try {
      const profile = await authApi.getProfile();
      // Update user with full profile
      setUser({
        ...user,
        ...profile
      } as User);
      localStorage.setItem('user', JSON.stringify(profile));
    } catch (error: any) {
      console.error('Profile fetch error:', error);
      if (error.response?.status === 401 || error.response?.status === 404) {
        // Token/profile invalid
        localStorage.removeItem('authToken');
        localStorage.removeItem('refreshToken');
        localStorage.removeItem('user');
        setToken(null);
        setUser(null);
        if (!silent) {
          // Optional: try refresh if refreshToken exists
          // await authApi.refreshToken();
        }
      }
    } finally {
      if (!silent) setIsLoading(false);
    }
  };

  const login = async (email: string, password: string): Promise<boolean> => {
    try {
      const data: AuthResponse = await authApi.login({ email, password });
      localStorage.setItem('authToken', data.access_token);
      if (data.refresh_token) {
        localStorage.setItem('refreshToken', data.refresh_token);
      }
      localStorage.setItem('user', JSON.stringify(data.user));
      
      setToken(data.access_token);
      setUser(data.user);
      setIsLoading(false);
      return true;
    } catch (error) {
      console.error('Login error:', error);
      return false;
    }
  };

  const register = async (email: string, name: string, password: string): Promise<boolean> => {
    try {
      const data: AuthResponse = await authApi.register({ email, name, password });
      localStorage.setItem('authToken', data.access_token);
      if (data.refresh_token) {
        localStorage.setItem('refreshToken', data.refresh_token);
      }
      setToken(data.access_token);
      setUser(data.user);
      return true;
    } catch (error) {
      console.error('Register error:', error);
      return false;
    }
  };

  const logout = async () => {
    await authApi.logout();
    localStorage.removeItem('authToken');
    localStorage.removeItem('refreshToken');
    localStorage.removeItem('user');
    setToken(null);
    setUser(null);
  };

  const value: AuthContextType = {
    user,
    token,
    login,
    register,
    logout,
    isAuthenticated: !!token,
    isLoading,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { api } from '@/lib/api';
import { cn } from '@/lib/utils';
import type { ProfileResponse } from '@/types/profile';

interface ProfileProps {
  collapsed: boolean;
}

interface User {
  id: string;
  email: string;
  name: string;
  role: string;
}

export function Profile({ collapsed }: ProfileProps) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchProfile = async () => {
      const token = localStorage.getItem('authToken');
      if (!token) {
        setUser(null);
        setLoading(false);
        return;
      }

      try {
        const response = await api.getProfile(token);
        const profileData = response.data as any;
        if (profileData && !profileData.error) {
          setUser({
            id: profileData.id?.toString() || '1',
            email: profileData.email || '',
            name: profileData.name || profileData.first_name || profileData.email?.split('@')[0] || 'User',
            role: profileData.role || profileData.currentRole || 'User'
          });
        } else {
          console.warn('Invalid profile response:', profileData);
          setUser(null);
        }
      } catch (error) {
        console.error('Failed to fetch profile:', error);
        setUser(null);
      } finally {
        setLoading(false);
      }
    };

    fetchProfile();

    // Listen for auth changes
    const handleAuthChange = () => {
      fetchProfile();
    };

    window.addEventListener('authChange', handleAuthChange);

    return () => {
      window.removeEventListener('authChange', handleAuthChange);
    };
  }, []); 

  const getInitials = (name?: string, email?: string): string => {
    if (!name?.trim()) {
      if (email) {
        const localPart = email.split('@')[0];
        return localPart.slice(0, 2).toUpperCase();
      }
      return '?';
    }
    return name
      .split(' ')
      .map((word) => word.charAt(0).toUpperCase())
      .join('')
      .slice(0, 2);
  };

  if (loading) {
    return (
      <div className={cn(
        "h-16 flex items-center border-b border-sidebar-border px-4",
        collapsed ? "justify-center" : "gap-3"
      )}>
        <div className="w-8 h-8 rounded-full bg-muted animate-pulse" />
        {!collapsed && (
          <div className="flex flex-col gap-1">
            <div className="h-4 bg-muted rounded animate-pulse w-20" />
            <div className="h-3 bg-muted rounded animate-pulse w-16" />
          </div>
        )}
      </div>
    );
  }

  if (!user) {
    return (
      <div className={cn(
        "h-16 flex items-center border-b border-sidebar-border px-4",
        collapsed ? "justify-center" : "gap-3"
      )}>
        <Avatar className="w-8 h-8">
          <AvatarFallback className="bg-muted text-muted-foreground">?</AvatarFallback>
        </Avatar>
        {!collapsed && (
          <div className="flex flex-col">
            <span className="font-display font-bold text-sidebar-foreground">Guest</span>
            <span className="text-xs text-sidebar-foreground/60">Please login</span>
          </div>
        )}
      </div>
    );
  }

  return (
    <div
      className={cn(
        "h-16 flex items-center border-b border-sidebar-border px-4 cursor-pointer hover:bg-sidebar-accent/50 transition-colors",
        collapsed ? "justify-center" : "gap-3"
      )}
onClick={() => navigate('/settings')}
    >
      <Avatar className="w-8 h-8">
        <AvatarFallback className="bg-primary text-primary-foreground">
          {getInitials(user.name, user.email)}
        </AvatarFallback>
      </Avatar>
      {!collapsed && (
        <div className="flex flex-col">
          <span className="font-display font-bold text-sidebar-foreground">{user.name || user.email?.split('@')[0] || 'User'}</span>
          <span className="text-xs text-sidebar-foreground/60 capitalize">{user.role || 'User'}</span>
        </div>
      )}
    </div>
  );
}

