export default function CareerAnalytics() {
  const { toast } = useToast();
  const [stats, setStats] = useState<CareerStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [selectedAssessment, setSelectedAssessment] = useState<UserAssessment | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    fetchCareerStats();
  }, []);

  const fetchCareerStats = async () => {
    try {
      setLoading(true);
      // Fetch assessments from the admin API
      const response = await axiosClient.get('/admin/assessments?limit=1000');
      
      // Process the data to create stats
      const assessments = response.data.assessments || [];
      
      // Calculate stats
      const completed = assessments.filter((a: any) => a.status === 'completed');
      const avgScore = completed.length > 0 
        ? completed.reduce((sum: number, a: any) => sum + (a.score || 0), 0) / completed.length 
        : 0;

      // Get skill counts
      const skillCounts: Record<string, number> = {};
      assessments.forEach((a: any) => {
        const skillName = a.skill_name || 'Unknown';
        skillCounts[skillName] = (skillCounts[skillName] || 0) + 1;
      });

      // Get recent assessments
      const recent = assessments
        .sort((a: any, b: any) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
        .slice(0, 10);

      setStats({
        total_assessments: assessments.length,
        completed_assessments: completed.length,
        average_score: Math.round(avgScore),
        top_skills: Object.entries(skillCounts)
          .map(([name, count]) => ({ name, count }))
          .sort((a, b) => b.count - a.count)
          .slice(0, 5),
        career_paths: [], // Would need career data
        recent_assessments: recent
      });
    } catch (error) {
      console.error('Error fetching career stats:', error);
      toast({
        title: "Error",
        description: "Failed to fetch career analytics",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const exportData = () => {
    if (!stats) return;
    
    const csvContent = [
      ['User ID', 'User Name', 'Email', 'Skill', 'Score', 'Status', 'Completed At'].join(','),
      ...stats.recent_assessments.map(a => [
        a.user_id,
        `"${a.user_name}"`,
        a.user_email,
        `"${a.skill_name}"`,
        a.score,
        a.status,
        a.completed_at
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `career_analytics_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    link.remove();

    toast({
      title: "Success",
      description: "Analytics data exported",
    });
  };

  const filteredAssessments = stats?.recent_assessments.filter(assessment => {
    const matchesSearch = 
      assessment.user_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      assessment.user_email.toLowerCase().includes(searchQuery.toLowerCase()) ||
      assessment.skill_name.toLowerCase().includes(searchQuery.toLowerCase());
    
    const matchesStatus = statusFilter === 'all' || assessment.status === statusFilter;
    
    return matchesSearch && matchesStatus;
  }) || [];

  const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884D8'];

  if (loading) {
    return (
      <div className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <Skeleton className="h-32" />
          <Skeleton className="h-32" />
          <Skeleton className="h-32" />
          <Skeleton className="h-32" />
        </div>
        <Skeleton className="h-64" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header Actions */}
      <div className="flex justify-between items-center">
        <div className="flex gap-2">
          <Button variant="outline" onClick={fetchCareerStats}>
            <RefreshCw className="h-4 w-4 mr-2" />
            Refresh
          </Button>
          <Button variant="outline" onClick={exportData}>
            <Download className="h-4 w-4 mr-2" />
            Export CSV
          </Button>
        </div>
      </div>

      {/* Stats Overview */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <Target className="h-4 w-4" />
              Total Assessments
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">{stats?.total_assessments || 0}</div>
            <p className="text-xs text-muted-foreground mt-1">
              All time assessments
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <Award className="h-4 w-4" />
              Completed
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">{stats?.completed_assessments || 0}</div>
            <p className="text-xs text-muted-foreground mt-1">
              Successfully completed
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <TrendingUp className="h-4 w-4" />
              Average Score
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">{stats?.average_score || 0}%</div>
            <p className="text-xs text-muted-foreground mt-1">
              Across all assessments
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <Users className="h-4 w-4" />
              Active Users
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">
              {new Set(stats?.recent_assessments.map(a => a.user_id)).size || 0}
            </div>
            <p className="text-xs text-muted-foreground mt-1">
              Users with assessments
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Top Skills Chart */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <GraduationCap className="h-5 w-5" />
              Top Skills Assessed
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={stats?.top_skills || []}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                  <YAxis />
                  <Tooltip />
                  <Bar dataKey="count" fill="#8884d8" />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>

        {/* Assessment Status Distribution */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Briefcase className="h-5 w-5" />
              Assessment Status
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={[
                      { name: 'Completed', value: stats?.completed_assessments || 0 },
                      { name: 'Pending', value: (stats?.total_assessments || 0) - (stats?.completed_assessments || 0) }
                    ]}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                    outerRadius={80}
                    fill="#8884d8"
                    dataKey="value"
                  >
                    {stats && [
                      <Cell key="completed" fill="#00C49F" />,
                      <Cell key="pending" fill="#FFBB28" />
                    ]}
                  </Pie>
                  <Tooltip />
                </PieChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Recent Assessments Table */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center justify-between">
            <span>Recent Assessments</span>
            <Badge variant="outline">{filteredAssessments.length} results</Badge>
          </CardTitle>
        </CardHeader>
        <CardContent>
          {/* Filters */}
          <div className="flex flex-col sm:flex-row gap-4 mb-6">
            <div className="flex-1 relative">
              <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Search by user, email, or skill..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>
            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="w-40">
                <SelectValue placeholder="Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Status</SelectItem>
                <SelectItem value="completed">Completed</SelectItem>
                <SelectItem value="pending">Pending</SelectItem>
                <SelectItem value="in_progress">In Progress</SelectItem>
              </SelectContent>
            </Select>
          </div>

          {/* Table */}
          <div className="space-y-2">
            {filteredAssessments.length === 0 ? (
              <Alert>
                <AlertDescription>No assessments found</AlertDescription>
              </Alert>
            ) : (
              filteredAssessments.map((assessment) => (
                <div
                  key={assessment.id}
                  className="flex items-center justify-between p-4 border rounded-lg hover:bg-muted/50 transition-colors"
                >
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <p className="font-medium">{assessment.user_name}</p>
                      <span className="text-muted-foreground">ΓÇó</span>
                      <p className="text-sm text-muted-foreground">{assessment.user_email}</p>
                    </div>
                    <div className="flex items-center gap-2 text-sm">
                      <Badge variant="outline">{assessment.skill_name}</Badge>
                      <Badge 
                        variant={assessment.status === 'completed' ? 'default' : 'outline'}
                        className={assessment.status === 'completed' ? 'bg-green-500' : ''}
                      >
                        {assessment.status}
                      </Badge>
                      {assessment.score > 0 && (
                        <span className="text-muted-foreground">
                          Score: {assessment.score}%
                        </span>
                      )}
                    </div>
                  </div>
                  <div className="flex items-center gap-4">
                    <span className="text-sm text-muted-foreground">
                      {new Date(assessment.completed_at).toLocaleDateString()}
                    </span>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => {
                        setSelectedAssessment(assessment);
                        setIsModalOpen(true);
                      }}
                    >
                      <Eye className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))
            )}
          </div>
        </CardContent>
      </Card>

      {/* Assessment Detail Modal */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Assessment Details</DialogTitle>
          </DialogHeader>
          {selectedAssessment && (
            <div className="space-y-4 py-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-sm text-muted-foreground">User</p>
                  <p className="font-medium">{selectedAssessment.user_name}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Email</p>
                  <p className="font-medium">{selectedAssessment.user_email}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Skill</p>
                  <p className="font-medium">{selectedAssessment.skill_name}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Status</p>
                  <Badge 
                    variant={selectedAssessment.status === 'completed' ? 'default' : 'outline'}
                    className={selectedAssessment.status === 'completed' ? 'bg-green-500' : ''}
                  >
                    {selectedAssessment.status}
                  </Badge>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Score</p>
                  <p className="font-medium">{selectedAssessment.score}%</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Completed</p>
                  <p className="font-medium">
                    {new Date(selectedAssessment.completed_at).toLocaleString()}
                  </p>
                </div>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Plus, Trash2, Save } from 'lucide-react';
import axiosClient from '@/api/axiosClient';

interface CareerRecommendation {
  id?: number;
  title: string;
  description: string;
  industry: string;
  match_score: number;
}

interface CareerRecommendationEditorProps {
  userId: number | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: () => void;
}

const CareerRecommendationEditor = ({ userId, isOpen, onClose, onSave }: CareerRecommendationEditorProps) => {
  const [recommendations, setRecommendations] = useState<CareerRecommendation[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (userId && isOpen) {
      fetchCurrentRecommendations();
    }
  }, [userId, isOpen]);

  const fetchCurrentRecommendations = async () => {
    if (!userId) return;

    try {
      setLoading(true);
      const response = await axiosClient.get(`/admin/users/${userId}`);
      setRecommendations(response.data.careerRecommendations || []);
      setError(null);
    } catch (error: any) {
      setError(error.response?.data?.detail || 'Failed to fetch recommendations');
    } finally {
      setLoading(false);
    }
  };

  const addNewRecommendation = () => {
    setRecommendations([...recommendations, {
      title: '',
      description: '',
      industry: '',
      match_score: 0
    }]);
  };

  const updateRecommendation = (index: number, field: keyof CareerRecommendation, value: string | number) => {
    const updated = [...recommendations];
    updated[index] = { ...updated[index], [field]: value };
    setRecommendations(updated);
  };

  const removeRecommendation = (index: number) => {
    setRecommendations(recommendations.filter((_, i) => i !== index));
  };

  const saveRecommendations = async () => {
    if (!userId) return;

    try {
      setSaving(true);
      await axiosClient.put(`/admin/users/${userId}/career-recommendations`, {
        recommendations: recommendations
      });
      onSave();
      onClose();
    } catch (error: any) {
      setError(error.response?.data?.detail || 'Failed to save recommendations');
    } finally {
      setSaving(false);
    }
  };

  const industries = [
    'Technology',
    'Healthcare',
    'Finance',
    'Education',
    'Manufacturing',
    'Retail',
    'Consulting',
    'Marketing',
    'Engineering',
    'Other'
  ];

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Edit Career Recommendations</DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {error && (
            <Alert variant="destructive">
              <AlertDescription>{error}</AlertDescription>
            </Alert>
          )}

          {loading ? (
            <div className="space-y-4">
              {Array.from({ length: 3 }).map((_, i) => (
                <Card key={i}>
                  <CardContent className="pt-6">
                    <div className="space-y-4">
                      <Skeleton className="h-4 w-48" />
                      <Skeleton className="h-20 w-full" />
                      <div className="flex gap-4">
                        <Skeleton className="h-10 w-32" />
                        <Skeleton className="h-10 w-24" />
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          ) : (
            <>
              <div className="flex justify-between items-center">
                <div>
                  <h3 className="text-lg font-semibold">Career Recommendations</h3>
                  <p className="text-sm text-muted-foreground">
                    Manage career recommendations for this user
                  </p>
                </div>
                <Button onClick={addNewRecommendation}>
                  <Plus className="h-4 w-4 mr-2" />
                  Add Recommendation
                </Button>
              </div>

              <div className="space-y-4">
                {recommendations.length === 0 ? (
                  <div className="text-center py-8 text-muted-foreground">
                    No career recommendations. Click "Add Recommendation" to create one.
                  </div>
                ) : (
                  recommendations.map((rec, index) => (
                    <Card key={index}>
                      <CardHeader>
                        <div className="flex items-center justify-between">
                          <CardTitle className="text-base">
                            Recommendation #{index + 1}
                          </CardTitle>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => removeRecommendation(index)}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </CardHeader>
                      <CardContent className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div className="space-y-2">
                            <Label htmlFor={`title-${index}`}>Job Title</Label>
                            <Input
                              id={`title-${index}`}
                              value={rec.title}
                              onChange={(e) => updateRecommendation(index, 'title', e.target.value)}
                              placeholder="e.g. Software Engineer"
                            />
                          </div>
                          <div className="space-y-2">
                            <Label htmlFor={`industry-${index}`}>Industry</Label>
                            <Select
                              value={rec.industry}
                              onValueChange={(value) => updateRecommendation(index, 'industry', value)}
                            >
                              <SelectTrigger>
                                <SelectValue placeholder="Select industry" />
                              </SelectTrigger>
                              <SelectContent>
                                {industries.map((industry) => (
                                  <SelectItem key={industry} value={industry}>
                                    {industry}
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                          </div>
                        </div>

                        <div className="space-y-2">
                          <Label htmlFor={`description-${index}`}>Description</Label>
                          <Textarea
                            id={`description-${index}`}
                            value={rec.description}
                            onChange={(e) => updateRecommendation(index, 'description', e.target.value)}
                            placeholder="Describe the role and why it matches the user's profile..."
                            rows={3}
                          />
                        </div>

                        <div className="flex items-center gap-4">
                          <div className="space-y-2 flex-1">
                            <Label htmlFor={`score-${index}`}>Match Score (%)</Label>
                            <Input
                              id={`score-${index}`}
                              type="number"
                              min="0"
                              max="100"
                              value={rec.match_score}
                              onChange={(e) => updateRecommendation(index, 'match_score', parseInt(e.target.value) || 0)}
                            />
                          </div>
                          <div className="flex items-end">
                            <Badge variant="outline" className="px-3 py-1">
                              {rec.match_score}% Match
                            </Badge>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  ))
                )}
              </div>

              <div className="flex justify-end gap-4 pt-4 border-t">
                <Button variant="outline" onClick={onClose}>
                  Cancel
                </Button>
                <Button onClick={saveRecommendations} disabled={saving}>
                  <Save className="h-4 w-4 mr-2" />
                  {saving ? 'Saving...' : 'Save Changes'}
                </Button>
              </div>
            </>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default CareerRecommendationEditor;

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { 
  Plus, 
  Edit2, 
  Trash2, 
  ChevronDown, 
  ChevronRight, 
  FolderTree, 
  Code2, 
  Server, 
  Layout, 
  Brain, 
  Cloud, 
  Users,
  Loader2,
  AlertCircle
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { useToast } from '@/hooks/use-toast';
import { domainsApi, Domain, Skill } from '@/api/domains.api';

const domainIcons: Record<string, React.ComponentType<{ className?: string }>> = {
  'Frontend': Code2,
  'Backend': Server,
  'Full Stack': Layout,
  'AI / ML': Brain,
  'DevOps': Cloud,
  'QA Engineer': Users,
  'default': FolderTree,
};

export default function DomainSkillsManager() {
  const [domains, setDomains] = useState<Domain[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedDomains, setExpandedDomains] = useState<Set<number>>(new Set());
  const [isDomainDialogOpen, setIsDomainDialogOpen] = useState(false);
  const [isSkillDialogOpen, setIsSkillDialogOpen] = useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [editingDomain, setEditingDomain] = useState<Domain | null>(null);
  const [editingSkill, setEditingSkill] = useState<Skill | null>(null);
  const [deletingItem, setDeletingItem] = useState<{ type: 'domain' | 'skill'; item: Domain | Skill } | null>(null);
  const [selectedDomainForSkill, setSelectedDomainForSkill] = useState<number | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Form states
  const [domainName, setDomainName] = useState('');
  const [skillName, setSkillName] = useState('');
  const [skillDescription, setSkillDescription] = useState('');
  const [skillDemandLevel, setSkillDemandLevel] = useState(0);

  const { toast } = useToast();

  useEffect(() => {
    loadDomains();
  }, []);

  const loadDomains = async () => {
    try {
      setLoading(true);
      const response = await domainsApi.getAllDomains(true);
      setDomains(response.domains);
    } catch (error) {
      console.error('Error loading domains:', error);
      toast({
        title: "Error",
        description: "Failed to load domains and skills",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const toggleDomainExpansion = (domainId: number) => {
    setExpandedDomains(prev => {
      const newSet = new Set(prev);
      if (newSet.has(domainId)) {
        newSet.delete(domainId);
      } else {
        newSet.add(domainId);
      }
      return newSet;
    });
  };

  // Domain CRUD operations
  const openCreateDomainDialog = () => {
    setEditingDomain(null);
    setDomainName('');
    setIsDomainDialogOpen(true);
  };

  const openEditDomainDialog = (domain: Domain) => {
    setEditingDomain(domain);
    setDomainName(domain.name);
    setIsDomainDialogOpen(true);
  };

  const handleSaveDomain = async () => {
    if (!domainName.trim()) {
      toast({
        title: "Validation Error",
        description: "Domain name is required",
        variant: "destructive",
      });
      return;
    }

    try {
      setIsSubmitting(true);
      if (editingDomain) {
        await domainsApi.updateDomain(editingDomain.id, { name: domainName });
        toast({
          title: "Success",
          description: "Domain updated successfully",
        });
      } else {
        await domainsApi.createDomain({ name: domainName });
        toast({
          title: "Success",
          description: "Domain created successfully",
        });
      }
      setIsDomainDialogOpen(false);
      loadDomains();
    } catch (error: any) {
      console.error('Error saving domain:', error);
      toast({
        title: "Error",
        description: error.response?.data?.detail || "Failed to save domain",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  // Skill CRUD operations
  const openCreateSkillDialog = (domainId: number) => {
    setEditingSkill(null);
    setSelectedDomainForSkill(domainId);
    setSkillName('');
    setSkillDescription('');
    setSkillDemandLevel(0);
    setIsSkillDialogOpen(true);
  };

  const openEditSkillDialog = (skill: Skill) => {
    setEditingSkill(skill);
    setSelectedDomainForSkill(skill.domain_id);
    setSkillName(skill.name);
    setSkillDescription(skill.description || '');
    setSkillDemandLevel(skill.demand_level || 0);
    setIsSkillDialogOpen(true);
  };

  const handleSaveSkill = async () => {
    if (!skillName.trim()) {
      toast({
        title: "Validation Error",
        description: "Skill name is required",
        variant: "destructive",
      });
      return;
    }

    // Only require domain selection when creating a new skill
    if (!editingSkill && !selectedDomainForSkill) {
      toast({
        title: "Validation Error",
        description: "Domain is required",
        variant: "destructive",
      });
      return;
    }


    try {
      setIsSubmitting(true);
      if (editingSkill) {
        await domainsApi.updateSkill(editingSkill.id, {
          name: skillName,
          description: skillDescription,
          domain_id: selectedDomainForSkill,
          demand_level: skillDemandLevel,
        });
        toast({
          title: "Success",
          description: "Skill updated successfully",
        });
      } else {
        await domainsApi.createSkill({
          name: skillName,
          description: skillDescription,
          domain_id: selectedDomainForSkill,
          demand_level: skillDemandLevel,
        });
        toast({
          title: "Success",
          description: "Skill created successfully",
        });
      }
      setIsSkillDialogOpen(false);
      loadDomains();
    } catch (error: any) {
      console.error('Error saving skill:', error);
      toast({
        title: "Error",
        description: error.response?.data?.detail || "Failed to save skill",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  // Delete operations
  const openDeleteDialog = (type: 'domain' | 'skill', item: Domain | Skill) => {
    setDeletingItem({ type, item });
    setIsDeleteDialogOpen(true);
  };

  const handleDelete = async () => {
    if (!deletingItem) return;

    try {
      setIsSubmitting(true);
      if (deletingItem.type === 'domain') {
        await domainsApi.deleteDomain(deletingItem.item.id);
        toast({
          title: "Success",
          description: "Domain and its skills deleted successfully",
        });
      } else {
        await domainsApi.deleteSkill(deletingItem.item.id);
        toast({
          title: "Success",
          description: "Skill deleted successfully",
        });
      }
      setIsDeleteDialogOpen(false);
      loadDomains();
    } catch (error: any) {
      console.error('Error deleting:', error);
      toast({
        title: "Error",
        description: error.response?.data?.detail || "Failed to delete",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const getDomainIcon = (domainName: string) => {
    const IconComponent = domainIcons[domainName] || domainIcons['default'];
    return <IconComponent className="w-5 h-5" />;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Domain & Skills Management</h2>
          <p className="text-muted-foreground">
            Manage career domains and their associated skills dynamically
          </p>
        </div>
        <Button onClick={openCreateDomainDialog}>
          <Plus className="w-4 h-4 mr-2" />
          Add Domain
        </Button>
      </div>

      {/* Domains List */}
      <div className="space-y-4">
        {domains.length === 0 ? (
          <Card>
            <CardContent className="p-8 text-center">
              <FolderTree className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
              <h3 className="text-lg font-semibold mb-2">No Domains Found</h3>
              <p className="text-muted-foreground mb-4">
                Get started by creating your first domain
              </p>
              <Button onClick={openCreateDomainDialog}>
                <Plus className="w-4 h-4 mr-2" />
                Create Domain
              </Button>
            </CardContent>
          </Card>
        ) : (
          domains.map((domain) => {
            const isExpanded = expandedDomains.has(domain.id);
            const skillsCount = domain.skills?.length || 0;

            return (
              <Card key={domain.id} className="overflow-hidden">
                <CardHeader className="pb-3">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center text-primary">
                        {getDomainIcon(domain.name)}
                      </div>
                      <div>
                        <CardTitle className="text-lg">{domain.name}</CardTitle>
                        <div className="flex items-center gap-2 mt-1">
                          <Badge variant="secondary" className="text-xs">
                            {skillsCount} {skillsCount === 1 ? 'Skill' : 'Skills'}
                          </Badge>
                        </div>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => openCreateSkillDialog(domain.id)}
                      >
                        <Plus className="w-4 h-4 mr-1" />
                        Add Skill
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => openEditDomainDialog(domain)}
                      >
                        <Edit2 className="w-4 h-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => openDeleteDialog('domain', domain)}
                        className="text-destructive hover:text-destructive"
                      >
                        <Trash2 className="w-4 h-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => toggleDomainExpansion(domain.id)}
                      >
                        {isExpanded ? (
                          <ChevronDown className="w-5 h-5" />
                        ) : (
                          <ChevronRight className="w-5 h-5" />
                        )}
                      </Button>
                    </div>
                  </div>
                </CardHeader>

                {isExpanded && domain.skills && domain.skills.length > 0 && (
                  <CardContent className="pt-0">
                    <div className="border-t pt-4">
                      <h4 className="text-sm font-medium text-muted-foreground mb-3">
                        Skills in this domain
                      </h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                        {domain.skills.map((skill) => (
                          <Card key={skill.id} className="bg-muted/50">
                            <CardContent className="p-3">
                              <div className="flex items-center justify-between">
                                <div className="flex-1 min-w-0">
                                  <p className="font-medium text-sm truncate">
                                    {skill.name}
                                  </p>
                                  {skill.description && (
                                    <p className="text-xs text-muted-foreground truncate">
                                      {skill.description}
                                    </p>
                                  )}
                                </div>
                                <div className="flex items-center gap-1 ml-2">
                                  <Button
                                    variant="ghost"
                                    size="icon"
                                    className="h-8 w-8"
                                    onClick={() => openEditSkillDialog(skill)}
                                  >
                                    <Edit2 className="w-3 h-3" />
                                  </Button>
                                  <Button
                                    variant="ghost"
                                    size="icon"
                                    className="h-8 w-8 text-destructive hover:text-destructive"
                                    onClick={() => openDeleteDialog('skill', skill)}
                                  >
                                    <Trash2 className="w-3 h-3" />
                                  </Button>
                                </div>
                              </div>
                            </CardContent>
                          </Card>
                        ))}
                      </div>
                    </div>
                  </CardContent>
                )}

                {isExpanded && (!domain.skills || domain.skills.length === 0) && (
                  <CardContent className="pt-0">
                    <div className="border-t pt-4">
                      <div className="text-center py-4 text-muted-foreground">
                        <p className="text-sm">No skills in this domain yet</p>
                        <Button
                          variant="outline"
                          size="sm"
                          className="mt-2"
                          onClick={() => openCreateSkillDialog(domain.id)}
                        >
                          <Plus className="w-4 h-4 mr-1" />
                          Add First Skill
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                )}
              </Card>
            );
          })
        )}
      </div>

      {/* Domain Dialog */}
      <Dialog open={isDomainDialogOpen} onOpenChange={setIsDomainDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {editingDomain ? 'Edit Domain' : 'Create New Domain'}
            </DialogTitle>
            <DialogDescription>
              {editingDomain 
                ? 'Update the domain name below.' 
                : 'Enter a name for the new career domain.'}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="domainName">Domain Name</Label>
              <Input
                id="domainName"
                value={domainName}
                onChange={(e) => setDomainName(e.target.value)}
                placeholder="e.g., Frontend, Backend, DevOps"
              />
            </div>
          </div>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setIsDomainDialogOpen(false)}
              disabled={isSubmitting}
            >
              Cancel
            </Button>
            <Button onClick={handleSaveDomain} disabled={isSubmitting}>
              {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
              {editingDomain ? 'Update' : 'Create'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Skill Dialog */}
      <Dialog open={isSkillDialogOpen} onOpenChange={setIsSkillDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {editingSkill ? 'Edit Skill' : 'Create New Skill'}
            </DialogTitle>
            <DialogDescription>
              {editingSkill
                ? 'Update the skill details below.'
                : 'Enter details for the new skill.'}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="skillName">Skill Name</Label>
              <Input
                id="skillName"
                value={skillName}
                onChange={(e) => setSkillName(e.target.value)}
                placeholder="e.g., React, Python, Docker"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="skillDescription">Description (Optional)</Label>
              <Textarea
                id="skillDescription"
                value={skillDescription}
                onChange={(e) => setSkillDescription(e.target.value)}
                placeholder="Brief description of this skill"
                rows={3}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="demandLevel">Demand Level (0-100)</Label>
              <Input
                id="demandLevel"
                type="number"
                min={0}
                max={100}
                value={skillDemandLevel}
                onChange={(e) => setSkillDemandLevel(parseInt(e.target.value) || 0)}
              />
            </div>
          </div>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setIsSkillDialogOpen(false)}
              disabled={isSubmitting}
            >
              Cancel
            </Button>
            <Button onClick={handleSaveSkill} disabled={isSubmitting}>
              {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
              {editingSkill ? 'Update' : 'Create'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <Dialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <AlertCircle className="w-5 h-5 text-destructive" />
              Confirm Deletion
            </DialogTitle>
            <DialogDescription>
              {deletingItem?.type === 'domain' ? (
                <>
                  Are you sure you want to delete the domain <strong>{deletingItem?.item.name}</strong>?
                  <br /><br />
                  <span className="text-destructive font-medium">
                    Warning: This will also delete all skills associated with this domain.
                  </span>
                </>
              ) : (
                <>
                  Are you sure you want to delete the skill <strong>{deletingItem?.item.name}</strong>?
                  <br /><br />
                  This action cannot be undone.
                </>
              )}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setIsDeleteDialogOpen(false)}
              disabled={isSubmitting}
            >
              Cancel
            </Button>
            <Button
              variant="destructive"
              onClick={handleDelete}
              disabled={isSubmitting}
            >
              {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
              Delete
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { 
  FileText, 
  Search, 
  Download, 
  RefreshCw, 
  AlertCircle, 
  CheckCircle2,
  Clock,
  FileCode,
  Trash2,
  Eye
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import axiosClient from '@/api/axiosClient';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';

interface LogFile {
  name: string;
  path: string;
  size: number;
  modified: string;
  size_human: string;
}

interface LogEntry {
  timestamp: string | null;
  file: string;
  message: string;
  context: string[];
  line_number: number;
  type: string;
}

export default function LogViewer() {
  const { toast } = useToast();
  const [logFiles, setLogFiles] = useState<LogFile[]>([]);
  const [selectedFile, setSelectedFile] = useState<string | null>(null);
  const [fileContent, setFileContent] = useState<string[]>([]);
  const [errors, setErrors] = useState<LogEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [linesToShow, setLinesToShow] = useState(100);
  const [timeRange, setTimeRange] = useState('24');
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);
  const [viewingFile, setViewingFile] = useState<LogFile | null>(null);
  const [autoRefresh, setAutoRefresh] = useState(true);

  // Initial data load
  useEffect(() => {
    fetchLogFiles();
    fetchErrors();
  }, [timeRange]);

  // Auto-refresh interval
  useEffect(() => {
    let interval: NodeJS.Timeout | null = null;
    
    if (autoRefresh) {
      interval = setInterval(() => {
        fetchLogFiles();
        fetchErrors();
      }, 10000); // Refresh every 10 seconds
    }
    
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [autoRefresh, timeRange]);


  const fetchLogFiles = async () => {
    try {
      setLoading(true);
      const response = await axiosClient.get('/admin/logs/files');
      setLogFiles(response.data.log_files);
    } catch (error) {
      console.error('Error fetching log files:', error);
      toast({
        title: "Error",
        description: "Failed to fetch log files",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const fetchErrors = async () => {
    try {
      const response = await axiosClient.get(`/admin/logs/errors?hours=${timeRange}&limit=100`);
      setErrors(response.data.errors);
    } catch (error) {
      console.error('Error fetching errors:', error);
    }
  };

  const viewLogFile = async (file: LogFile) => {
    try {
      const response = await axiosClient.get('/admin/logs/view', {
        params: {
          file_path: file.path,
          lines: linesToShow,
          search: searchQuery || undefined
        }
      });
      
      setFileContent(response.data.content);
      setViewingFile(file);
      setIsViewModalOpen(true);
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.response?.data?.detail || "Failed to read log file",
        variant: "destructive",
      });
    }
  };

  const downloadLogFile = async (file: LogFile) => {
    try {
      const response = await axiosClient.get('/admin/logs/view', {
        params: {
          file_path: file.path,
          lines: 10000 // Get more lines for download
        }
      });
      
      const blob = new Blob([response.data.content.join('\n')], { type: 'text/plain' });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', file.name);
      document.body.appendChild(link);
      link.click();
      link.remove();
      
      toast({
        title: "Success",
        description: "Log file downloaded",
      });
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to download log file",
        variant: "destructive",
      });
    }
  };

  const getFileIcon = (filename: string) => {
    if (filename.includes('error')) return <AlertCircle className="h-4 w-4 text-red-500" />;
    if (filename.includes('access')) return <Eye className="h-4 w-4 text-blue-500" />;
    return <FileCode className="h-4 w-4 text-gray-500" />;
  };

  const getErrorColor = (message: string) => {
    if (message.includes('CRITICAL') || message.includes('FATAL')) return 'bg-red-500/10 text-red-600 border-red-500/20';
    if (message.includes('ERROR')) return 'bg-orange-500/10 text-orange-600 border-orange-500/20';
    if (message.includes('WARNING')) return 'bg-yellow-500/10 text-yellow-600 border-yellow-500/20';
    return 'bg-blue-500/10 text-blue-600 border-blue-500/20';
  };

  return (
    <div className="space-y-6">
      {/* Filters */}
      <Card>
        <CardContent className="p-4">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex-1 relative">
              <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Search in logs..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>
            <Select value={timeRange} onValueChange={setTimeRange}>
              <SelectTrigger className="w-40">
                <SelectValue placeholder="Time range" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="1">Last 1 hour</SelectItem>
                <SelectItem value="6">Last 6 hours</SelectItem>
                <SelectItem value="24">Last 24 hours</SelectItem>
                <SelectItem value="48">Last 48 hours</SelectItem>
                <SelectItem value="168">Last 7 days</SelectItem>
              </SelectContent>
            </Select>
            <Button 
              variant={autoRefresh ? "default" : "outline"}
              onClick={() => setAutoRefresh(!autoRefresh)}
            >
              <RefreshCw className={`h-4 w-4 mr-2 ${autoRefresh ? 'animate-spin' : ''}`} />
              {autoRefresh ? 'Live Updates On' : 'Live Updates Off'}
            </Button>
            <Button variant="outline" onClick={() => {
              fetchLogFiles();
              fetchErrors();
            }}>
              <RefreshCw className="h-4 w-4 mr-2" />
              Refresh Now
            </Button>

          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Log Files */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5" />
              Log Files
            </CardTitle>
          </CardHeader>
          <CardContent>
            {loading ? (
              <div className="space-y-4">
                {Array.from({ length: 5 }).map((_, i) => (
                  <Skeleton key={i} className="h-16" />
                ))}
              </div>
            ) : logFiles.length === 0 ? (
              <Alert>
                <AlertCircle className="h-4 w-4" />
                <AlertDescription>No log files found</AlertDescription>
              </Alert>
            ) : (
              <div className="space-y-2">
                {logFiles.map((file) => (
                  <div
                    key={file.path}
                    className="flex items-center justify-between p-4 border rounded-lg hover:bg-muted/50 transition-colors"
                  >
                    <div className="flex items-center gap-3">
                      {getFileIcon(file.name)}
                      <div>
                        <p className="font-medium text-sm">{file.name}</p>
                        <div className="flex items-center gap-2 text-xs text-muted-foreground">
                          <span>{file.size_human}</span>
                          <span>ΓÇó</span>
                          <span>{new Date(file.modified).toLocaleString()}</span>
                        </div>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => viewLogFile(file)}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => downloadLogFile(file)}
                      >
                        <Download className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Recent Errors */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <AlertCircle className="h-5 w-5" />
              Recent Errors
              <Badge variant="outline" className="ml-2">
                {errors.length}
              </Badge>
            </CardTitle>
          </CardHeader>
          <CardContent>
            {errors.length === 0 ? (
              <Alert>
                <CheckCircle2 className="h-4 w-4" />
                <AlertDescription>No errors found in the selected time range</AlertDescription>
              </Alert>
            ) : (
              <div className="space-y-2 max-h-96 overflow-y-auto">
                {errors.map((error, index) => (
                  <div
                    key={index}
                    className={`p-3 border rounded-lg ${getErrorColor(error.message)}`}
                  >
                    <div className="flex items-start justify-between gap-2">
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium truncate">
                          {error.message}
                        </p>
                        <div className="flex items-center gap-2 mt-1 text-xs">
                          <Clock className="h-3 w-3" />
                          {error.timestamp ? new Date(error.timestamp).toLocaleString() : 'Unknown time'}
                          <span>ΓÇó</span>
                          <span>{error.file}</span>
                          <span>ΓÇó</span>
                          <span>Line {error.line_number}</span>
                        </div>
                        {error.context.length > 0 && (
                          <div className="mt-2 p-2 bg-black/5 rounded text-xs font-mono">
                            {error.context.map((line, i) => (
                              <div key={i} className={line === error.message ? 'font-bold' : ''}>
                                {line}
                              </div>
                            ))}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* View Log Modal */}
      <Dialog open={isViewModalOpen} onOpenChange={setIsViewModalOpen}>
        <DialogContent className="max-w-4xl max-h-[80vh]">
          <DialogHeader>
            <DialogTitle className="flex items-center justify-between">
              <span>{viewingFile?.name}</span>
              <Badge variant="outline">{viewingFile?.size_human}</Badge>
            </DialogTitle>
          </DialogHeader>
          <div className="mt-4">
            <div className="flex items-center gap-4 mb-4">
              <div className="flex-1 relative">
                <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Filter lines..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-10"
                />
              </div>
              <Select 
                value={linesToShow.toString()} 
                onValueChange={(v) => setLinesToShow(parseInt(v))}
              >
                <SelectTrigger className="w-32">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="50">50 lines</SelectItem>
                  <SelectItem value="100">100 lines</SelectItem>
                  <SelectItem value="500">500 lines</SelectItem>
                  <SelectItem value="1000">1000 lines</SelectItem>
                </SelectContent>
              </Select>
              <Button 
                variant="outline" 
                onClick={() => viewingFile && viewLogFile(viewingFile)}
              >
                <RefreshCw className="h-4 w-4 mr-2" />
                Apply
              </Button>
            </div>
            <div className="bg-black text-green-400 p-4 rounded-lg font-mono text-sm max-h-96 overflow-y-auto">
              {fileContent.length === 0 ? (
                <p className="text-gray-500">No content to display</p>
              ) : (
                fileContent.map((line, index) => (
                  <div key={index} className="hover:bg-white/5 px-2 py-0.5">
                    <span className="text-gray-500 select-none mr-2">
                      {(index + 1).toString().padStart(4, '0')}
                    </span>
                    <span className={line.includes('ERROR') ? 'text-red-400' : line.includes('WARNING') ? 'text-yellow-400' : ''}>
                      {line}
                    </span>
                  </div>
                ))
              )}
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Skeleton } from '@/components/ui/skeleton';
import { Checkbox } from '@/components/ui/checkbox';
import { 
  Plus, 
  Search, 
  Upload, 
  Download, 
  Edit2, 
  Trash2, 
  FileSpreadsheet,
  AlertCircle,
  CheckCircle2,
  X
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { useCallback } from 'react';
import axiosClient from '@/api/axiosClient';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';


function useDebounce(value: string, delay: number) {
  const [debouncedValue, setDebouncedValue] = useState(value);
  
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);
    
    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);
  
  return debouncedValue;
}


interface Question {
  id: number;
  skill_id: number;
  skill_name: string;
  question_text: string;
  question_type: string;
  options: string[];
  correct_answer: string;
  difficulty: string;
  explanation: string | null;
  created_at: string;
  updated_at: string;
}

interface Skill {
  id: number;
  name: string;
  description?: string;
}

interface Domain {
  id: number;
  name: string;
  skills: Skill[];
}


export default function QuizManager() {
  const { toast } = useToast();
  const fileInputRef = useRef<HTMLInputElement>(null);
  
  const [questions, setQuestions] = useState<Question[]>([]);
  const [skills, setSkills] = useState<Skill[]>([]);
  const [domains, setDomains] = useState<Domain[]>([]);
  const [selectedDomainId, setSelectedDomainId] = useState<string>('');
  const [filteredSkills, setFilteredSkills] = useState<Skill[]>([]);
  const [loading, setLoading] = useState(true);

  const [search, setSearch] = useState('');
  const [domainFilter, setDomainFilter] = useState<string>('all');
  const [skillFilter, setSkillFilter] = useState<string>('all');
  const [difficultyFilter, setDifficultyFilter] = useState<string>('all');
  const [filteredViewSkills, setFilteredViewSkills] = useState<Skill[]>([]);
  const [sortBy, setSortBy] = useState('newest');

  const debouncedSearch = useDebounce(search, 300);

  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [selectedQuestions, setSelectedQuestions] = useState<number[]>([]);
  const limit = 10;

  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [uploadSkillId, setUploadSkillId] = useState<string>('none');
  const [activeTab, setActiveTab] = useState('view');

  // Form state
  const [formData, setFormData] = useState({
    skill_id: '',
    domain_id: '',
    question_text: '',
    question_type: 'multiple_choice',
    options: ['', '', '', ''],
    correct_answer: '',
    difficulty: 'medium',
    explanation: ''
  });

  useEffect(() => {
    setPage(1);
  }, [debouncedSearch, sortBy]);

  useEffect(() => {
    fetchQuestions();
    fetchSkills();
    fetchDomainsWithSkills();
  }, [debouncedSearch, domainFilter, skillFilter, difficultyFilter, sortBy, page]);

  const fetchQuestions = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      params.append('skip', ((page - 1) * limit).toString());
      params.append('limit', limit.toString());
      if (debouncedSearch) params.append('search', debouncedSearch);      if (domainFilter !== 'all') params.append('domain_id', domainFilter);
      if (skillFilter !== 'all') params.append('skill_id', skillFilter);

      if (difficultyFilter !== 'all') params.append('difficulty', difficultyFilter);
      params.append('sort_by', sortBy);

      const response = await axiosClient.get(`/admin/quiz/questions?${params.toString()}`);

      setQuestions(response.data.questions);
      setTotal(response.data.total);
    } catch (error: any) {
      toast({
        title: "Error",
        description: "Failed to fetch questions",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const fetchSkills = async () => {
    try {
      const response = await axiosClient.get('/skills');
      setSkills(response.data.skills || []);
    } catch (error) {
      console.error('Error fetching skills:', error);
    }
  };

  const fetchDomainsWithSkills = async () => {
    try {
      const response = await axiosClient.get('/admin/quiz/domains-with-skills');
      setDomains(response.data.domains || []);
    } catch (error) {
      console.error('Error fetching domains:', error);
    }
  };

  const handleDomainChange = (domainId: string) => {
    setSelectedDomainId(domainId);
    setFormData({...formData, domain_id: domainId, skill_id: ''});
    
    // Filter skills for selected domain
    const selectedDomain = domains.find(d => d.id.toString() === domainId);
    setFilteredSkills(selectedDomain ? selectedDomain.skills : []);
  };


  const handleCreateQuestion = async () => {
    if (!formData.skill_id) {
      toast({ title: "Validation Error", description: "Skill is required", variant: "destructive" });
      return;
    }
    
    const filledOptions = formData.options.filter(opt => opt.trim() !== '');
    if (formData.question_type === 'multiple_choice' && filledOptions.length < 2) {
      toast({ title: "Validation Error", description: "Multiple choice questions require at least 2 options", variant: "destructive" });
      return;
    }
    
    if (!formData.correct_answer.trim()) {
      toast({ title: "Validation Error", description: "Correct answer is required", variant: "destructive" });
      return;
    }
    
    if (formData.question_type === 'multiple_choice' && !filledOptions.includes(formData.correct_answer)) {
      toast({ title: "Validation Error", description: "Correct answer must exactly match one of the provided options", variant: "destructive" });
      return;
    }

    try {
      const data = {
        ...formData,
        skill_id: parseInt(formData.skill_id),
        options: formData.question_type === 'multiple_choice' 
          ? formData.options.filter(opt => opt.trim() !== '')
          : formData.question_type === 'true_false' 
            ? ['True', 'False']
            : []
      };


      await axiosClient.post('/admin/quiz/questions', data);
      
      toast({
        title: "Success",
        description: "Question created successfully",
      });
      
      setIsCreateModalOpen(false);
      resetForm();
      fetchQuestions();
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.response?.data?.detail || "Failed to create question",
        variant: "destructive",
      });
    }
  };

  const handleUpdateQuestion = async () => {
    if (!editingQuestion) return;

    if (!formData.skill_id) {
      toast({ title: "Validation Error", description: "Skill is required", variant: "destructive" });
      return;
    }
    
    const filledOptions = formData.options.filter(opt => opt.trim() !== '');
    if (formData.question_type === 'multiple_choice' && filledOptions.length < 2) {
      toast({ title: "Validation Error", description: "Multiple choice questions require at least 2 options", variant: "destructive" });
      return;
    }
    
    if (!formData.correct_answer.trim()) {
      toast({ title: "Validation Error", description: "Correct answer is required", variant: "destructive" });
      return;
    }
    
    if (formData.question_type === 'multiple_choice' && !filledOptions.includes(formData.correct_answer)) {
      toast({ title: "Validation Error", description: "Correct answer must exactly match one of the provided options", variant: "destructive" });
      return;
    }

    try {
      const data = {
        ...formData,
        skill_id: parseInt(formData.skill_id),
        options: formData.question_type === 'multiple_choice' 
          ? formData.options.filter(opt => opt.trim() !== '')
          : formData.question_type === 'true_false' 
            ? ['True', 'False']
            : []
      };


      await axiosClient.put(`/admin/quiz/questions/${editingQuestion.id}`, data);
      
      toast({
        title: "Success",
        description: "Question updated successfully",
      });
      
      setIsEditModalOpen(false);
      setEditingQuestion(null);
      resetForm();
      fetchQuestions();
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.response?.data?.detail || "Failed to update question",
        variant: "destructive",
      });
    }
  };

  const handleDeleteQuestion = async (questionId: number) => {
    if (!confirm('Are you sure you want to delete this question?')) return;

    try {
      await axiosClient.delete(`/admin/quiz/questions/${questionId}`);
      
      toast({
        title: "Success",
        description: "Question deleted successfully",
      });
      
      fetchQuestions();
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.response?.data?.detail || "Failed to delete question",
        variant: "destructive",
      });
    }
  };

  const handleBulkDelete = async () => {
    if (selectedQuestions.length === 0) return;
    if (!confirm(`Are you sure you want to delete ${selectedQuestions.length} questions?`)) return;

    try {
      await axiosClient.post('/admin/quiz/questions/bulk-delete', selectedQuestions);
      
      toast({
        title: "Success",
        description: `${selectedQuestions.length} questions deleted successfully`,
      });
      
      setSelectedQuestions([]);
      fetchQuestions();
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.response?.data?.detail || "Failed to delete questions",
        variant: "destructive",
      });
    }
  };

  const handleFileUpload = async () => {
    if (!uploadFile) {
      toast({
        title: "Error",
        description: "Please select a file",
        variant: "destructive",
      });
      return;
    }

    const formData = new FormData();
    formData.append('file', uploadFile);
    if (uploadSkillId && uploadSkillId !== 'none') {
      formData.append('skill_id', uploadSkillId);
    }


    try {
      const response = await axiosClient.post('/admin/quiz/upload-excel', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      toast({
        title: "Upload Complete",
        description: `Created ${response.data.created_count} questions. ${response.data.error_count} errors.`,
      });

      setIsUploadModalOpen(false);
      setUploadFile(null);
      setUploadSkillId('none');
      fetchQuestions();

    } catch (error: any) {
      toast({
        title: "Upload Failed",
        description: error.response?.data?.detail || "Failed to upload file",
        variant: "destructive",
      });
    }
  };

  const downloadTemplate = async () => {
    try {
      const response = await axiosClient.get('/admin/quiz/download-template', {
        responseType: 'blob',
      });

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', 'question_template.xlsx');
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to download template",
        variant: "destructive",
      });
    }
  };

  const openEditModal = (question: Question) => {
    setEditingQuestion(question);
    
    // Find the domain for this skill
    const skillDomain = domains.find(d => 
      d.skills.some(s => s.id === question.skill_id)
    );
    
    if (skillDomain) {
      setSelectedDomainId(skillDomain.id.toString());
      setFilteredSkills(skillDomain.skills);
    }
    
    setFormData({
      skill_id: question.skill_id.toString(),
      domain_id: skillDomain ? skillDomain.id.toString() : '',
      question_text: question.question_text,
      question_type: question.question_type || 'multiple_choice',
      options: [...question.options, '', '', '', ''].slice(0, 4),
      correct_answer: question.correct_answer,
      difficulty: question.difficulty,
      explanation: question.explanation || ''
    });
    setIsEditModalOpen(true);
  };


  const resetForm = () => {
    setFormData({
      skill_id: '',
      domain_id: '',
      question_text: '',
      question_type: 'multiple_choice',
      options: ['', '', '', ''],
      correct_answer: '',
      difficulty: 'medium',
      explanation: ''
    });
    setSelectedDomainId('');
    setFilteredSkills([]);
  };



  const toggleSelectAll = () => {
    if (selectedQuestions.length === questions.length) {
      setSelectedQuestions([]);
    } else {
      setSelectedQuestions(questions.map(q => q.id));
    }
  };

  const toggleSelectQuestion = (questionId: number) => {
    if (selectedQuestions.includes(questionId)) {
      setSelectedQuestions(selectedQuestions.filter(id => id !== questionId));
    } else {
      setSelectedQuestions([...selectedQuestions, questionId]);
    }
  };

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty) {
      case 'easy': return 'bg-green-500/10 text-green-600 border-green-500/20';
      case 'medium': return 'bg-yellow-500/10 text-yellow-600 border-yellow-500/20';
      case 'hard': return 'bg-red-500/10 text-red-600 border-red-500/20';
      default: return 'bg-gray-500/10 text-gray-600 border-gray-500/20';
    }
  };

  const getQuestionTypeColor = (questionType: string) => {
    switch (questionType) {
      case 'multiple_choice': return 'bg-blue-500/10 text-blue-600 border-blue-500/20';
      case 'true_false': return 'bg-purple-500/10 text-purple-600 border-purple-500/20';
      case 'short_answer': return 'bg-orange-500/10 text-orange-600 border-orange-500/20';
      default: return 'bg-gray-500/10 text-gray-600 border-gray-500/20';
    }
  };

  const getQuestionTypeLabel = (questionType: string) => {
    switch (questionType) {
      case 'multiple_choice': return 'Multiple Choice';
      case 'true_false': return 'True/False';
      case 'short_answer': return 'Short Answer';
      default: return questionType;
    }
  };


  return (
    <div className="space-y-6">
      <Tabs value={activeTab} onValueChange={setActiveTab} className="space-y-6">
        <TabsList className="grid w-full grid-cols-2 bg-muted/50 p-1 rounded-lg">
          <TabsTrigger value="add">Add Questions</TabsTrigger>
          <TabsTrigger value="view">View Questions</TabsTrigger>
        </TabsList>

        {/* Add Questions Tab */}
        <TabsContent value="add" className="space-y-6">
          <Tabs defaultValue="manual" className="space-y-6">
            <TabsList className="grid w-full grid-cols-2 max-w-md bg-muted/50 p-1 rounded-lg">
              <TabsTrigger value="manual">Manual</TabsTrigger>
              <TabsTrigger value="file">File</TabsTrigger>
            </TabsList>

            {/* Manual Sub-tab */}
            <TabsContent value="manual" className="space-y-6">
              <Card>
                <CardHeader>
                  <CardTitle>Create New Question</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div>
                    <Label>Domain</Label>
                    <Select 
                      value={selectedDomainId} 
                      onValueChange={handleDomainChange}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Select a domain" />
                      </SelectTrigger>
                      <SelectContent>
                        {domains.map(domain => (
                          <SelectItem key={domain.id} value={domain.id.toString()}>
                            {domain.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div>
                    <Label>Skill</Label>
                    <Select 
                      value={formData.skill_id} 
                      onValueChange={(value) => setFormData({...formData, skill_id: value})}
                      disabled={!selectedDomainId || filteredSkills.length === 0}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder={selectedDomainId ? "Select a skill" : "Select a domain first"} />
                      </SelectTrigger>
                      <SelectContent>
                        {filteredSkills.map(skill => (
                          <SelectItem key={skill.id} value={skill.id.toString()}>
                            {skill.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                  <div>
                    <Label>Question Text</Label>
                    <Textarea
                      value={formData.question_text}
                      onChange={(e) => setFormData({...formData, question_text: e.target.value})}
                      placeholder="Enter your question..."
                      rows={3}
                    />
                  </div>
                  <div>
                    <Label>Options (one per line)</Label>
                    {formData.options.map((option, index) => (
                      <Input
                        key={index}
                        value={option}
                        onChange={(e) => {
                          const newOptions = [...formData.options];
                          newOptions[index] = e.target.value;
                          setFormData({...formData, options: newOptions});
                        }}
                        placeholder={`Option ${index + 1}`}
                        className="mb-2"
                      />
                    ))}
                  </div>
                  <div>
                    <Label>Correct Answer</Label>
                    <Input
                      value={formData.correct_answer}
                      onChange={(e) => setFormData({...formData, correct_answer: e.target.value})}
                      placeholder="Enter the correct answer"
                    />
                  </div>
                  <div>
                    <Label>Difficulty</Label>
                    <Select 
                      value={formData.difficulty} 
                      onValueChange={(value) => setFormData({...formData, difficulty: value})}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="easy">Easy</SelectItem>
                        <SelectItem value="medium">Medium</SelectItem>
                        <SelectItem value="hard">Hard</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div>
                    <Label>Explanation (Optional)</Label>
                    <Textarea
                      value={formData.explanation}
                      onChange={(e) => setFormData({...formData, explanation: e.target.value})}
                      placeholder="Explain why this is the correct answer..."
                      rows={2}
                    />
                  </div>
                  <div className="flex gap-2 pt-4">
                    <Button onClick={handleCreateQuestion}>
                      <Plus className="h-4 w-4 mr-2" />
                      Create Question
                    </Button>
                    <Button variant="outline" onClick={resetForm}>
                      <X className="h-4 w-4 mr-2" />
                      Clear Form
                    </Button>
                  </div>
                </CardContent>
              </Card>
            </TabsContent>

            {/* File Sub-tab */}
            <TabsContent value="file" className="space-y-6">
              <Card>
                <CardHeader>
                  <CardTitle>Upload Questions from File</CardTitle>
                </CardHeader>
                <CardContent className="space-y-6">
                  <Alert className='bg-yellow-100'>
                    <AlertCircle className="h-4 w-4 bg-yellow-400 rounded-3xl" />
                    <AlertDescription>
                      Upload an Excel file (.xlsx, .xls) or CSV file (.csv) with question data. 
                      Select a domain and skill, then upload your file.
                    </AlertDescription>
                  </Alert>
                  
                  <div>
                    <Label>Domain</Label>
                    <Select 
                      value={selectedDomainId} 
                      onValueChange={handleDomainChange}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Select a domain" />
                      </SelectTrigger>
                      <SelectContent>
                        {domains.map(domain => (
                          <SelectItem key={domain.id} value={domain.id.toString()}>
                            {domain.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  
                  <div>
                    <Label>Skill</Label>
                    <Select 
                      value={uploadSkillId} 
                      onValueChange={setUploadSkillId}
                      disabled={!selectedDomainId || filteredSkills.length === 0}
                    >
                      <SelectTrigger>
                        <SelectValue placeholder={selectedDomainId ? "Select a skill" : "Select a domain first"} />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="none">Use skill_id from file</SelectItem>
                        {filteredSkills.map(skill => (
                          <SelectItem key={skill.id} value={skill.id.toString()}>
                            {skill.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  
                  <div>
                    <Label>Upload File</Label>
                    <Input
                      className=''
                      type="file"
                      accept=".xlsx,.xls,.csv"
                      onChange={(e) => setUploadFile(e.target.files?.[0] || null)}
                      ref={fileInputRef}
                    />
                    <p className="text-sm text-muted-foreground mt-2">
                      Supported formats: Excel (.xlsx, .xls) or CSV (.csv)
                    </p>
                  </div>

                  <div className="flex gap-2 pt-4">
                    <Button onClick={handleFileUpload} disabled={!uploadFile}>
                      <Upload className="h-4 w-4 mr-2" />
                      Upload Questions
                    </Button>
                    <Button variant="outline" onClick={downloadTemplate}>
                      <Download className="h-4 w-4 mr-2" />
                      Download Template
                    </Button>
                  </div>
                </CardContent>
              </Card>
            </TabsContent>

          </Tabs>
        </TabsContent>


        {/* View Questions Tab */}
        <TabsContent value="view" className="space-y-6">
          {/* Header Actions */}
          <div className="flex flex-col sm:flex-row gap-4 justify-between items-start sm:items-center">
            <div className="flex gap-2">
              <Button onClick={() => setActiveTab('add')}>
                <Plus className="h-4 w-4 mr-2" />
                Add Question
              </Button>
            </div>

            {selectedQuestions.length > 0 && (
              <Button variant="destructive" onClick={handleBulkDelete}>
                <Trash2 className="h-4 w-4 mr-2" />
                Delete Selected ({selectedQuestions.length})
              </Button>
            )}
          </div>

          {/* Filters */}
          <Card>
            <CardContent className="p-4">
              <div className="flex flex-col sm:flex-row gap-4">
                <div className="flex-1 relative">
                  <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder="Search questions..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="pl-10"
                  />
                </div>
                <Select 
                  value={domainFilter} 
                  onValueChange={(value) => {
                    setDomainFilter(value);
                    setSkillFilter('all');
                    setPage(1);
                    // Filter skills based on selected domain
                    if (value === 'all') {
                      setFilteredViewSkills([]);
                    } else {
                      const selectedDomain = domains.find(d => d.id.toString() === value);
                      setFilteredViewSkills(selectedDomain ? selectedDomain.skills : []);
                    }
                  }}
                >
                  <SelectTrigger className="w-40">
                    <SelectValue placeholder="Filter by domain" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Domains</SelectItem>
                    {domains.map(domain => (
                      <SelectItem key={domain.id} value={domain.id.toString()}>
                        {domain.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>

                <Select 
                  value={skillFilter} 
                  onValueChange={(value) => {
                    setSkillFilter(value);
                    setPage(1);
                  }}
                  disabled={domainFilter === 'all'}
                >
                  <SelectTrigger className="w-40">
                    <SelectValue placeholder={domainFilter === 'all' ? "Select domain first" : "Filter by skill"} />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Skills</SelectItem>
                    {filteredViewSkills.map(skill => (
                      <SelectItem key={skill.id} value={skill.id.toString()}>
                        {skill.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>

                <Select value={difficultyFilter} onValueChange={(value) => {
                    setDifficultyFilter(value);
                    setPage(1);
                  }}>
                  <SelectTrigger className="w-40">
                    <SelectValue placeholder="Difficulty" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Levels</SelectItem>
                    <SelectItem value="easy">Easy</SelectItem>
                    <SelectItem value="medium">Medium</SelectItem>
                    <SelectItem value="hard">Hard</SelectItem>
                  </SelectContent>
                </Select>

                <Select value={sortBy} onValueChange={(value) => {
                    setSortBy(value);
                  }}>
                  <SelectTrigger className="w-40">
                    <SelectValue placeholder="Sort By" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="newest">Newest First</SelectItem>
                    <SelectItem value="oldest">Oldest First</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {/* Questions Table */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center justify-between">
                <span>Questions ({total})</span>
                <div className="flex items-center gap-2">
                  <Checkbox
                    checked={selectedQuestions.length === questions.length && questions.length > 0}
                    onCheckedChange={toggleSelectAll}
                  />
                  <span className="text-sm font-normal text-muted-foreground">
                    Select All
                  </span>
                </div>
              </CardTitle>
            </CardHeader>
            <CardContent>
              {loading ? (
                <div className="space-y-4">
                  {Array.from({ length: 5 }).map((_, i) => (
                    <Skeleton key={i} className="h-20" />
                  ))}
                </div>
              ) : questions.length === 0 ? (
                <Alert>
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>No questions found. Create your first question or upload from Excel.</AlertDescription>
                </Alert>
              ) : (
                <div className="space-y-4">
                  {questions.map((question) => (
                    <div
                      key={question.id}
                      className="flex items-start gap-4 p-4 border rounded-lg hover:bg-muted/50 transition-colors"
                    >
                      <Checkbox
                        checked={selectedQuestions.includes(question.id)}
                        onCheckedChange={() => toggleSelectQuestion(question.id)}
                      />
                      <div className="flex-1 min-w-0">
                        <div className="flex items-start justify-between gap-4">
                          <div className="flex-1">
                            <p className="font-medium mb-2 line-clamp-2" title={question.question_text}>{question.question_text}</p>
                            <div className="flex flex-wrap gap-2 mb-2">
                              <Badge variant="outline" className={getDifficultyColor(question.difficulty)}>
                                {question.difficulty}
                              </Badge>
                              <Badge variant="outline" className={getQuestionTypeColor(question.question_type)}>
                                {getQuestionTypeLabel(question.question_type)}
                              </Badge>
                              <Badge variant="outline">{question.skill_name}</Badge>
                            </div>

                            <div className="text-sm text-muted-foreground">
                              <span className="font-medium">Options:</span> {question.options.join(', ')}
                            </div>
                            <div className="text-sm text-muted-foreground">
                              <span className="font-medium">Answer:</span> {question.correct_answer}
                            </div>
                          </div>
                          <div className="flex gap-2">
                            <Button
                              variant="ghost"
                              size="icon"
                              onClick={() => openEditModal(question)}
                            >
                              <Edit2 className="h-4 w-4" />
                            </Button>
                            <Button
                              variant="ghost"
                              size="icon"
                              onClick={() => handleDeleteQuestion(question.id)}
                            >
                              <Trash2 className="h-4 w-4 text-red-500" />
                            </Button>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}

                  {/* Pagination */}
                  {total > limit && (
                    <div className="flex justify-between items-center pt-4">
                      <div className="text-sm text-muted-foreground">
                        Showing {((page - 1) * limit) + 1} to {Math.min(page * limit, total)} of {total}
                      </div>
                      <div className="flex gap-2">
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => setPage(page - 1)}
                          disabled={page === 1}
                        >
                          Previous
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => setPage(page + 1)}
                          disabled={page * limit >= total}
                        >
                          Next
                        </Button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>


      {/* Edit Question Modal */}

      <Dialog open={isEditModalOpen} onOpenChange={setIsEditModalOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Edit Question</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div>
              <Label>Domain</Label>
              <Select 
                value={selectedDomainId} 
                onValueChange={handleDomainChange}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select a domain" />
                </SelectTrigger>
                <SelectContent>
                  {domains.map(domain => (
                    <SelectItem key={domain.id} value={domain.id.toString()}>
                      {domain.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label>Skill</Label>
              <Select 
                value={formData.skill_id} 
                onValueChange={(value) => setFormData({...formData, skill_id: value})}
                disabled={!selectedDomainId || filteredSkills.length === 0}
              >
                <SelectTrigger>
                  <SelectValue placeholder={selectedDomainId ? "Select a skill" : "Select a domain first"} />
                </SelectTrigger>
                <SelectContent>
                  {filteredSkills.map(skill => (
                    <SelectItem key={skill.id} value={skill.id.toString()}>
                      {skill.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Question Text</Label>
              <Textarea
                value={formData.question_text}
                onChange={(e) => setFormData({...formData, question_text: e.target.value})}
                placeholder="Enter your question..."
                rows={3}
              />
            </div>
            <div>
              <Label>Options (one per line)</Label>
              {formData.options.map((option, index) => (
                <Input
                  key={index}
                  value={option}
                  onChange={(e) => {
                    const newOptions = [...formData.options];
                    newOptions[index] = e.target.value;
                    setFormData({...formData, options: newOptions});
                  }}
                  placeholder={`Option ${index + 1}`}
                  className="mb-2"
                />
              ))}
            </div>
            <div>
              <Label>Correct Answer</Label>
              <Input
                value={formData.correct_answer}
                onChange={(e) => setFormData({...formData, correct_answer: e.target.value})}
                placeholder="Enter the correct answer"
              />
            </div>
            <div>
              <Label>Difficulty</Label>
              <Select 
                value={formData.difficulty} 
                onValueChange={(value) => setFormData({...formData, difficulty: value})}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="easy">Easy</SelectItem>
                  <SelectItem value="medium">Medium</SelectItem>
                  <SelectItem value="hard">Hard</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label>Explanation (Optional)</Label>
              <Textarea
                value={formData.explanation}
                onChange={(e) => setFormData({...formData, explanation: e.target.value})}
                placeholder="Explain why this is the correct answer..."
                rows={2}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => {
              setIsEditModalOpen(false);
              setEditingQuestion(null);
              resetForm();
            }}>
              Cancel
            </Button>
            <Button onClick={handleUpdateQuestion}>Update Question</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { 
  Activity, 
  Cpu, 
  MemoryStick, 
  HardDrive, 
  Network, 
  Server,
  RefreshCw,
  CheckCircle2,
  AlertCircle,
  Clock
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import axiosClient from '@/api/axiosClient';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';

interface SystemMetrics {
  timestamp: string;
  cpu: {
    percent: number;
    count: number;
    frequency_mhz: number | null;
    per_cpu: number[];
  };
  memory: {
    total_gb: number;
    available_gb: number;
    percent: number;
    used_gb: number;
  };
  disk: {
    total_gb: number;
    used_gb: number;
    free_gb: number;
    percent: number;
  };
  network: {
    bytes_sent: number;
    bytes_recv: number;
    packets_sent: number;
    packets_recv: number;
  };
  top_processes: Array<{
    pid: number;
    name: string;
    cpu_percent: number;
    memory_percent: number;
    status: string;
  }>;
  uptime: string;
}


interface ServiceStatus {
  services: Array<{
    name: string;
    status: 'healthy' | 'warning' | 'error';
    message: string;
  }>;
  overall_status: string;
  timestamp: string;
}

export default function SystemMonitor() {
  const { toast } = useToast();
  const [metrics, setMetrics] = useState<SystemMetrics | null>(null);
  const [serviceStatus, setServiceStatus] = useState<ServiceStatus | null>(null);
  const [loading, setLoading] = useState(true);
  const [autoRefresh, setAutoRefresh] = useState(true);
  const [metricsHistory, setMetricsHistory] = useState<Array<{ time: string; cpu: number; memory: number }>>([]);

  // Initial data fetch
  useEffect(() => {
    fetchData();
  }, []);

  // Auto-refresh interval management
  useEffect(() => {
    let interval: NodeJS.Timeout | null = null;
    
    if (autoRefresh) {
      interval = setInterval(fetchData, 5000); // Refresh every 5 seconds
    }
    
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [autoRefresh]);


  const fetchData = async () => {
    try {
      const [metricsRes, statusRes] = await Promise.all([
        axiosClient.get('/admin/logs/system-metrics'),
        axiosClient.get('/admin/logs/service-status')
      ]);
      
      setMetrics(metricsRes.data);
      setServiceStatus(statusRes.data);
      
      // Add to history
      setMetricsHistory(prev => {
        const newPoint = {
          time: new Date().toLocaleTimeString(),
          cpu: metricsRes.data.cpu.percent,
          memory: metricsRes.data.memory.percent
        };
        const newHistory = [...prev, newPoint].slice(-20); // Keep last 20 points
        return newHistory;
      });
      
      setLoading(false);
    } catch (error) {
      console.error('Error fetching system data:', error);
      toast({
        title: "Error",
        description: "Failed to fetch system metrics",
        variant: "destructive",
      });
    }
  };

  const formatBytes = (bytes: number) => {

    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'healthy': return 'bg-green-500';
      case 'warning': return 'bg-yellow-500';
      case 'error': return 'bg-red-500';
      default: return 'bg-gray-500';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'healthy': return <CheckCircle2 className="h-4 w-4 text-green-500" />;
      case 'warning': return <AlertCircle className="h-4 w-4 text-yellow-500" />;
      case 'error': return <AlertCircle className="h-4 w-4 text-red-500" />;
      default: return <AlertCircle className="h-4 w-4 text-gray-500" />;
    }
  };

  if (loading) {
    return (
      <div className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <Skeleton className="h-32" />
          <Skeleton className="h-32" />
          <Skeleton className="h-32" />
          <Skeleton className="h-32" />
        </div>
        <Skeleton className="h-64" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <Button
            variant={autoRefresh ? "default" : "outline"}
            size="sm"
            onClick={() => setAutoRefresh(!autoRefresh)}
          >
            <RefreshCw className="h-4 w-4 mr-2" />
            {autoRefresh ? 'Auto-refresh On' : 'Auto-refresh Off'}
          </Button>

          <Button
            variant="outline"
            size="sm"
            onClick={fetchData}
          >
            <RefreshCw className="h-4 w-4 mr-2" />
            Refresh Now
          </Button>
        </div>
        <div className="flex items-center gap-2">
          <Clock className="h-4 w-4 text-muted-foreground" />
          <span className="text-sm text-muted-foreground">
            Uptime: {metrics?.uptime || 'N/A'}
          </span>

        </div>
      </div>

      {/* Service Status */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Server className="h-5 w-5" />
            Service Status
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {serviceStatus?.services.map((service) => (
              <div
                key={service.name}
                className="flex items-center justify-between p-4 border rounded-lg"
              >
                <div className="flex items-center gap-3">
                  {getStatusIcon(service.status)}
                  <div>
                    <p className="font-medium">{service.name}</p>
                    <p className="text-sm text-muted-foreground">{service.message}</p>
                  </div>
                </div>
                <Badge 
                  variant="outline" 
                  className={`${getStatusColor(service.status)} text-white border-0`}
                >
                  {service.status}
                </Badge>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Metrics Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {/* CPU */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <Cpu className="h-4 w-4" />
              CPU Usage
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold mb-2">
              {metrics?.cpu.percent.toFixed(1)}%
            </div>
            <Progress 
              value={metrics?.cpu.percent} 
              className="h-2"
            />
            <p className="text-xs text-muted-foreground mt-2">
              {metrics?.cpu.count} cores @ {metrics?.cpu.frequency_mhz ? `${(metrics.cpu.frequency_mhz / 1000).toFixed(2)} GHz` : 'N/A'}
            </p>
          </CardContent>
        </Card>

        {/* Memory */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <MemoryStick className="h-4 w-4" />
              Memory Usage
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold mb-2">
              {metrics?.memory.percent.toFixed(1)}%
            </div>
            <Progress 
              value={metrics?.memory.percent} 
              className="h-2"
            />
            <p className="text-xs text-muted-foreground mt-2">
              {metrics?.memory.used_gb.toFixed(2)} GB / {metrics?.memory.total_gb.toFixed(2)} GB
            </p>
          </CardContent>
        </Card>

        {/* Disk */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <HardDrive className="h-4 w-4" />
              Disk Usage
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold mb-2">
              {metrics?.disk.percent}%
            </div>
            <Progress 
              value={metrics?.disk.percent} 
              className="h-2"
            />
            <p className="text-xs text-muted-foreground mt-2">
              {metrics?.disk.used_gb.toFixed(2)} GB / {metrics?.disk.total_gb.toFixed(2)} GB
            </p>
          </CardContent>
        </Card>

        {/* Network */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <Network className="h-4 w-4" />
              Network I/O
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Sent:</span>
                <span>{metrics && formatBytes(metrics.network.bytes_sent)}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Received:</span>
                <span>{metrics && formatBytes(metrics.network.bytes_recv)}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Packets:</span>
                <span>{metrics?.network.packets_sent + metrics?.network.packets_recv}</span>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Performance Chart */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Activity className="h-5 w-5" />
            Performance History
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={metricsHistory}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis 
                  dataKey="time" 
                  tick={{ fontSize: 12 }}
                  interval="preserveStartEnd"
                />
                <YAxis 
                  tick={{ fontSize: 12 }}
                  domain={[0, 100]}
                />
                <Tooltip />
                <Area
                  type="monotone"
                  dataKey="cpu"
                  stroke="#8884d8"
                  fill="#8884d8"
                  fillOpacity={0.3}
                  name="CPU %"
                />
                <Area
                  type="monotone"
                  dataKey="memory"
                  stroke="#82ca9d"
                  fill="#82ca9d"
                  fillOpacity={0.3}
                  name="Memory %"
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </CardContent>
      </Card>

      {/* Top Processes */}
      <Card>
        <CardHeader>
          <CardTitle>Top Processes</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-2">
            {metrics?.top_processes.map((process) => (
              <div
                key={process.pid}
                className="flex items-center justify-between p-3 border rounded-lg"
              >
                <div className="flex-1">
                  <p className="font-medium text-sm">{process.name}</p>
                  <p className="text-xs text-muted-foreground">PID: {process.pid}</p>
                </div>
                <div className="flex items-center gap-4 text-sm">
                  <div className="text-right">
                    <p className="font-medium">{process.cpu_percent}%</p>
                    <p className="text-xs text-muted-foreground">CPU</p>
                  </div>
                  <div className="text-right">
                    <p className="font-medium">{process.memory_percent.toFixed(1)}%</p>
                    <p className="text-xs text-muted-foreground">Memory</p>
                  </div>
                  <Badge variant="outline" className="text-xs">
                    {process.status}
                  </Badge>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Progress } from '@/components/ui/progress';
import { User, Mail, Calendar, Award, Target, BookOpen, Edit } from 'lucide-react';
import axiosClient from '@/api/axiosClient';

interface UserDetails {
  id: number;
  email: string;
  name: string;
  role: string;
  currentRole: string;
  created_at: string;
  updated_at: string;
  skills?: any[];
  assessments?: any[];
  careerRecommendations?: any[];
  learningPath?: any;
}

interface UserDetailsModalProps {
  userId: number | null;
  isOpen: boolean;
  onClose: () => void;
  onEditCareer: (userId: number) => void;
}

const UserDetailsModal = ({ userId, isOpen, onClose, onEditCareer }: UserDetailsModalProps) => {
  const [userDetails, setUserDetails] = useState<UserDetails | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (userId && isOpen) {
      fetchUserDetails();
    }
  }, [userId, isOpen]);

  const fetchUserDetails = async () => {
    if (!userId) return;

    try {
      setLoading(true);
      const response = await axiosClient.get(`/admin/users/${userId}`);
      setUserDetails(response.data);
      setError(null);
    } catch (error: any) {
      setError(error.response?.data?.detail || 'Failed to fetch user details');
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  const getSkillLevelColor = (level: string) => {
    switch (level.toLowerCase()) {
      case 'expert':
        return 'bg-green-500';
      case 'advanced':
        return 'bg-blue-500';
      case 'intermediate':
        return 'bg-yellow-500';
      case 'beginner':
        return 'bg-gray-500';
      default:
        return 'bg-gray-400';
    }
  };

  const renderProfileTab = () => {
    if (!userDetails) return null;

    return (
      <div className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <User className="h-5 w-5" />
                Basic Information
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center gap-2">
                <User className="h-4 w-4 text-muted-foreground" />
                <span className="font-medium">{userDetails.name}</span>
              </div>
              <div className="flex items-center gap-2">
                <Mail className="h-4 w-4 text-muted-foreground" />
                <span>{userDetails.email}</span>
              </div>
              <div className="flex items-center gap-2">
                <Badge variant={userDetails.role === 'ADMIN' ? 'destructive' : 'default'}>
                  {userDetails.role}
                </Badge>
              </div>
              {userDetails.currentRole && (
                <div className="flex items-center gap-2">
                  <Target className="h-4 w-4 text-muted-foreground" />
                  <span>Current Role: {userDetails.currentRole}</span>
                </div>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Calendar className="h-5 w-5" />
                Account Details
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div>
                <div className="text-sm text-muted-foreground">Joined</div>
                <div className="font-medium">{formatDate(userDetails.created_at)}</div>
              </div>
              <div>
                <div className="text-sm text-muted-foreground">Last Updated</div>
                <div className="font-medium">{formatDate(userDetails.updated_at)}</div>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  };

  const renderSkillsTab = () => {
    if (!userDetails?.skills) return null;

    return (
      <div className="space-y-4">
        {userDetails.skills.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            No skills assessed yet
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {userDetails.skills.map((skill, index) => (
              <Card key={index}>
                <CardContent className="pt-6">
                  <div className="flex items-center justify-between mb-2">
                    <span className="font-medium">{skill.name}</span>
                    <Badge variant="outline">{skill.level}</Badge>
                  </div>
                  <Progress value={skill.confidence} className="mb-2" />
                  <div className="text-sm text-muted-foreground">
                    Confidence: {skill.confidence}%
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>
    );
  };

  const renderAssessmentsTab = () => {
    if (!userDetails?.assessments) return null;

    return (
      <div className="space-y-4">
        {userDetails.assessments.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            No assessments completed
          </div>
        ) : (
          <div className="space-y-4">
            {userDetails.assessments.map((assessment, index) => (
              <Card key={index}>
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <Award className="h-5 w-5" />
                    Assessment #{assessment.id}
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-2 gap-4 mb-4">
                    <div>
                      <div className="text-sm text-muted-foreground">Status</div>
                      <Badge variant={assessment.status === 'completed' ? 'default' : 'secondary'}>
                        {assessment.status}
                      </Badge>
                    </div>
                    <div>
                      <div className="text-sm text-muted-foreground">Completed</div>
                      <div>{formatDate(assessment.completed_at)}</div>
                    </div>
                  </div>
                  <div>
                    <div className="text-sm text-muted-foreground mb-2">Skills Assessed</div>
                    <div className="flex flex-wrap gap-2">
                      {assessment.skills?.map((skill, skillIndex) => (
                        <Badge key={skillIndex} variant="outline">
                          {skill.skill_name} ({skill.level})
                        </Badge>
                      ))}
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>
    );
  };

  const renderCareerTab = () => {
    if (!userDetails?.careerRecommendations) return null;

    return (
      <div className="space-y-6">
        <div className="flex justify-between items-center">
          <h3 className="text-lg font-semibold">Career Recommendations</h3>
          <Button onClick={() => onEditCareer(userDetails.id)}>
            <Edit className="h-4 w-4 mr-2" />
            Edit Recommendations
          </Button>
        </div>

        {userDetails.careerRecommendations.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            No career recommendations yet
          </div>
        ) : (
          <div className="space-y-4">
            {userDetails.careerRecommendations.map((rec, index) => (
              <Card key={index}>
                <CardHeader>
                  <CardTitle>{rec.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-muted-foreground mb-4">{rec.description}</p>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <div className="text-sm text-muted-foreground">Industry</div>
                      <div>{rec.industry}</div>
                    </div>
                    <div>
                      <div className="text-sm text-muted-foreground">Match Score</div>
                      <div>{rec.match_score}%</div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>
    );
  };

  const renderLearningTab = () => {
    if (!userDetails?.learningPath) return null;

    const path = userDetails.learningPath;

    return (
      <div className="space-y-6">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <BookOpen className="h-5 w-5" />
              Learning Path
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-2 gap-4 mb-4">
              <div>
                <div className="text-sm text-muted-foreground">Target Role</div>
                <div className="font-medium">{path.target_role_title}</div>
              </div>
              <div>
                <div className="text-sm text-muted-foreground">Progress</div>
                <div className="flex items-center gap-2">
                  <Progress value={path.progress} className="flex-1" />
                  <span className="text-sm">{path.progress}%</span>
                </div>
              </div>
            </div>
            <div>
              <div className="text-sm text-muted-foreground mb-2">Duration</div>
              <div>{path.total_duration}</div>
            </div>
          </CardContent>
        </Card>

        <div>
          <h4 className="font-semibold mb-4">Learning Steps</h4>
          <div className="space-y-3">
            {path.steps?.map((step, index) => (
              <Card key={index}>
                <CardContent className="pt-6">
                  <div className="flex items-start gap-4">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${
                      step.is_completed ? 'bg-green-500 text-white' : 'bg-gray-200 text-gray-600'
                    }`}>
                      {index + 1}
                    </div>
                    <div className="flex-1">
                      <h5 className="font-medium">{step.title}</h5>
                      <p className="text-sm text-muted-foreground mt-1">{step.description}</p>
                      <div className="flex items-center gap-2 mt-2">
                        <Badge variant={step.is_completed ? 'default' : 'secondary'}>
                          {step.is_completed ? 'Completed' : 'Pending'}
                        </Badge>
                        <span className="text-sm text-muted-foreground">
                          Duration: {step.duration}
                        </span>
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        </div>
      </div>
    );
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>User Details</DialogTitle>
        </DialogHeader>

        {loading ? (
          <div className="space-y-4">
            <Skeleton className="h-8 w-48" />
            <Skeleton className="h-32 w-full" />
            <Skeleton className="h-32 w-full" />
          </div>
        ) : error ? (
          <Alert variant="destructive">
            <AlertDescription>{error}</AlertDescription>
          </Alert>
        ) : userDetails ? (
          <Tabs defaultValue="profile" className="w-full">
            <TabsList className="grid w-full grid-cols-5">
              <TabsTrigger value="profile">Profile</TabsTrigger>
              <TabsTrigger value="skills">Skills</TabsTrigger>
              <TabsTrigger value="assessments">Assessments</TabsTrigger>
              <TabsTrigger value="career">Career</TabsTrigger>
              <TabsTrigger value="learning">Learning</TabsTrigger>
            </TabsList>

            <TabsContent value="profile" className="mt-6">
              {renderProfileTab()}
            </TabsContent>

            <TabsContent value="skills" className="mt-6">
              {renderSkillsTab()}
            </TabsContent>

            <TabsContent value="assessments" className="mt-6">
              {renderAssessmentsTab()}
            </TabsContent>

            <TabsContent value="career" className="mt-6">
              {renderCareerTab()}
            </TabsContent>

            <TabsContent value="learning" className="mt-6">
              {renderLearningTab()}
            </TabsContent>
          </Tabs>
        ) : null}
      </DialogContent>
    </Dialog>
  );
};

export default UserDetailsModal;

import { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle,DialogDescription, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { AlertCircle } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import axiosClient from '@/api/axiosClient';

interface UserFormProps {
  userId: number | null;
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  isEditMode: boolean;
}

interface UserData {
  id?: number;
  email: string;
  name: string;
  role: string;
  currentRole: string;
  password?: string;
}

export default function UserForm({ userId, isOpen, onClose, onSuccess, isEditMode }: UserFormProps) {
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [fetchingUser, setFetchingUser] = useState(false);
  const [error, setError] = useState<string | null>(null);
  
  const [formData, setFormData] = useState<UserData>({
    email: '',
    name: '',
    role: 'user',
    currentRole: '',
    password: ''
  });

  useEffect(() => {
    if (isOpen && isEditMode && userId) {
      fetchUserData();
    } else if (isOpen && !isEditMode) {
      // Reset form for new user
      setFormData({
        email: '',
        name: '',
        role: 'user',
        currentRole: '',
        password: ''
      });
      setError(null);
    }
  }, [isOpen, userId, isEditMode]);

  const fetchUserData = async () => {
    if (!userId) return;
    
    try {
      setFetchingUser(true);
      const response = await axiosClient.get(`/admin/users/${userId}`);
      const user = response.data;
      
      setFormData({
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role,
        currentRole: user.currentRole || '',
        password: '' // Don't populate password
      });
      setError(null);
    } catch (error: any) {
      setError(error.response?.data?.detail || 'Failed to fetch user data');
    } finally {
      setFetchingUser(false);
    }
  };

  const handleSubmit = async () => {
    try {
      setLoading(true);
      setError(null);

      // Validation
      if (!formData.email || !formData.name) {
        setError('Email and name are required');
        return;
      }

      if (!isEditMode && !formData.password) {
        setError('Password is required for new users');
        return;
      }

      const payload = {
        email: formData.email,
        name: formData.name,
        role: formData.role,
        currentRole: formData.currentRole,
        ...(formData.password && { password: formData.password })
      };

      if (isEditMode && userId) {
        // Update existing user
        await axiosClient.put(`/admin/users/${userId}`, payload);
        toast({
          title: "Success",
          description: "User updated successfully",
        });
      } else {
        // Create new user
        await axiosClient.post('/admin/users', payload);
        toast({
          title: "Success",
          description: "User created successfully",
        });
      }

      onSuccess();
      onClose();
    } catch (error: any) {
      setError(error.response?.data?.detail || 'Failed to save user');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!userId) return;
    
    if (!confirm('Are you sure you want to delete this user? This action cannot be undone.')) {
      return;
    }

    try {
      setLoading(true);
      await axiosClient.delete(`/admin/users/${userId}`);
      
      toast({
        title: "Success",
        description: "User deleted successfully",
      });
      
      onSuccess();
      onClose();
    } catch (error: any) {
      setError(error.response?.data?.detail || 'Failed to delete user');
      setLoading(false);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>
              {isEditMode ? 'Edit User' : 'Create New User'}
            </DialogTitle>
            <DialogDescription>
              {isEditMode ? 'Update user information' : 'Create a new user account'}
            </DialogDescription>
          </DialogHeader>      

        {fetchingUser ? (
          <div className="py-8 text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto"></div>
            <p className="mt-2 text-sm text-muted-foreground">Loading user data...</p>
          </div>
        ) : (
          <div className="space-y-4 py-4">
            {error && (
              <Alert variant="destructive">
                <AlertCircle className="h-4 w-4" />
                <AlertDescription>{error}</AlertDescription>
              </Alert>
            )}

            <div>
              <Label htmlFor="email">Email *</Label>
              <Input
                id="email"
                type="email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                placeholder="user@example.com"
                disabled={isEditMode} // Email cannot be changed
              />
            </div>

            <div>
              <Label htmlFor="name">Full Name *</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                placeholder="John Doe"
              />
            </div>

            <div>
              <Label htmlFor="role">Role</Label>
              <Select
                value={formData.role}
                onValueChange={(value) => setFormData({ ...formData, role: value })}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="user">User</SelectItem>
                  <SelectItem value="admin">Admin</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label htmlFor="currentRole">Current Job Role</Label>
              <Input
                id="currentRole"
                value={formData.currentRole}
                onChange={(e) => setFormData({ ...formData, currentRole: e.target.value })}
                placeholder="Software Engineer"
              />
            </div>

            <div>
              <Label htmlFor="password">
                {isEditMode ? 'New Password (leave blank to keep current)' : 'Password *'}
              </Label>
              <Input
                id="password"
                type="password"
                value={formData.password}
                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                placeholder={isEditMode ? 'ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó' : 'Enter password'}
              />
            </div>
          </div>
        )}

        <DialogFooter className="gap-2">
          {isEditMode && (
            <Button
              variant="destructive"
              onClick={handleDelete}
              disabled={loading || fetchingUser}
            >
              Delete User
            </Button>
          )}
          <Button
            variant="outline"
            onClick={onClose}
            disabled={loading}
          >
            Cancel
          </Button>
          <Button
            onClick={handleSubmit}
            disabled={loading || fetchingUser}
          >
            {loading ? 'Saving...' : (isEditMode ? 'Update User' : 'Create User')}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Search, Users, Eye, Edit, RefreshCw } from 'lucide-react';
import { useCallback } from 'react';
import axiosClient from '@/api/axiosClient';

interface User {
  id: number;
  email: string;
  name: string;
  role: string;
  currentRole: string;
  created_at: string;
  updated_at: string;
}

interface UsersResponse {
  users: User[];
  total: number;
  page: number;
  limit: number;
}

interface UserManagementTableProps {
  onViewUser: (userId: number) => void;
  onEditUser: (userId: number) => void;
  refreshKey?: number;
}

const UserManagementTable = ({ onViewUser, onEditUser }: UserManagementTableProps) => {
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState('');
  const [roleFilter, setRoleFilter] = useState<string>('all');
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [refreshKey, setRefreshKey] = useState(0);

  const limit = 10;

  const fetchUsers = useCallback(async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams({
        page: page.toString(),
        skip: ((page - 1) * limit).toString(),
        limit: limit.toString(),
        search: search,
        role: roleFilter === 'all' ? '' : roleFilter
      });

      const response = await axiosClient.get(`/admin/users?${params}`);
      setUsers(response.data.users);
      setTotal(response.data.total);
      setError(null);
    } catch (error: any) {
      setError(error.response?.data?.detail || 'Failed to fetch users');
    } finally {
      setLoading(false);
    }
  }, [page, search, roleFilter, limit, axiosClient]);

  const refreshUsers = () => {
    setRefreshKey(prev => prev + 1);
  };

  useEffect(() => {
    fetchUsers();
  }, [search, roleFilter, page, refreshKey]);




  const handleSearch = (value: string) => {
    setSearch(value);
    setPage(1);
  };

  const handleRoleFilter = (value: string) => {
    setRoleFilter(value);
    setPage(1);
  };

  const formatDate = (dateString: string | null | undefined) => {
    if (!dateString) return 'N/A';
    try {
      return new Date(dateString).toLocaleDateString();
    } catch {
      return 'Invalid Date';
    }
  };

  const getRoleBadgeVariant = (role: string) => {
    switch (role?.toLowerCase()) {
      case 'admin':
        return 'destructive';
      case 'user':
        return 'default';
      default:
        return 'secondary';
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Users className="h-5 w-5" />
          User Management
        </CardTitle>
      </CardHeader>
      <CardContent>
        {/* Filters */}
        <div className="flex gap-4 mb-6">
          <div className="flex-1">
            <div className="relative">
              <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Search by name or email..."
                value={search}
                onChange={(e) => handleSearch(e.target.value)}
                className="pl-10"
              />
            </div>
          </div>

            <Select onValueChange={handleRoleFilter} value={roleFilter}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="All Roles" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Roles</SelectItem>
              <SelectItem value="user">User</SelectItem>
              <SelectItem value="admin">Admin</SelectItem>
            </SelectContent>
          </Select>
          <Button variant="ghost" size="sm" onClick={refreshUsers}>
            <RefreshCw className="h-4 w-4 mr-2" />
            Refresh
          </Button>
        </div>

        {/* Table */}
        {loading ? (
          <div className="space-y-4">
            {Array.from({ length: 5 }).map((_, i) => (
              <div key={i} className="flex gap-4">
                <Skeleton className="h-12 flex-1" />
                <Skeleton className="h-12 w-24" />
                <Skeleton className="h-12 w-20" />
              </div>
            ))}
          </div>
        ) : error ? (
          <Alert variant="destructive">
            <AlertDescription>{error}</AlertDescription>
          </Alert>
        ) : (
          <>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Name</TableHead>
                  <TableHead>Email</TableHead>
                  <TableHead>Role</TableHead>
                  <TableHead>Current Role</TableHead>
                  <TableHead>Joined</TableHead>
                  <TableHead>Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {users.map((user) => (
                  <TableRow key={user.id}>
                    <TableCell className="font-medium">{user.name}</TableCell>
                    <TableCell>{user.email}</TableCell>
                    <TableCell>
                      <Badge variant={getRoleBadgeVariant(user.role)}>
                        {user.role}
                      </Badge>
                    </TableCell>
                    <TableCell>{user.currentRole || 'Not set'}</TableCell>
                    <TableCell>{formatDate(user.created_at)}</TableCell>
                    <TableCell>
                    <div className="flex gap-2">
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => onViewUser(user.id)}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => onEditUser(user.id)}
                      >
                        <Edit className="h-4 w-4" />
                      </Button>
                    </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>

            {/* Pagination */}
            {total > limit && (
              <div className="flex justify-between items-center mt-4">
                <div className="text-sm text-muted-foreground">
                  Showing {((page - 1) * limit) + 1} to {Math.min(page * limit, total)} of {total} users
                </div>
                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setPage(page - 1)}
                    disabled={page === 1}
                  >
                    Previous
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setPage(page + 1)}
                    disabled={page * limit >= total}
                  >
                    Next
                  </Button>
                </div>
              </div>
            )}
          </>
        )}
      </CardContent>
    </Card>
  );
};

export default UserManagementTable;

import { useApp } from '@/contexts/AppContext';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { 
  Trophy, 
  Star, 
  Target, 
  Zap, 
  Crown, 
  Medal,
  Flame,
  Rocket,
  Brain,
  Lightbulb
} from 'lucide-react';
import { cn } from '@/lib/utils';

interface Achievement {
  id: string;
  title: string;
  description: string;
  icon: React.ElementType;
  unlocked: boolean;
  progress: number;
  color: string;
}

export function Achievements() {
  const { userSkills, isLoadingSkills, careerMatches, learningPath } = useApp();

  // Calculate achievements based on user data
  const achievements = [

    {
      id: 'first-assessment',
      title: 'First Steps',
      description: 'Complete your first skill assessment',
      icon: Target,
      unlocked: userSkills.length >= 1,
      progress: Math.min((userSkills.length / 1) * 100, 100),
      color: 'bg-blue-500'
    },
    {
      id: 'skill-master',
      title: 'Skill Master',
      description: 'Achieve expert level in 3 skills',
      icon: Crown,
      unlocked: userSkills.filter((s: any) => (s.score || 0) >= 80).length >= 3,
      progress: Math.min((userSkills.filter((s: any) => (s.score || 0) >= 80).length / 3) * 100, 100),
      color: 'bg-yellow-500'
    },
    {
      id: 'assessment-streak',
      title: 'Assessment Streak',
      description: 'Complete 10 skill assessments',
      icon: Flame,
      unlocked: userSkills.length >= 10,
      progress: Math.min((userSkills.length / 10) * 100, 100),
      color: 'bg-orange-500'
    },
    {
      id: 'career-explorer',
      title: 'Career Explorer',
      description: 'View 5 career matches',
      icon: Rocket,
      unlocked: careerMatches.length >= 5,
      progress: Math.min((careerMatches.length / 5) * 100, 100),
      color: 'bg-purple-500'
    },
    {
      id: 'learning-starter',
      title: 'Learning Starter',
      description: 'Begin your first learning path',
      icon: Brain,
      unlocked: learningPath !== null,
      progress: learningPath ? 100 : 0,
      color: 'bg-green-500'
    },
    {
      id: 'path-completer',
      title: 'Path Completer',
      description: 'Complete a learning path',
      icon: Medal,
      unlocked: (learningPath?.progress || 0) === 100,
      progress: learningPath?.progress || 0,
      color: 'bg-pink-500'
    },
    {
      id: 'quick-learner',
      title: 'Quick Learner',
      description: 'Score 90%+ on any assessment',
      icon: Zap,
      unlocked: userSkills.some((s: any) => (s.score || 0) >= 90),
      progress: userSkills.some((s: any) => (s.score || 0) >= 90) ? 100 : 
        Math.max(...userSkills.map((s: any) => s.score || 0), 0),
      color: 'bg-red-500'
    },
    {
      id: 'knowledge-seeker',
      title: 'Knowledge Seeker',
      description: 'Complete 20 assessments',
      icon: Lightbulb,
      unlocked: userSkills.length >= 20,
      progress: Math.min((userSkills.length / 20) * 100, 100),
      color: 'bg-indigo-500'
    }
  ];

  const unlockedCount = achievements.filter(a => a.unlocked).length;
  const totalCount = achievements.length;

  if (isLoadingSkills) {
    return (
      <Card className="h-full">
        <CardHeader className="pb-2">
          <Skeleton className="h-6 w-32" />
          <Skeleton className="h-4 w-48" />
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-4 gap-3">
            {Array.from({ length: 8 }).map((_, i) => (
              <Skeleton key={i} className="aspect-square rounded-lg" />
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="h-full">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="text-lg font-display flex items-center gap-2">
              <Trophy className="w-5 h-5 text-yellow-500" />
              Achievements
            </CardTitle>
            <p className="text-sm text-muted-foreground">
              {unlockedCount} of {totalCount} unlocked
            </p>
          </div>
          <div className="flex items-center gap-1">
            <Star className="w-4 h-4 text-yellow-500 fill-yellow-500" />
            <span className="font-bold">{unlockedCount}</span>
          </div>
        </div>
      </CardHeader>
      <CardContent>
        <div className="grid grid-cols-4 gap-3">
          {achievements.map((achievement) => (
            <div
              key={achievement.id}
              className={cn(
                "relative aspect-square rounded-lg p-2 flex flex-col items-center justify-center text-center transition-all cursor-pointer group",
                achievement.unlocked 
                  ? "bg-muted hover:bg-muted/80" 
                  : "bg-muted/30 opacity-60 grayscale"
              )}
              title={`${achievement.title}: ${achievement.description} (${Math.round(achievement.progress)}%)`}
            >
              <div className={cn(
                "w-8 h-8 rounded-full flex items-center justify-center mb-1",
                achievement.unlocked ? achievement.color : "bg-gray-300",
                "text-white"
              )}>
                <achievement.icon className="w-4 h-4" />
              </div>
              <span className="text-[10px] font-medium leading-tight line-clamp-2">
                {achievement.title}
              </span>
              
              {/* Progress bar for locked achievements */}
              {!achievement.unlocked && achievement.progress > 0 && (
                <div className="absolute bottom-1 left-1 right-1 h-1 bg-gray-200 rounded-full overflow-hidden">
                  <div 
                    className={cn("h-full rounded-full", achievement.color)}
                    style={{ width: `${achievement.progress}%` }}
                  />
                </div>
              )}
              
              {/* Unlocked indicator */}
              {achievement.unlocked && (
                <div className="absolute -top-1 -right-1 w-4 h-4 bg-green-500 rounded-full flex items-center justify-center">
                  <Star className="w-2.5 h-2.5 text-white fill-white" />
                </div>
              )}
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

import { useApp } from '@/contexts/AppContext';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { ProgressRing } from '@/components/ui/progress-ring';
import { ArrowRight, TrendingUp, Briefcase, DollarSign, Clock, Star } from 'lucide-react';
import { Link } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils';
import { Skeleton } from '@/components/ui/skeleton';

// API response format
interface CareerMatchFromAPI {
  role_id: number;
  title: string;
  level: string;
  match_percentage: number;
  matched_skills: string[];
  missing_skills: string[];
  explanation?: string;
  average_salary?: {
    min: number;
    max: number;
    currency: string;
  };
  growth_rate?: number;
  market_outlook?: string;
  estimated_time_to_qualify?: string;
  key_skills?: string[];
}

export function CareerMatches() {
  const { careerMatches, isLoadingCareers } = useApp();

  // Handle both old and new API formats
  const matches = Array.isArray(careerMatches) ? careerMatches : [];
  const topMatches = matches.slice(0, 3) as any[];

  const formatSalary = (min: number, max: number) => {
    return `$${(min / 1000).toFixed(0)}k-${(max / 1000).toFixed(0)}k`;
  };

  const getOutlookColor = (outlook: string) => {
    switch (outlook) {
      case 'Excellent': return 'bg-green-100 text-green-800';
      case 'Good': return 'bg-blue-100 text-blue-800';
      case 'Moderate': return 'bg-yellow-100 text-yellow-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  if (isLoadingCareers) {
    return (
      <Card className="h-full">
        <CardHeader className="pb-2">
          <Skeleton className="h-6 w-40" />
          <Skeleton className="h-4 w-48" />
        </CardHeader>
        <CardContent className="space-y-4">
          {Array.from({ length: 3 }).map((_, i) => (
            <div key={i} className="flex items-center gap-4 p-3">
              <Skeleton className="w-14 h-14 rounded-full" />
              <div className="flex-1 space-y-2">
                <Skeleton className="h-4 w-32" />
                <Skeleton className="h-3 w-48" />
              </div>
              <div className="space-y-1">
                <Skeleton className="h-3 w-16" />
                <Skeleton className="h-3 w-20" />
              </div>
            </div>
          ))}
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="h-full">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="text-lg font-display">Top Career Matches</CardTitle>
            <p className="text-sm text-muted-foreground">Based on your current skills</p>
          </div>
          <Button variant="ghost" size="sm" asChild>
            <Link to="/careers" className="gap-1">
              Explore <ArrowRight className="w-4 h-4" />
            </Link>
          </Button>
        </div>
      </CardHeader>
      <CardContent className="space-y-4">
        {topMatches.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            <Briefcase className="w-8 h-8 mx-auto mb-2 opacity-50" />
            <p>Complete assessments to see career matches</p>
          </div>
        ) : (
          topMatches.map((match, index) => {
            const matchScore = match.match_percentage || match.matchScore || 0;
            const hasSalary = match.average_salary || match.averageSalary;
            const hasGrowth = match.growth_rate || match.growthRate;

            return (
              <div
                key={match.role_id || match.roleId}
                className={cn(
                  "flex items-start gap-4 p-3 rounded-lg border transition-colors hover:bg-muted/50",
                  index === 0 && "border-primary/30 bg-primary/5"
                )}
              >
                <ProgressRing value={matchScore} size={56} strokeWidth={5}>
                  <span className="text-sm font-bold">{Math.round(matchScore)}%</span>
                </ProgressRing>

                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-2">
                    <div>
                      <h4 className="font-semibold text-sm truncate">{match.title}</h4>
                      <div className="flex items-center gap-2 mt-0.5">
                        <span className="text-xs text-muted-foreground capitalize">
                          {match.level}
                        </span>
                        {match.market_outlook && (
                          <Badge className={cn("text-[10px] px-1.5 py-0", getOutlookColor(match.market_outlook))}>
                            {match.market_outlook}
                          </Badge>
                        )}
                      </div>
                    </div>
                    {index === 0 && (
                      <Star className="w-4 h-4 text-primary fill-primary flex-shrink-0" />
                    )}
                  </div>

                  <div className="flex items-center gap-3 mt-2 text-xs text-muted-foreground">
                    <span className="flex items-center gap-1">
                      <TrendingUp className="w-3 h-3" />
                      {match.matched_skills?.length || match.matchedCount || 0} skills
                    </span>

                    {hasSalary && (
                      <span className="flex items-center gap-1 text-green-600">
                        <DollarSign className="w-3 h-3" />
                        {formatSalary(
                          hasSalary.min || 50000, 
                          hasSalary.max || 100000
                        )}
                      </span>
                    )}

                    {hasGrowth && (
                      <span className="flex items-center gap-1 text-blue-600">
                        <TrendingUp className="w-3 h-3" />
                        +{(hasGrowth || 0).toFixed(0)}%
                      </span>
                    )}
                  </div>

                  {match.estimated_time_to_qualify && match.estimated_time_to_qualify !== 'Ready now' && (
                    <div className="flex items-center gap-1 mt-1.5 text-xs text-muted-foreground">
                      <Clock className="w-3 h-3" />
                      <span>Est. {match.estimated_time_to_qualify} to qualify</span>
                    </div>
                  )}

                  {match.key_skills && match.key_skills.length > 0 && (
                    <div className="flex flex-wrap gap-1 mt-2">
                      {match.key_skills.slice(0, 2).map((skill: string, i: number) => (
                        <Badge key={i} variant="outline" className="text-[10px] px-1.5 py-0">
                          {skill}
                        </Badge>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            );
          })
        )}
      </CardContent>
    </Card>
  );
}

import { useEffect, useState, useCallback } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import { CheckCircle2, Trophy, ArrowRight, Calendar, RefreshCw } from 'lucide-react';
import { useNavigate } from 'react-router-dom';


interface CompletedAssessment {
  skill_id: number;
  skill_name: string;
  score: number;
  level: string;
  confidence: number;
  completed_at: string;
}

export function CompletedAssessments() {
  const [assessments, setAssessments] = useState<CompletedAssessment[]>([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  const fetchCompletedAssessments = useCallback(async () => {
    try {
      setLoading(true);
      
      // Get token from localStorage (try both possible keys)
      const token = localStorage.getItem('authToken') || localStorage.getItem('token') || localStorage.getItem('access_token');
      
      if (!token) {
        console.error('No auth token found in localStorage');
        setLoading(false);
        return;
      }
      
      console.log('Fetching completed assessments with token...');
      
      // Fetch from API endpoint
      const response = await fetch('http://localhost:5000/api/assessment/completed', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      console.log('Response status:', response.status);

      if (response.ok) {
        const data = await response.json();
        console.log('RAW API Response:', JSON.stringify(data, null, 2));
        console.log('Received assessments:', data.assessments?.length || 0);
        if (data.assessments?.length > 0) {
          console.log('First assessment raw:', data.assessments[0]);
        }
        // Ensure assessments is always an array
        const assessmentsArray = Array.isArray(data.assessments) ? data.assessments : [];
        console.log('Setting assessments array:', assessmentsArray.length);
        setAssessments(assessmentsArray);
      } else {
        const errorText = await response.text();
        console.error('Failed to fetch assessments:', response.status, errorText);
        
        // Fallback: try to get from user_skills endpoint
        const skillsResponse = await fetch('http://localhost:5000/api/skills/user-skills', {
          headers: {
            'Authorization': `Bearer ${token}`
          }
        });
        
        if (skillsResponse.ok) {
          const skillsData = await skillsResponse.json();
          console.log('Fallback - received skills:', skillsData.skills?.length || 0);
          console.log('Fallback - raw skills data:', JSON.stringify(skillsData, null, 2));
          
          // Transform user skills to assessment format
          const transformedAssessments = (skillsData.skills || [])
            .filter((skill: any) => {
              const hasScore = skill.score > 0;
              console.log(`Skill ${skill.skill_name} (ID: ${skill.skill_id}): score=${skill.score}, hasScore=${hasScore}`);
              return hasScore;
            })
            .map((skill: any) => ({
              skill_id: skill.skill_id,
              skill_name: skill.skill_name,
              score: skill.score,
              level: skill.level || 'Beginner',
              confidence: skill.confidence || 0,
              completed_at: skill.assessed_at || new Date().toISOString()
            }))
            .sort((a: any, b: any) => new Date(b.completed_at).getTime() - new Date(a.completed_at).getTime());
          
          console.log('Transformed assessments:', transformedAssessments.length);
          console.log('Transformed data:', JSON.stringify(transformedAssessments, null, 2));
          setAssessments(transformedAssessments);
        } else {
          console.error('Fallback also failed:', skillsResponse.status);
        }
      }
    } catch (error) {
      console.error('Error fetching completed assessments:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  // Initial fetch on mount
  useEffect(() => {
    fetchCompletedAssessments();
  }, [fetchCompletedAssessments]);

  // Listen for assessment completion events
  useEffect(() => {
    const handleAssessmentComplete = () => {
      console.log('Assessment completed event received, refreshing...');
      fetchCompletedAssessments();
    };

    // Listen for custom event
    window.addEventListener('assessmentCompleted', handleAssessmentComplete);
    
    // Also listen for storage changes (in case other tabs update)
    const handleStorageChange = (e: StorageEvent) => {
      if (e.key === 'lastAssessmentCompleted') {
        console.log('Storage change detected, refreshing assessments...');
        fetchCompletedAssessments();
      }
    };
    window.addEventListener('storage', handleStorageChange);

    return () => {
      window.removeEventListener('assessmentCompleted', handleAssessmentComplete);
      window.removeEventListener('storage', handleStorageChange);
    };
  }, [fetchCompletedAssessments]);



  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-green-600 bg-green-100';
    if (score >= 60) return 'text-blue-600 bg-blue-100';
    if (score >= 40) return 'text-yellow-600 bg-yellow-100';
    return 'text-red-600 bg-red-100';
  };

  const getLevelBadgeVariant = (level: string) => {
    const lowerLevel = level.toLowerCase();
    if (lowerLevel === 'expert') return 'default';
    if (lowerLevel === 'advanced') return 'secondary';
    if (lowerLevel === 'intermediate') return 'outline';
    return 'secondary';
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric'
    });
  };

  if (loading) {
    return (
      <Card className="h-full">
        <CardHeader className="pb-2">
          <Skeleton className="h-6 w-40" />
          <Skeleton className="h-4 w-48" />
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            <Skeleton className="h-16 w-full" />
            <Skeleton className="h-16 w-full" />
            <Skeleton className="h-16 w-full" />
          </div>
        </CardContent>
      </Card>
    );
  }

  if (assessments.length === 0) {
    console.log('RENDERING EMPTY STATE - assessments array is empty');
    return (
      <Card className="h-full">
        <CardHeader className="pb-2">
          <CardTitle className="text-lg font-display flex items-center gap-2">
            <Trophy className="w-5 h-5 text-yellow-500" />
            Completed Assessments
          </CardTitle>
          <p className="text-sm text-muted-foreground">Your assessment history and scores</p>
        </CardHeader>
        <CardContent>
          <div className="text-center py-8">
            <div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center mx-auto mb-4">
              <CheckCircle2 className="w-8 h-8 text-muted-foreground" />
            </div>
            <p className="text-muted-foreground mb-4">No completed assessments yet</p>
            <Button onClick={() => navigate('/skill_selection')} size="sm">
              Take Your First Assessment
            </Button>
          </div>
        </CardContent>
      </Card>
    );
  }


  // Debug: Log what's being rendered
  console.log('RENDERING - assessments count:', assessments.length);
  if (assessments.length > 0) {
    console.log('RENDERING - first assessment:', {
      name: assessments[0].skill_name,
      score: assessments[0].score,
      scoreType: typeof assessments[0].score
    });
  }

  return (
    <Card className="h-full">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="text-lg font-display flex items-center gap-2">
              <Trophy className="w-5 h-5 text-yellow-500" />
              Completed Assessments
            </CardTitle>
            <p className="text-sm text-muted-foreground">
              {assessments.length} assessment{assessments.length !== 1 ? 's' : ''} completed
            </p>
          </div>
          <Button 
            variant="ghost" 
            size="icon" 
            onClick={fetchCompletedAssessments}
            disabled={loading}
            className="h-8 w-8"
          >
            <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
          </Button>
        </div>
      </CardHeader>

      <CardContent>
        <div className="space-y-3 max-h-[300px] overflow-y-auto pr-1">
          {assessments.map((assessment, index) => (
            <div
              key={`${assessment.skill_id}-${index}`}
              className="flex items-center justify-between p-3 rounded-lg border border-border hover:bg-muted/50 transition-colors"
            >

              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1">
                  <h4 className="font-medium truncate">{assessment.skill_name}</h4>
                  <Badge variant={getLevelBadgeVariant(assessment.level)} className="text-xs">
                    {assessment.level}
                  </Badge>
                </div>
                <div className="flex items-center gap-2 text-xs text-muted-foreground">
                  <Calendar className="w-3 h-3" />
                  {formatDate(assessment.completed_at)}
                </div>
              </div>
              
              <div className="flex items-center gap-3 ml-4">
                <div className={`px-3 py-1.5 rounded-full font-bold text-sm ${getScoreColor(assessment.score)}`}>
                  {typeof assessment.score === 'number' ? assessment.score.toFixed(1) : assessment.score}%
                </div>
              </div>

            </div>
          ))}
        </div>
        
        <div className="mt-4 pt-3 border-t space-y-2">
          <Button 
            variant="outline" 
            className="w-full text-sm"
            onClick={() => navigate('/assessment-history')}
          >
            View Full History
            <ArrowRight className="w-4 h-4 ml-2" />
          </Button>
          <Button 
            variant="ghost" 
            className="w-full text-sm"
            onClick={() => navigate('/skill_selection')}
          >
            Take More Assessments
            <ArrowRight className="w-4 h-4 ml-2" />
          </Button>
        </div>

      </CardContent>
    </Card>
  );
}

import { useApp } from '@/contexts/AppContext';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { Skeleton } from '@/components/ui/skeleton';
import { 
  GraduationCap, 
  Clock, 
  CheckCircle2, 
  Play,
  ArrowRight,
  BookOpen,
  PlayCircle
} from 'lucide-react';
import { Link } from 'react-router-dom';
import { Badge } from '@/components/ui/badge';
import { useState, useCallback } from 'react';
import { useToast } from '@/hooks/use-toast';

export function LearningPathCard() {
  const { learningPath, isLoadingLearning, markStepComplete } = useApp();
  const [isMarkingComplete, setIsMarkingComplete] = useState(false);
  const { toast } = useToast();

  // Always calculate first - fixes hook order
  const completedSteps = learningPath?.steps?.filter((s: any) => s.isCompleted || s.is_completed).length || 0;
  const totalSteps = learningPath?.steps?.length || 0;
  const clientProgress = totalSteps > 0 ? Math.round((completedSteps / totalSteps) * 100) : 0;
  const nextStep = learningPath?.steps?.find((s: any) => !s.isCompleted && !s.is_completed);

  const handleTestMarkComplete = useCallback(async () => {
    if (!nextStep || !learningPath) {
      toast({
        title: 'No step to test',
        description: 'Complete path or refresh',
      });
      return;
    }

    setIsMarkingComplete(true);
    try {
      toast({
        title: 'Testing...',
        description: 'markStepComplete ΓåÆ instant update',
      });

      await markStepComplete(nextStep.id.toString());

      toast({
        title: 'Γ£à Complete!',
        description: `${clientProgress + Math.round(100/totalSteps)}% progress`,
      });
    } catch (error) {
      toast({
        title: 'Γ¥î Error',
        description: 'Check console',
        variant: 'destructive',
      });
      console.error(error);
    } finally {
      setIsMarkingComplete(false);
    }
  }, [nextStep, learningPath, markStepComplete, clientProgress, totalSteps, toast]);

  if (isLoadingLearning) {
    return (
      <Card className="h-full">
