function generateAIResponse(message: string, context: any): string {
  const { userSkills, careerMatches, allGaps } = context;

  const lowerMessage = message.toLowerCase();

  if (lowerMessage.includes('skill') && lowerMessage.includes('focus')) {
    const topGaps = allGaps.slice(0, 3);
    if (topGaps.length > 0) {
      return `Based on your assessment, I recommend focusing on these skills first:\n\n${topGaps.map((g: any, i: number) => 
        `${i + 1}. **${g.skill.name}** - ${g.severity} priority gap (${g.currentScore}% ΓåÆ ${g.requiredScore}%)`
      ).join('\n')}\n\nThese skills have the highest impact on your target career paths. Start with ${topGaps[0].skill.name} as it appears most frequently in your matched roles.`;
    }
    return "Complete your skill assessment first so I can provide personalized recommendations!";
  }

  if (lowerMessage.includes('gap')) {
    const highGaps = allGaps.filter((g: any) => g.severity === 'high');
    if (highGaps.length > 0) {
      return `You have ${highGaps.length} high-priority skill gaps:\n\n${highGaps.slice(0, 4).map((g: any) => 
        `ΓÇó **${g.skill.name}**: Need to improve by ${g.gapScore} points`
      ).join('\n')}\n\n**Strategy:** Dedicate 2-3 focused hours weekly to each skill. Use hands-on projects alongside courses for faster retention.`;
    }
    return "Great news! You don't have any critical skill gaps. Focus on refining your existing strengths.";
  }

  if (lowerMessage.includes('career') || lowerMessage.includes('path')) {
    const topMatch = careerMatches[0];
    if (topMatch) {
      const title = topMatch.title || topMatch.role?.title || 'Unknown Role';
      const minSalary = topMatch.averageSalary?.min || topMatch.role?.averageSalary?.min || 0;
      const maxSalary = topMatch.averageSalary?.max || topMatch.role?.averageSalary?.max || 0;
      const growthRate = topMatch.growthRate || topMatch.role?.growthRate || 0;
      return `Based on your skills, **${title}** is your best match at ${topMatch.matchScore}%!\n\n**Why this fits you:**\n${topMatch.reasoning}\n\n**Salary range:** $${Math.round(minSalary/1000)}k - $${Math.round(maxSalary/1000)}k\n**Growth rate:** +${growthRate}%\n\n${topMatch.gaps?.length > 0 ? `You'll need to close ${topMatch.gaps.length} skill gaps first.` : "You're already well-prepared for this role!"}`;
    }
    return "Complete your assessment to get personalized career recommendations!";
  }

  if (lowerMessage.includes('learn') || lowerMessage.includes('resource')) {
    return `Here's my recommended learning approach:\n\n1. **Start with fundamentals** - Build a solid foundation before advanced topics\n2. **Project-based learning** - Apply skills immediately through real projects\n3. **Spaced repetition** - Review concepts regularly for long-term retention\n4. **Community engagement** - Join developer communities for support and networking\n\nFor your specific gaps, I recommend:\nΓÇó Udemy and Coursera for structured courses\nΓÇó FreeCodeCamp for hands-on practice\nΓÇó YouTube tutorials for quick concept reviews\nΓÇó GitHub for real-world project exposure`;
  }

  return `I'm your AI Career Assistant, here to help you navigate your professional development!\n\nI can help you with:\nΓÇó **Skill prioritization** - Which skills to develop first\nΓÇó **Gap analysis** - Understanding your improvement areas\nΓÇó **Career guidance** - Matching you with suitable roles\nΓÇó **Learning strategies** - Effective ways to build new skills\n\nWhat would you like to explore?`;
}

