interface SkillGap {
  skillId: string;
  skill: { id: string; name: string; description: string; categoryId: string; demandLevel: number };
  currentLevel: 'beginner' | 'intermediate' | 'advanced' | 'expert';
  requiredLevel: 'beginner' | 'intermediate' | 'advanced' | 'expert';
  currentScore: number;
  requiredScore: number;
  gapScore: number;
  severity: 'low' | 'medium' | 'high' | 'none';
  priority: number;
}

export default function GapAnalysis() {
  const { allGaps, careerMatches, isLoadingCareers } = useApp();
  const [detailedGaps, setDetailedGaps] = useState<SkillGap[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedDomain, setSelectedDomain] = useState<string>('all');

  // Fetch detailed gap analysis from API, but also use AppContext data
  useEffect(() => {
    const fetchGapAnalysis = async () => {
      try {
        setLoading(true);
        setError(null);

        // Fetch detailed skills analysis to get current/required scores
        let skillsResponse;
        try {
          skillsResponse = await skillsApi.analyzeSkills();
        } catch (apiErr) {
          console.error('API call failed:', apiErr);
          skillsResponse = null;
        }

        // Safely extract data from response
        let skillsAnalysis: any = { gaps: [] };
        if (skillsResponse && typeof skillsResponse === 'object') {
          // Handle both {data: {gaps: []}} and {gaps: []} formats
          if (skillsResponse.data && typeof skillsResponse.data === 'object') {
            skillsAnalysis = skillsResponse.data;
          } else if (Array.isArray(skillsResponse.gaps)) {
            skillsAnalysis = skillsResponse;
          }
        }

        // Ensure gaps is an array
        const gapsArray = Array.isArray(skillsAnalysis?.gaps) ? skillsAnalysis.gaps : [];

        // Map ALL skills from the response (including those with no gap)
        const mappedGaps = Array.isArray(gapsArray) ? gapsArray.map((gap: any) => ({
          skillId: gap?.skillId || '',
          skill: { 
            id: gap?.skill?.id || gap?.skillId || '', 
            name: gap?.skill?.name || 'Unknown Skill', 
            description: gap?.skill?.description || '', 
            categoryId: gap?.skill?.categoryId || '', 
            demandLevel: gap?.skill?.demandLevel || 0 
          },
          currentLevel: gap?.currentLevel || 'beginner',
          requiredLevel: gap?.requiredLevel || 'intermediate',
          currentScore: gap?.currentScore || 0,
          requiredScore: gap?.requiredScore || 0,
          gapScore: gap?.gapScore || 0,
          severity: (gap?.severity as 'low' | 'medium' | 'high' | 'none') || 'none',
          priority: gap?.priority || 0,
        })) : [];

        setDetailedGaps(mappedGaps);

      } catch (err) {
        console.error('Error fetching gap analysis:', err);
        setError('Failed to load gap analysis. Please try again.');
        setDetailedGaps([]);
      } finally {
        setLoading(false);
      }
    };

    fetchGapAnalysis();
  }, []);

  // Combine AppContext gaps with detailed gaps for display
  // Use detailedGaps as primary since it has full skill objects from API
  // Enhance with AppContext severity/priority if available
  const safeAllGaps = Array.isArray(allGaps) ? allGaps : [];
  const safeDetailedGaps = Array.isArray(detailedGaps) ? detailedGaps : [];

  const combinedGaps = safeDetailedGaps.length > 0 
    ? safeDetailedGaps.map((detailed: any) => {
        // Find matching AppContext gap for severity/priority
        const appGap = safeAllGaps.find((g: any) => {
          const gSkillName = typeof g?.skill === 'object' ? g?.skill?.name : g?.skill;
          return gSkillName === detailed?.skill?.name || g?.skillId === detailed?.skillId;
        });
        return {
          ...detailed,
          severity: appGap?.severity || detailed?.severity || 'none',
          priority: appGap?.priority || detailed?.priority || 5,
        };
      })
    : safeAllGaps.map((appGap: any) => ({
        // Fallback: convert AppContext gaps to full format
        skillId: appGap?.skillId || appGap?.skill || '',
        skill: { 
          id: appGap?.skillId || appGap?.skill || '', 
          name: typeof appGap?.skill === 'object' ? appGap?.skill?.name : appGap?.skill, 
          description: '', 
          categoryId: '', 
          demandLevel: 0 
        },
        currentLevel: 'beginner',
        requiredLevel: 'intermediate',
        currentScore: 0,
        requiredScore: 0,
        gapScore: 0,
        severity: appGap?.severity || 'none',
        priority: appGap?.priority || 5,
      }));

  // Get unique skills - ALL of them, including complete ones
  const uniqueSkills = Array.isArray(combinedGaps) 
    ? combinedGaps
        .filter(gap => gap && gap.skillId) // Only include valid skills
        .filter((gap, index, self) =>
          index === self.findIndex(g => g.skillId === gap.skillId)
        )
        .sort((a, b) => {
          // Sort by priority first (gaps first), then by gap score
          if (a.severity === 'none' && b.severity !== 'none') return 1;
          if (a.severity !== 'none' && b.severity === 'none') return -1;
          return (b?.gapScore || 0) - (a?.gapScore || 0);
        })
    : [];

  // Get only gaps for stats (skills with actual gaps)
  const uniqueGaps = uniqueSkills.filter(g => (g?.gapScore || 0) > 0);

  // Stats
  const highGaps = uniqueGaps.filter(g => g?.severity === 'high').length;
  const mediumGaps = uniqueGaps.filter(g => g?.severity === 'medium').length;
  const lowGaps = uniqueGaps.filter(g => g?.severity === 'low').length;

  // Get user's assessed domain from career matches
  const userDomain = careerMatches?.[0]?.domain_name || 'General';
  const userDomainId = careerMatches?.[0]?.domain_id || 'all';

  // All career matches are now from the user's assessed domain only
  const domainCareers = careerMatches?.slice(0, 5) || [];

  // Get unique domains from actual gap data (dynamic, not mock data)
  const availableDomains = Array.from(new Set(uniqueSkills.map(skill => skill?.skill?.categoryId).filter(Boolean)));

  // Filter skills by selected domain (default to user's assessed domain)
  const effectiveDomain = selectedDomain === 'all' ? userDomainId : selectedDomain;

  const filteredSkills = effectiveDomain === 'all' 
    ? uniqueSkills 
    : uniqueSkills.filter(skill => {
        // Handle both string and number comparison
        const skillDomain = String(skill?.skill?.categoryId || '');
        const selectedDomainStr = String(effectiveDomain);
        return skillDomain === selectedDomainStr;
      });

  // Chart data - use ALL filtered skills (including complete ones)
  const chartData = Array.isArray(filteredSkills) 
    ? filteredSkills.slice(0, 8).map(skill => ({
        name: skill?.skill?.name?.length > 10 ? skill.skill.name.slice(0, 10) + '...' : (skill?.skill?.name || 'Unknown'),
        current: skill?.currentScore || 0,
        required: skill?.requiredScore || 0,
        gap: skill?.gapScore || 0,
        severity: skill?.severity || 'none',
        categoryId: skill?.skill?.categoryId || '',
        isComplete: skill?.severity === 'none' || (skill?.gapScore || 0) <= 0
      }))
    : [];

  if (loading || isLoadingCareers) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="w-8 h-8 animate-spin text-primary" />
          <span className="ml-2 text-muted-foreground">Loading gap analysis...</span>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="text-center py-12">
          <AlertTriangle className="w-12 h-12 mx-auto mb-4 text-destructive" />
          <p className="text-destructive font-medium">{error}</p>
          <Button 
            variant="outline" 
            className="mt-4"
            onClick={() => window.location.reload()}
          >
            Try Again
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold mb-2">Skill Gap Analysis</h1>
        <p className="text-muted-foreground">
          Based on your <span className="text-primary font-medium">{userDomain}</span> assessment ΓÇó 
          Showing gaps for careers in this domain
        </p>
      </div>

      {/* Domain Career Matches */}
      {domainCareers.length > 0 && (
        <Card className="mb-6">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Briefcase className="w-5 h-5" />
              Career Matches for {userDomain}
            </CardTitle>
            <p className="text-sm text-muted-foreground">
              Top career matches based on your {userDomain} skill assessment
            </p>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {domainCareers.map((match: any) => (
                <div
                  key={match.role_id || match.title}
                  className="p-4 rounded-lg border border-primary bg-primary/5"
                >
                  <div className="flex items-center justify-between mb-2">
                    <span className="font-semibold">{match.title}</span>
                    <span className={`text-sm font-medium ${
                      match.match_percentage >= 70 ? 'text-success' :
                      match.match_percentage >= 50 ? 'text-warning' : 'text-destructive'
                    }`}>
                      {match.match_percentage}%
                    </span>
                  </div>
                  <p className="text-sm text-muted-foreground mb-2">
                    {match.level} ΓÇó {match.domain_name || userDomain}
                  </p>
                  <div className="flex items-center gap-2 text-xs text-muted-foreground">
                    <span>{match.matched_count || 0} skills matched</span>
                    <span>ΓÇó</span>
                    <span>{match.missing_count || 0} gaps to fill</span>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        <Card className="bg-gradient-to-br from-primary/10 to-secondary/10">
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground mb-1">Start Learning Path</p>
                <p className="text-2xl font-bold">{uniqueGaps.length}</p>
              </div>
              <div className="w-12 h-12 rounded-full bg-primary/20 flex items-center justify-center">
                <TrendingUp className="w-6 h-6 text-primary" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground mb-1">Critical Gaps</p>
                <p className="text-2xl font-bold text-destructive">{highGaps}</p>
              </div>
              <div className="w-12 h-12 rounded-full bg-destructive/20 flex items-center justify-center">
                <AlertTriangle className="w-6 h-6 text-destructive" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground mb-1">Moderate Gaps</p>
                <p className="text-2xl font-bold text-warning">{mediumGaps}</p>
              </div>
              <div className="w-12 h-12 rounded-full bg-warning/20 flex items-center justify-center">
                <TrendingUp className="w-6 h-6 text-warning" />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Gap Overview Chart */}
        <Card className="lg:col-span-2">
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-2">
                <TrendingUp className="w-5 h-5" />
                Gap Overview
              </CardTitle>

              {/* Domain Filter - Dynamic based on user's assessed domain */}
              <div className="flex items-center gap-2">
                <Filter className="w-4 h-4 text-muted-foreground" />
                <select
                  value={selectedDomain}
                  onChange={(e) => setSelectedDomain(e.target.value)}
                  className="text-sm border rounded-md px-2 py-1 bg-background"
                >
                  <option value="all">All Domains</option>
                  {availableDomains.map(domainId => {
                    const category = skillCategories.find(c => c.id === String(domainId));
                    return (
                      <option key={domainId} value={domainId}>
                        {category?.name || `Domain ${domainId}`}
                      </option>
                    );
                  })}
                </select>
              </div>
            </div>
            <p className="text-sm text-muted-foreground">
              Current vs required skill levels
            </p>
          </CardHeader>
          <CardContent>
            {chartData.length > 0 ? (
              <div className="h-[300px]">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData}>
                    <XAxis 
                      dataKey="name" 
                      tick={{ fontSize: 12 }}
                      interval={0}
                      angle={-45}
                      textAnchor="end"
                      height={80}
                    />
                    <YAxis 
                      tick={{ fontSize: 12 }}
                      domain={[0, 100]}
                      label={{ value: 'Score (%)', angle: -90, position: 'insideLeft' }}
                    />
                    <Tooltip 
                      content={({ active, payload }) => {
                        if (active && payload && payload.length) {
                          const data = payload[0].payload;
                          return (
                            <div className="bg-background border rounded-lg p-3 shadow-lg">
                              <p className="font-semibold mb-1">{data.name}</p>
                              <p className="text-sm text-muted-foreground">Current: {data.current}%</p>
                              <p className="text-sm text-muted-foreground">Required: {data.required}%</p>
                              {data.gap > 0 ? (
                                <p className="text-sm text-destructive">Gap: {data.gap} points</p>
                              ) : (
                                <p className="text-sm text-success">Γ£ô Skill complete!</p>
                              )}
                            </div>
                          );
                        }
                        return null;
                      }}
                    />
                    <Bar dataKey="current" name="Current" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} />
                    <Bar dataKey="required" name="Required" fill="hsl(var(--muted))" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            ) : (
              <div className="h-[300px] flex items-center justify-center text-muted-foreground">
                No skills to display for the selected domain
              </div>
            )}
          </CardContent>
        </Card>

        {/* Gap Summary */}
        <Card>
          <CardHeader>
            <CardTitle>Gap Summary</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <span className="text-sm">High Priority</span>
                <span className="font-semibold text-destructive">{highGaps}</span>
              </div>
              <Progress value={highGaps > 0 ? 100 : 0} className="h-2 bg-destructive/20" />

              <div className="flex items-center justify-between">
                <span className="text-sm">Medium Priority</span>
                <span className="font-semibold text-warning">{mediumGaps}</span>
              </div>
              <Progress value={mediumGaps > 0 ? 66 : 0} className="h-2 bg-warning/20" />

              <div className="flex items-center justify-between">
                <span className="text-sm">Low Priority</span>
                <span className="font-semibold text-success">{lowGaps}</span>
              </div>
              <Progress value={lowGaps > 0 ? 33 : 0} className="h-2 bg-success/20" />

              <div className="flex items-center justify-between pt-4 border-t">
                <span className="font-medium">Complete Skills</span>
                <span className="font-semibold text-success">
                  {uniqueSkills.filter(g => g.severity === 'none').length}
                </span>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Gap Details */}
      <Card className="mt-6">
        <CardHeader>
          <CardTitle>Gap Details</CardTitle>
          <p className="text-sm text-muted-foreground">
            All assessed skills sorted by priority
          </p>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {filteredSkills.map((gap, index) => {
              const category = skillCategories.find(c => c.id === gap.skill.categoryId);
              const isComplete = gap.severity === 'none' || gap.gapScore <= 0;

              return (
                <div 
                  key={`${gap.skillId}-${index}`}
                  className={cn(
                    "p-4 rounded-lg border transition-colors",
                    isComplete ? "bg-success/5 border-success/20" : "bg-card hover:bg-accent/50"
                  )}
                >
                  <div className="flex items-start justify-between mb-3">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <h4 className="font-semibold">{gap.skill.name}</h4>
                        {isComplete ? (
                          <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-success/20 text-success">
                            <CheckCircle2 className="w-3 h-3 mr-1" />
                            Complete
                          </span>
                        ) : (
                          <GapBadge severity={gap.severity as 'low' | 'medium' | 'high'} />
                        )}
                      </div>
                      <p className="text-sm text-muted-foreground">
                        {category?.name} ΓÇó Priority: {gap.priority}/10
                      </p>
                    </div>
                    <div className="text-right">
                      <div className="flex items-center gap-2">
                        <SkillBadge level={gap.currentLevel} />
                        {!isComplete && (
                          <>
                            <ArrowRight className="w-4 h-4 text-muted-foreground" />
                            <SkillBadge level={gap.requiredLevel} />
                          </>
                        )}
                      </div>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Current: {gap.currentScore}%</span>
                      <span className="text-muted-foreground">Required: {gap.requiredScore}%</span>
                    </div>
                    <div className="relative h-2 bg-muted rounded-full overflow-hidden">
                      <div 
                        className={cn(
                          "absolute left-0 top-0 h-full rounded-full transition-all",
                          isComplete ? "bg-success" : "bg-primary"
                        )}
                        style={{ width: `${gap.currentScore}%` }}
                      />
                      {!isComplete && (
                        <div 
                          className="absolute top-0 h-full w-0.5 bg-destructive"
                          style={{ left: `${gap.requiredScore}%` }}
                        />
                      )}
                    </div>
                    {isComplete ? (
                      <p className="text-xs text-success">
                        Γ£ô You've met the target for this skill!
                      </p>
                    ) : (
                      <p className="text-xs text-muted-foreground">
                        Need to improve by <span className="font-medium text-foreground">{gap.gapScore} points</span>
                      </p>
                    )}
                  </div>
                </div>
              );
            })}

            {filteredSkills.length === 0 && (
              <div className="text-center py-12 text-muted-foreground">
                <CheckCircle2 className="w-12 h-12 mx-auto mb-4 text-success" />
                <p className="font-medium">No skills found for this domain!</p>
                <p className="text-sm">Try selecting a different domain or take an assessment.</p>
              </div>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useApp } from '@/contexts/AppContext';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { SkillBadge } from '@/components/ui/skill-badge';
import { Checkbox } from '@/components/ui/checkbox';
import { StepAssessmentModal } from '@/components/learning/StepAssessmentModal';
import { CertificateDisplay } from '@/components/learning/CertificateDisplay';
import { 
  GraduationCap, 
  Clock, 
  BookOpen, 
  Video, 
  FileText,
  ExternalLink,
  CheckCircle2,
  Target,
  Briefcase,
  Loader2,
  Lock,
  Unlock,
  PlayCircle,
  AlertCircle,
  Trophy,
  Award,
  DollarSign,
  TrendingUp
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { Link } from 'react-router-dom';
import { learningApi } from '@/api/learning.api.ts';
import { certificateApi } from '@/api/certificate.api';
import type { LearningResource, LearningPath, CareerMatch, LearningPathStep, Certificate } from '@/types';

const resourceIcons: Record<LearningResource['type'], React.ComponentType<{ className?: string }>> = {
  course: GraduationCap,
  tutorial: BookOpen,
  book: FileText,
  video: Video,
  project: Target,
};

// Extended step type with UI state
interface StepWithUIState extends LearningPathStep {
  canComplete?: boolean;
  isLocked?: boolean;
  previousCompleted?: boolean;
  assessmentPassed?: boolean;
}

export default function Learning() {
  const [learningPath, setLearningPath] = useState<LearningPath | null>(null);
  const [selectedCareer, setSelectedCareer] = useState<CareerMatch | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [stepStatuses, setStepStatuses] = useState<Record<number, {
    canComplete: boolean;
    isLocked: boolean;
    previousCompleted: boolean;
    assessmentPassed: boolean;
  }>>({});

  // Certificate modal state
  const [showCertificate, setShowCertificate] = useState(false);
  const [certificate, setCertificate] = useState<Certificate | null>(null);

  // Assessment modal state
  const [assessmentModalOpen, setAssessmentModalOpen] = useState(false);
  const [currentAssessment, setCurrentAssessment] = useState<{
    stepId: number;
    skillName: string;
    targetLevel: string;
    questions: Array<{
      id: number;
      question: string;
      options: string[];
    }>;
  } | null>(null);

  useEffect(() => {
    const fetchLearningPath = async () => {
      try {
        setLoading(true);
        setError(null);

        // Check if there's a selected career from localStorage
        const storedCareer = localStorage.getItem('selectedCareer');
        if (storedCareer) {
          const career = JSON.parse(storedCareer);
          setSelectedCareer(career);

          // Generate learning path for this career
          // Handle both snake_case (API format) and camelCase (TypeScript format)
          const roleId = career.roleId || career.role_id;
          if (!roleId) {
            throw new Error('Invalid career data: missing roleId');
          }
          const pathData = await learningApi.generatePath(roleId);
          setLearningPath(pathData);

          // Fetch step statuses for the new path
          await fetchStepStatuses(pathData);

          // Check if there's already a certificate for this path
          await checkForCertificate(pathData.id);
        } else {
          // Try to get existing learning path
          const existingPath = await learningApi.getPath();
          if (existingPath) {
            setLearningPath(existingPath);
            await fetchStepStatuses(existingPath);
            // Check if there's already a certificate for this path
            await checkForCertificate(existingPath.id);
          }
        }
      } catch (err) {
        console.error('Error fetching learning path:', err);
        setError('Failed to load learning path. Please select a career first.');
      } finally {
        setLoading(false);
      }
    };

    fetchLearningPath();
  }, []);

  const checkForCertificate = async (pathId: number) => {
    try {
      const result = await certificateApi.getCertificateForPath(pathId);
      if (result.exists && result.certificate) {
        setCertificate(result.certificate);
        // Show certificate if path is completed
        if (learningPath?.progress === 100) {
          setShowCertificate(true);
        }
      }
    } catch (error) {
      console.error('Error checking for certificate:', error);
    }
  };

  const fetchStepStatuses = async (path: LearningPath) => {
    if (!path?.steps) return;

    const statuses: Record<number, any> = {};

    for (const step of path.steps) {
      try {
        const status = await learningApi.canCompleteStep(path.id, step.id);
        statuses[step.id] = {
          canComplete: status.can_complete,
          isLocked: !status.previous_step_completed && status.step_order > 1,
          previousCompleted: status.previous_step_completed,
          assessmentPassed: status.assessment_passed,
        };
      } catch (error) {
        console.error(`Error fetching status for step ${step.id}:`, error);
        statuses[step.id] = {
          canComplete: false,
          isLocked: true,
          previousCompleted: false,
          assessmentPassed: false,
        };
      }
    }

    setStepStatuses(statuses);
  };

  const handleOpenAssessment = async (step: LearningPathStep) => {
    if (!learningPath) return;

    try {
      const assessment = await learningApi.getStepAssessment(learningPath.id, step.id);

      // If already passed, just mark complete
      if (assessment.assessment_already_passed) {
        await handleMarkComplete(step.id);
        return;
      }

      setCurrentAssessment({
        stepId: step.id,
        skillName: assessment.skill_name,
        targetLevel: assessment.target_level,
        questions: assessment.questions,
      });
      setAssessmentModalOpen(true);
    } catch (error) {
      console.error('Error loading assessment:', error);
    }
  };

  const handleAssessmentSubmit = async (answers: string[]) => {
    if (!learningPath || !currentAssessment) {
      throw new Error('No active assessment');
    }

    return await learningApi.submitStepAssessment(
      learningPath.id,
      currentAssessment.stepId,
      answers
    );
  };

  const handleAssessmentPass = async () => {
    if (!learningPath || !currentAssessment) return;

    // Refresh step statuses
    await fetchStepStatuses(learningPath);

    // Close modal
    setAssessmentModalOpen(false);
    setCurrentAssessment(null);
  };

  const handleMarkComplete = async (stepId: number) => {
    if (!learningPath) return;

    try {
      const result = await learningApi.markStepComplete(learningPath.id, stepId);

      // Check if certificate was generated
      if (result.certificate) {
        setCertificate(result.certificate);
        setShowCertificate(true);
      }

      // Refresh learning path and statuses
      const updatedPath = await learningApi.getPath();
      if (updatedPath) {
        setLearningPath(updatedPath);
        await fetchStepStatuses(updatedPath);
      }
    } catch (error) {
      console.error('Error marking step complete:', error);
    }
  };

  // Get role from learning path (preferred) or from selected career (fallback)
  const targetRole = learningPath?.targetRole || selectedCareer?.role;
  const targetRoleTitle = targetRole?.title || selectedCareer?.title || 'Unknown Role';

  // Get additional role details from selected career for richer display
  const roleDetails = {
    level: selectedCareer?.level || targetRole?.level || '',
    salary: selectedCareer?.averageSalary,
    growthRate: selectedCareer?.growthRate,
    matchPercentage: selectedCareer?.match_percentage || selectedCareer?.matchScore,
  };

  // Format salary for display
  const formatSalary = (salary: { min: number; max: number }) => {
    if (!salary) return null;
    return `$${(salary.min / 1000).toFixed(0)}k - $${(salary.max / 1000).toFixed(0)}k`;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="w-8 h-8 animate-spin" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="text-center">
          <p className="text-red-500 mb-4">{error}</p>
          <Button onClick={() => window.location.reload()}>Retry</Button>
        </div>
      </div>
    );
  }

  if (!learningPath) {
    return (
      <div className="space-y-6 animate-fade-in">
        <div>
          <h1 className="text-3xl font-bold font-display">Learning Path</h1>
          <p className="text-muted-foreground mt-1">
            Your personalized roadmap to career success
          </p>
        </div>

        <Card className="p-12 text-center">
          <GraduationCap className="w-16 h-16 mx-auto text-muted-foreground mb-4" />
          <h3 className="text-xl font-semibold mb-2">No Learning Path Yet</h3>
          <p className="text-muted-foreground mb-6 max-w-md mx-auto">
            Select a target career from the Career Matches page to generate a personalized learning path.
          </p>
          <Button asChild>
            <Link to="/careers">
              <Briefcase className="w-4 h-4 mr-2" />
              Explore Careers
            </Link>
          </Button>
        </Card>
      </div>
    );
  }

  const steps = learningPath.steps || [];

  // Check if user already qualified (no steps needed)
  if (steps.length === 0 && learningPath.progress === 100) {
    return (
      <div className="space-y-6 animate-fade-in">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold font-display">Learning Path</h1>
            <p className="text-muted-foreground mt-1">
              Your roadmap to becoming a <span className="font-medium text-foreground">{targetRoleTitle}</span>
            </p>
          </div>
          <Card className="p-4 min-w-[200px] bg-success/10 border-success/30">
            <div className="text-center">
              <CheckCircle2 className="w-8 h-8 mx-auto text-success mb-2" />
              <p className="font-semibold text-success">Already Qualified!</p>
              <p className="text-xs text-muted-foreground mt-1">100% Complete</p>
            </div>
          </Card>
        </div>

        <Card className="p-12 text-center border-success/50 bg-success/5">
          <Award className="w-16 h-16 mx-auto text-success mb-4" />
          <h3 className="text-2xl font-semibold mb-2">≡ƒÄë Congratulations!</h3>
          <p className="text-muted-foreground mb-6 max-w-md mx-auto">
            You already have all the required skills for the <strong>{targetRoleTitle}</strong> role! 
            No learning path is needed - you're ready to apply for this position.
          </p>
          <div className="flex gap-3 justify-center">
            <Button asChild variant="outline">
              <Link to="/careers">
                <Briefcase className="w-4 h-4 mr-2" />
                Explore Other Careers
              </Link>
            </Button>
            <Button asChild>
              <Link to="/assistant">
                <GraduationCap className="w-4 h-4 mr-2" />
                Get Career Advice
              </Link>
            </Button>
          </div>
        </Card>
      </div>
    );
  }
  const completedSteps = steps.filter(s => s.isCompleted).length;

  // Debug info
  console.log('Learning Path:', learningPath);
  console.log('Steps:', steps);
  console.log('Step Statuses:', stepStatuses);

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Debug Info */}
      {process.env.NODE_ENV === 'development' && (
        <div className="p-3 bg-muted/50 rounded-lg text-xs font-mono">
          <p>Debug: steps={steps.length}, completed={completedSteps}, pathId={learningPath.id}, certificate={!!certificate}</p>
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
        <div className="space-y-2">
          <div className="flex items-center gap-3">
            <h1 className="text-3xl font-bold font-display">Learning Path</h1>
            {roleDetails.matchPercentage && (
              <span className="px-2 py-1 bg-primary/10 text-primary text-sm font-medium rounded-full">
                {Math.round(roleDetails.matchPercentage)}% Match
              </span>
            )}
          </div>
          <p className="text-muted-foreground">
            Your roadmap to becoming a <span className="font-semibold text-foreground">{targetRoleTitle}</span>
            {roleDetails.level && <span className="text-muted-foreground"> ({roleDetails.level} Level)</span>}
          </p>
          {/* Additional role details row */}
          <div className="flex flex-wrap items-center gap-4 text-sm">
            {roleDetails.salary && (
              <span className="flex items-center gap-1 text-green-600">
                <DollarSign className="w-4 h-4" />
                {formatSalary(roleDetails.salary)}
              </span>
            )}
            {roleDetails.growthRate && (
              <span className="flex items-center gap-1 text-blue-600">
                <TrendingUp className="w-4 h-4" />
                +{roleDetails.growthRate}% Growth
              </span>
            )}
          </div>
        </div>
        <Card className="p-4 min-w-[200px]">
          <div className="flex items-center gap-3">
            <div className="relative">
              <Progress value={learningPath.progress} className="h-2 w-24" />
            </div>
            <span className="font-semibold">{learningPath.progress}%</span>
          </div>
          <p className="text-xs text-muted-foreground mt-1">
            {completedSteps} of {steps.length} steps completed
          </p>
          <p className="text-xs text-muted-foreground">
            Est. time: {learningPath.totalDuration}
          </p>
        </Card>
      </div>

      {/* Learning Path Timeline */}
      <div className="relative">
        {/* Timeline line */}
        <div className="absolute left-6 top-0 bottom-0 w-0.5 bg-border" />

        <div className="space-y-6">
          {steps.length === 0 ? (
            <Card key="no-steps" className="p-8 text-center">
              <AlertCircle className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
              <h3 className="text-lg font-semibold mb-2">No Learning Steps Found</h3>
              <p className="text-muted-foreground mb-4">
                This learning path doesn't have any steps yet. Please go back and select a career again.
              </p>
              <Button asChild>
                <Link to="/careers">
                  <Briefcase className="w-4 h-4 mr-2" />
                  Select Career
                </Link>
              </Button>
            </Card>
          ) : steps.map((step, index) => {
            const status = stepStatuses[step.id] || {
              canComplete: false,
              isLocked: index > 0,
              previousCompleted: false,
              assessmentPassed: false,
            };

            const isFirstStep = index === 0;
            const isLocked = !isFirstStep && !status.previousCompleted;
            const canMarkComplete = status.canComplete;
            const showAssessmentButton = !isLocked && !step.isCompleted && !status.assessmentPassed;

            return (
              <div key={step.id} className="relative pl-14">
                {/* Timeline node */}
                <div 
                  className={cn(
                    "absolute left-4 -translate-x-1/2 w-5 h-5 rounded-full border-2 transition-colors flex items-center justify-center",
                    step.isCompleted 
                      ? "bg-success border-success" 
                      : isLocked
                        ? "bg-muted border-muted-foreground"
                        : "bg-background border-primary"
                  )}
                >
                  {step.isCompleted ? (
                    <CheckCircle2 className="w-full h-full text-success-foreground p-0.5" />
                  ) : isLocked ? (
                    <Lock className="w-3 h-3 text-muted-foreground" />
                  ) : (
                    <Unlock className="w-3 h-3 text-primary" />
                  )}
                </div>

                <Card className={cn(
                  "transition-all",
                  step.isCompleted && "opacity-75",
                  isLocked && "opacity-50"
                )}>
                  <CardHeader className="pb-2">
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <span className="text-xs font-medium text-muted-foreground">
                            Step {index + 1} of {steps.length}
                          </span>
                          <SkillBadge level={step.targetLevel || step.target_level || 'beginner'} />
                          {isLocked && (
                            <span className="text-xs flex items-center gap-1 text-muted-foreground">
                              <Lock className="w-3 h-3" /> Locked
                            </span>
                          )}
                        </div>
                        <CardTitle className={cn(
                          "text-lg font-display",
                          isLocked && "text-muted-foreground"
                        )}>
                          {step.skill?.name || step.skill_name || `Skill ${index + 1}`}
                        </CardTitle>
                      </div>

                      <div className="flex items-center gap-2 flex-wrap">
                        {step.isCompleted ? (
                          <CheckCircle2 className="w-5 h-5 text-success" />
                        ) : isLocked ? (
                          <div className="w-5 h-5 rounded border border-muted-foreground/30 flex items-center justify-center">
                            <Lock className="w-3 h-3 text-muted-foreground" />
                          </div>
                        ) : step.isCompleted ? (
                          // Step marked as done - show Take Assessment button
                          <Button
                            size="sm"
                            onClick={() => handleOpenAssessment(step)}
                            className="gap-1"
                          >
                            <GraduationCap className="w-4 h-4" />
                            Take Assessment
                          </Button>
                        ) : (
                          // Step not started - show Start Learning button
                          <Button
                            size="sm"
                            onClick={async () => {
                              // Open external learning resources if available
                              const resources = step.resources || [];
                              if (resources.length > 0 && resources[0].url) {
                                window.open(resources[0].url, '_blank');
                              }
                              // Mark step as started/in progress (same as mark complete for now)
                              try {
                                await handleMarkComplete(step.id);
                              } catch (error) {
                                console.error('Error starting step:', error);
                              }
                            }}
                            className="gap-1"
                          >
                            <PlayCircle className="w-4 h-4" />
                            Start Learning
                          </Button>
                        )}
                      </div>
                    </div>
                  </CardHeader>

                  <CardContent className="space-y-4">
                    <div className="flex items-center gap-4 text-sm text-muted-foreground">
                      <span className="flex items-center gap-1">
                        <Clock className="w-4 h-4" />
                        {step.estimatedDuration || step.estimated_duration || '1 week'}
                      </span>
                      <span className="flex items-center gap-1">
                        <Target className="w-4 h-4" />
                        Target: {step.targetLevel || step.target_level || 'beginner'}
                      </span>
                    </div>

                    {/* Status message */}
                    {isLocked && (
                      <div className="flex items-center gap-2 text-sm text-muted-foreground bg-muted/50 p-2 rounded">
                        <AlertCircle className="w-4 h-4" />
                        Complete Step {index} to unlock this module
                      </div>
                    )}

                    {/* Show locked assessment message when not completed */}
                    {!step.isCompleted && !isLocked && (
                      <div className="flex items-center gap-2 text-sm text-muted-foreground bg-muted/30 p-3 rounded-lg">
                        <Lock className="w-4 h-4" />
                        Complete the learning module to unlock the assessment
                      </div>
                    )}

                    {/* Show assessment button when step is completed */}
                    {step.isCompleted && !status.assessmentPassed && !canMarkComplete && (
                      <Button
                        size="sm"
                        onClick={() => handleOpenAssessment(step)}
                        className="gap-1 mt-2"
                      >
                        <GraduationCap className="w-4 h-4" />
                        Take Assessment
                      </Button>
                    )}

                    {/* Show assessment passed status */}
                    {status.assessmentPassed && (
                      <div className="flex items-center gap-2 text-sm text-success bg-success/10 p-2 rounded">
                        <CheckCircle2 className="w-4 h-4" />
                        Assessment Passed!
                      </div>
                    )}

                    {/* Show resources even when no URL - for viewing */}
                    {(step.resources || []).length > 0 && !isLocked && (
                      <div>
                        <h5 className="text-sm font-medium mb-2">Recommended Resources</h5>
                        <div className="space-y-2">
                          {(step.resources || []).map(resource => {
                            const ResourceIcon = resourceIcons[resource.type];
                            const hasUrl = resource.url && resource.url.trim() !== '';
                            return (
                              <div 
                                key={resource.id}
                                className={cn(
                                  "flex items-center justify-between p-3 rounded-lg transition-colors",
                                  hasUrl 
                                    ? "bg-muted/50 hover:bg-muted cursor-pointer" 
                                    : "bg-muted/30"
                                )}
                                onClick={() => {
                                  if (hasUrl) {
                                    window.open(resource.url, '_blank');
                                  }
                                }}
                              >
                                <div className="flex items-center gap-3">
                                  <div className="w-8 h-8 rounded bg-primary/10 flex items-center justify-center">
                                    <ResourceIcon className="w-4 h-4 text-primary" />
                                  </div>
                                  <div>
                                    <p className="font-medium text-sm">{resource.title}</p>
                                    <p className="text-xs text-muted-foreground">
                                      {resource.provider} ΓÇó {resource.duration} ΓÇó 
                                      <span className={cn(
                                        "ml-1",
                                        resource.cost === 'free' ? "text-success" : "text-muted-foreground"
                                      )}>
                                        {resource.cost === 'free' ? 'Free' : 'Paid'}
                                      </span>
                                    </p>
                                  </div>
                                </div>
                                {hasUrl ? (
                                  <Button variant="ghost" size="icon">
                                    <ExternalLink className="w-4 h-4" />
                                  </Button>
                                ) : (
                                  <span className="text-xs text-muted-foreground">View Only</span>
                                )}
                              </div>
                            );
                          })}
                        </div>
                      </div>
                    )}
                  </CardContent>
                </Card>
              </div>
            );
          })}
        </div>

        {/* Completion */}
        <div className="relative pl-14 mt-6">
          <div className={cn(
            "absolute left-4 -translate-x-1/2 w-8 h-8 rounded-full flex items-center justify-center",
            learningPath.progress === 100 
              ? "bg-success text-success-foreground" 
              : "bg-muted text-muted-foreground"
          )}>
            <Briefcase className="w-4 h-4" />
          </div>
          <Card className={cn(
            "p-6",
            learningPath.progress === 100 && "border-success/50 bg-success/5"
          )}>
            <div className="text-center">
              <h3 className="text-lg font-semibold font-display mb-2">
                {learningPath.progress === 100 ? "≡ƒÄë Congratulations!" : "Goal: " + targetRoleTitle}
              </h3>
              <p className="text-sm text-muted-foreground">
                {learningPath.progress === 100 
                  ? "You've completed your learning path and are ready for this role!"
                  : "Complete all steps and assessments to qualify for this position"
                }
              </p>
              {learningPath.progress === 100 && (
                <Button 
                  onClick={async () => {
                    // Check if certificate exists, if not generate one
                    if (!certificate) {
                      try {
                        const result = await certificateApi.generateCertificate(learningPath.id);
                        if (result.certificate) {
                          setCertificate(result.certificate);
                          setShowCertificate(true);
                        }
                      } catch (error) {
                        console.error('Error generating certificate:', error);
                      }
                    } else {
                      setShowCertificate(true);
                    }
                  }}
                  className="mt-4 bg-yellow-500 hover:bg-yellow-600 text-white gap-2"
                >
                  <Award className="w-4 h-4" />
                  View Certificate
                </Button>
              )}
            </div>
          </Card>
        </div>
      </div>

      {/* Assessment Modal */}
      {currentAssessment && (
        <StepAssessmentModal
          isOpen={assessmentModalOpen}
          onClose={() => {
            setAssessmentModalOpen(false);
            setCurrentAssessment(null);
          }}
          skillName={currentAssessment.skillName}
          targetLevel={currentAssessment.targetLevel}
          questions={currentAssessment.questions}
          onSubmit={handleAssessmentSubmit}
          onPass={handleAssessmentPass}
        />
      )}

      {/* Certificate Modal */}
      {showCertificate && certificate && (
        <CertificateDisplay 
          certificate={certificate} 
          onClose={() => setShowCertificate(false)} 
        />
      )}
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Progress } from '@/components/ui/progress';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/auth/AuthContext';
import { authApi, AuthResponse } from '@/api/auth.api';
import { LogIn, UserPlus, Check, X, Mail, Shield, Clock, Eye, EyeOff } from 'lucide-react';
import axiosClient from '@/api/axiosClient';



type AuthMode = 'login' | 'register' | 'verify' | 'forgotPassword' | 'resetPassword';

export default function Login() {
  const [mode, setMode] = useState<AuthMode>('login');
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [resendTimer, setResendTimer] = useState(0);
  const [resetToken, setResetToken] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmNewPassword, setConfirmNewPassword] = useState('');
  const [emailFocused, setEmailFocused] = useState(false);
  const [nameFocused, setNameFocused] = useState(false);
  const [passwordFocused, setPasswordFocused] = useState(false);
  const [confirmPasswordFocused, setConfirmPasswordFocused] = useState(false);
  const [newPasswordFocused, setNewPasswordFocused] = useState(false);
  const [confirmNewPasswordFocused, setConfirmNewPasswordFocused] = useState(false);
  const [pendingAuth, setPendingAuth] = useState<AuthResponse | null>(null);
  const otpRefs = useRef<(HTMLInputElement | null)[]>([]);
  const { toast } = useToast();
  const navigate = useNavigate();
  const { login: authLogin } = useAuth();


  // Password strength validation
  const validatePassword = (password: string) => {
    const hasLower = /[a-z]/.test(password);
    const hasUpper = /[A-Z]/.test(password);
    const hasNumber = /\d/.test(password);
    const hasSpecial = /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password);
    const isLongEnough = password.length >= 8;

    const score = [hasLower, hasUpper, hasNumber, hasSpecial, isLongEnough].filter(Boolean).length;
    let strength = 'Weak';
    let color = 'bg-red-500';

    if (score >= 4) {
      strength = 'Strong';
      color = 'bg-green-500';
    } else if (score >= 3) {
      strength = 'Moderate';
      color = 'bg-yellow-500';
    }

    return {
      hasLower,
      hasUpper,
      hasNumber,
      hasSpecial,
      isLongEnough,
      isValid: hasLower && hasUpper && hasNumber && hasSpecial && isLongEnough,
      score: (score / 5) * 100,
      strength,
      color
    };
  };

  const passwordValidation = validatePassword(password);

  // Resend timer effect
  useEffect(() => {
    if (resendTimer > 0) {
      const timer = setTimeout(() => setResendTimer(resendTimer - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [resendTimer]);

  // Resend starts countdown
  useEffect(() => {
    if (resendTimer > 0) {
      const timer = setTimeout(() => setResendTimer(resendTimer - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [resendTimer]);

  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) return;

    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);

    // Auto-focus next input
    if (value && index < 5) {
      otpRefs.current[index + 1]?.focus();
    }
  };

  const handleOtpKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      otpRefs.current[index - 1]?.focus();
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      if (mode === 'register') {
        // Validate password
        if (!passwordValidation.isValid) {
          setError('Password must meet all strength requirements.');
          setIsLoading(false);
          return;
        }

        // Check password confirmation
        if (password !== confirmPassword) {
          setError('Passwords do not match.');
          setIsLoading(false);
          return;
        }

        try {
          const reg = await authApi.register({ email, name, password });
          // Save pending auth info until email verification completes
          setPendingAuth(reg);
          // Send real OTP via backend
          await authApi.sendOtp({ email, purpose: 'verify' });
          toast({
            title: "Verification Code Sent",
            description: `A 6-digit code has been sent to ${email}.`,
          });
          setMode('verify');
          setResendTimer(30);
        } catch (err) {
          setError('Registration failed. Please try again.');
        }
      } else if (mode === 'login') {
        console.log('Login attempt with email:', email, 'password:', password);
        try {
          // Use AuthContext login to properly update state
          const success = await authLogin(email, password);
          
          if (!success) {
            setError('Login failed. Please check your credentials.');
            setIsLoading(false);
            return;
          }

          toast({
            title: "Login Successful",
            description: `Welcome back!`,
          });

          // Redirect to dashboard after successful login
          setTimeout(() => {
            navigate('/dashboard');
          }, 500);
        } catch (err: any) {

          console.error('Login error:', err);
          if (err.response?.status === 401) {
            setError('Invalid email or password');
          } else {
            setError('Login failed. Please check your connection and try again.');
          }
        }
      } else if (mode === 'verify') {
        const otpCode = otp.join('');
        if (otpCode.length !== 6) {
          setError('Please enter the complete 6-digit code.');
          setIsLoading(false);
          return;
        }

        try {
          await authApi.verifyOtp({ email, code: otpCode, purpose: 'verify' });
          // On success, persist tokens/user from register response
          if (pendingAuth) {
            localStorage.setItem('authToken', pendingAuth.access_token);
            if (pendingAuth.refresh_token) {
              localStorage.setItem('refreshToken', pendingAuth.refresh_token);
            }
            localStorage.setItem('user', JSON.stringify(pendingAuth.user));
          }
          toast({
            title: "Account Verified",
            description: `Welcome to Career Compass, ${name}!`,
          });
          // Let ProtectedRoute handle redirect
        } catch (err) {
          setError('Invalid verification code. Please try again.');
        }
      } else if (mode === 'forgotPassword') {
        try {
          await authApi.sendOtp({ email, purpose: 'reset' });
          toast({
            title: "Reset Code Sent",
            description: `A 6-digit code has been sent to ${email}.`,
          });
          setMode('resetPassword');
          setOtp(['', '', '', '', '', '']);
        } catch (err) {
          setError('Failed to send reset code. Please try again.');
        }
      } else if (mode === 'resetPassword') {
        const otpCode = otp.join('');
        if (otpCode.length !== 6) {
          setError('Please enter the complete 6-digit code.');
          setIsLoading(false);
          return;
        }

        // Validate new password
        const newPasswordValidation = validatePassword(newPassword);
        if (!newPasswordValidation.isValid) {
          setError('New password must meet all strength requirements.');
          setIsLoading(false);
          return;
        }

        // Check password confirmation
        if (newPassword !== confirmNewPassword) {
          setError('New passwords do not match.');
          setIsLoading(false);
          return;
        }

        try {
          // Direct reset endpoint call (backend forgot-password/reset-password)
          const resetData = {
            reset_token: resetToken,
            new_password: newPassword
          };
          await axiosClient.post('/auth/reset-password', resetData);
          toast({
            title: "Password Reset Successful",
            description: "You can now sign in with your new password.",
          });
          setMode('login');
          setPassword('');
          setNewPassword('');
          setConfirmNewPassword('');
          setOtp(['', '', '', '', '', '']);
        } catch (err) {
          setError('Invalid reset code. Please try again.');
        }
      }
    } catch (err) {
      setError('An unexpected error occurred');
    } finally {
      setIsLoading(false);
    }
  };

  const handleResendOtp = async () => {
    try {
      await authApi.sendOtp({ email, purpose: mode === 'verify' ? 'verify' : 'reset' });
      setResendTimer(30);
      setOtp(['', '', '', '', '', '']);
      otpRefs.current[0]?.focus();
      toast({
        title: "New Code Sent",
        description: `A new code has been sent to ${email}.`,
      });
    } catch (err) {
      setError('Failed to resend code. Please try again.');
    }
  };

  const renderLoginForm = () => (
    <>
      <CardHeader className="text-center">
        <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-primary/10 mb-4 mx-auto">
          <LogIn className="w-7 h-7 text-primary" />
        </div>
        <CardTitle className="text-2xl font-bold">Welcome Back</CardTitle>
        <CardDescription>Sign in to your Career Compass account</CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="email">Email</Label>
            <Input
              id="email"
              type="email"
              placeholder="Enter your email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              onFocus={() => setEmailFocused(true)}
              onBlur={() => setEmailFocused(false)}
              className={`transition-all duration-300 ${
                emailFocused ? 'ring-2 ring-primary/50 shadow-lg scale-[1.02]' : 'hover:shadow-md'
              }`}
              required
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="password">Password</Label>
            <div className="relative">
              <Input
                id="password"
                type={showPassword ? "text" : "password"}
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                onFocus={() => setPasswordFocused(true)}
                onBlur={() => setPasswordFocused(false)}
                className={`transition-all duration-300 ${
                  passwordFocused ? 'ring-2 ring-primary/50 shadow-lg scale-[1.02]' : 'hover:shadow-md'
                }`}
                required
              />
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="absolute right-0 top-0 h-full px-3 py-2"
                onClick={() => setShowPassword(!showPassword)}
              >
                {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
              </Button>
            </div>
          </div>

          {error && (
            <Alert variant="destructive">
              <AlertDescription>{error}</AlertDescription>
            </Alert>
          )}

          <Button type="submit" className="w-full" disabled={isLoading}>
            {isLoading ? 'Signing in...' : 'Sign In'}
          </Button>
        </form>

        <div className="mt-6 text-center space-y-2">
          <Button
            variant="link"
            onClick={() => {
              setMode('forgotPassword');
              setError('');
              setEmail('');
            }}
            className="text-sm"
          >
            Forgot Password?
          </Button>
          <br />
          <Button
            variant="link"
            onClick={() => navigate('/register')}
            className="text-sm"
          >
            Don't have an account? Sign up
          </Button>

        </div>
      </CardContent>
    </>
  );

  const renderRegisterForm = () => (
    <>
      <CardHeader className="text-center">
        <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-primary/10 mb-4 mx-auto">
          <UserPlus className="w-7 h-7 text-primary" />
        </div>
        <CardTitle className="text-2xl font-bold">Create Account</CardTitle>
        <CardDescription>Join Career Compass to start your journey</CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="name">Full Name</Label>
            <Input
              id="name"
              type="text"
              placeholder="Enter your full name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="email">Email</Label>
            <Input
              id="email"
              type="email"
              placeholder="Enter your email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="password">Password</Label>
            <div className="relative">
              <Input
                id="password"
                type={showPassword ? "text" : "password"}
                placeholder="Create a strong password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="absolute right-0 top-0 h-full px-3 py-2"
                onClick={() => setShowPassword(!showPassword)}
              >
                {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
              </Button>
            </div>

            {/* Password Strength Indicator */}
            {password && (
              <div className="space-y-2 p-3 bg-slate-50 dark:bg-slate-800/50 rounded-md border border-slate-200 dark:border-slate-700">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Shield className={`h-3.5 w-3.5 ${
                      passwordValidation.strength === 'Strong' ? 'text-green-500' :
                      passwordValidation.strength === 'Moderate' ? 'text-yellow-500' : 'text-red-500'
                    }`} />
                    <span className="text-xs font-medium text-slate-600 dark:text-slate-400">Password Strength</span>
                  </div>
                  <span className={`text-xs font-semibold px-2 py-0.5 rounded ${
                    passwordValidation.strength === 'Strong' ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' :
                    passwordValidation.strength === 'Moderate' ? 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400' :
                    'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
                  }`}>
                    {passwordValidation.strength}
                  </span>
                </div>

                <Progress
                  value={passwordValidation.score}
                  className="h-1.5"
                />

                <div className="flex flex-wrap gap-1 text-xs">
                  <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded ${
                    passwordValidation.isLongEnough ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-slate-100 text-slate-500 dark:bg-slate-700 dark:text-slate-400'
                  }`}>
                    {passwordValidation.isLongEnough ? <Check className="h-2.5 w-2.5" /> : <X className="h-2.5 w-2.5" />}
