            <TabsContent value="privacy" className="">
              <Card>
                <CardHeader>
                  <div className="flex items-center gap-2">
                    <Shield className="w-5 h-5 text-muted-foreground" />
                    <CardTitle>Privacy</CardTitle>
                  </div>
