                    />
                  </div>
                </CardContent>
              </Card>
            </TabsContent>

            <TabsContent value="data" className="">
              <Card>
                <CardHeader>
                  <div className="flex items-center gap-2">
                    <Download className="w-5 h-5 text-muted-foreground" />
                    <CardTitle>Data & Export</CardTitle>
                  </div>
                  <CardDescription>Export your data or manage account deletion</CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="flex gap-3">
                    <Button 
                      variant="outline" 
                      onClick={async () => {
                        try {
                          const result = await authApi.requestPrivacy('export');
                          toast.success(result.message);
                        } catch (error) {
                          toast.error('Failed to request data export');
                        }
                      }}
                    >
                      <Download className="w-4 h-4 mr-2" />
                      Export Data
                    </Button>
                    <Button 
                      variant="destructive" 
                      onClick={async () => {
                        if (confirm('Are you sure you want to request account deletion? This cannot be undone.')) {
                          try {
                            const result = await authApi.requestPrivacy('delete');
                            toast.success(result.message);
                          } catch (error) {
                            toast.error('Failed to request account deletion');
                          }
                        }
                      }}
                    >
                      <Trash2 className="w-4 h-4 mr-2" />
                      Delete Account
                    </Button>
                  </div>
                </CardContent>
              </Card>
            </TabsContent>
          </div>
        </Tabs>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useLocation, useParams } from 'react-router-dom';

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { ChevronLeft, CheckCircle2, Loader2, Timer, Maximize, AlertTriangle } from 'lucide-react';
import { cn } from '@/lib/utils';
import { skillsApi } from '@/api/skills.api';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/auth/AuthContext';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";



interface Question {
  id: number;
  question_text: string;
  options: string[];
  correct_answer: string;
  difficulty: string;
}

export default function SkillExam() {
  const navigate = useNavigate();
  const location = useLocation();
  const { skillName: urlSkillNameParam } = useParams<{ skillName: string }>();
  const { toast } = useToast();
  const { user, isLoading: isAuthLoading } = useAuth();

  // Get skill data from URL param, navigation state, URL search params, or localStorage
  const urlParams = new URLSearchParams(window.location.search);
  const urlSkillId = urlParams.get('skillId');
  const urlSkillName = urlParams.get('skillName');
  
  // Try to get from URL param first, then navigation state, then URL search params, then localStorage
  const skillName = urlSkillNameParam || location.state?.skillName || urlSkillName || localStorage.getItem('currentSkillName') || 'Unknown Skill';
  const initialSkillId = location.state?.skillId || (urlSkillId ? parseInt(urlSkillId) : null) || (localStorage.getItem('currentSkillId') ? parseInt(localStorage.getItem('currentSkillId')!) : null);




  const [loading, setLoading] = useState(true);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [answers, setAnswers] = useState<{[key: number]: string}>({});
  const [writtenAnswer, setWrittenAnswer] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [examComplete, setExamComplete] = useState(false);
  const [results, setResults] = useState<any>(null);
  const [skillId, setSkillId] = useState<number | null>(initialSkillId);
  const [timeLeft, setTimeLeft] = useState(600); // 10 minutes in seconds
  const [nextSkill, setNextSkill] = useState<{id: number, name: string} | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showSecurityWarning, setShowSecurityWarning] = useState(false);
  const [securityViolations, setSecurityViolations] = useState(0);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const examContainerRef = useRef<HTMLDivElement>(null);
  const violationTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Security constants
  const MAX_VIOLATIONS = 3;
  const VIOLATION_WARNING_DURATION = 5000; // 5 seconds

  // Reset state when URL parameter changes (for next exam navigation)

  useEffect(() => {
    setSkillId(initialSkillId);
    setExamComplete(false);
    setResults(null);
    setCurrentQuestion(0);
    setAnswers({});
    setWrittenAnswer('');
    setNextSkill(null);
    setLoading(true);
    window.scrollTo(0, 0);
  }, [urlSkillNameParam, initialSkillId]);

  // Store skill info in localStorage when available
  useEffect(() => {
    if (skillId && skillName && skillName !== 'Unknown Skill') {
      localStorage.setItem('currentSkillId', skillId.toString());
      localStorage.setItem('currentSkillName', skillName);
    }
  }, [skillId, skillName]);



  // Format time
  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Enter fullscreen mode
  const enterFullscreen = useCallback(async () => {
    try {
      const element = examContainerRef.current || document.documentElement;
      if (element.requestFullscreen) {
        await element.requestFullscreen();
      } else if ((element as any).webkitRequestFullscreen) {
        await (element as any).webkitRequestFullscreen();
      } else if ((element as any).msRequestFullscreen) {
        await (element as any).msRequestFullscreen();
      }
      setIsFullscreen(true);
    } catch (err) {
      console.error('Failed to enter fullscreen:', err);
      toast({
        title: "Fullscreen Required",
        description: "Please allow fullscreen mode to start the exam.",
        variant: "destructive",
      });
    }
  }, [toast]);

  // Exit fullscreen mode
  const exitFullscreen = useCallback(() => {
    if (document.exitFullscreen) {
      document.exitFullscreen();
    } else if ((document as any).webkitExitFullscreen) {
      (document as any).webkitExitFullscreen();
    } else if ((document as any).msExitFullscreen) {
      (document as any).msExitFullscreen();
    }
    setIsFullscreen(false);
  }, []);

  // Handle security violation
  const handleSecurityViolation = useCallback((reason: string) => {
    if (examComplete) return; // Don't count violations after exam is complete
    
    const newViolations = securityViolations + 1;
    setSecurityViolations(newViolations);
    setShowSecurityWarning(true);
    
    // Clear any existing timeout
    if (violationTimeoutRef.current) {
      clearTimeout(violationTimeoutRef.current);
    }
    
    // Auto-hide warning after duration
    violationTimeoutRef.current = setTimeout(() => {
      setShowSecurityWarning(false);
    }, VIOLATION_WARNING_DURATION);
    
    toast({
      title: "Security Warning!",
      description: `Violation ${newViolations}/${MAX_VIOLATIONS}: ${reason}. ${newViolations >= MAX_VIOLATIONS ? 'Exam will be auto-submitted!' : 'Please follow exam rules.'}`,
      variant: "destructive",
    });
    
    // Auto-submit if max violations reached
    if (newViolations >= MAX_VIOLATIONS) {
      toast({
        title: "Maximum Violations Reached",
        description: "Auto-submitting exam due to security violations...",
        variant: "destructive",
      });
      setTimeout(() => {
        submitExam();
      }, 2000);
    }
  }, [securityViolations, examComplete, toast]);

  // Prevent keyboard shortcuts
  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (examComplete) return;
    
    // Prevent Tab switching
    if (e.key === 'Tab') {
      e.preventDefault();
      handleSecurityViolation('Tab key is disabled during exam');
      return;
    }
    
    // Prevent Alt+Tab (Alt key)
    if (e.altKey) {
      e.preventDefault();
      handleSecurityViolation('Alt key combinations are disabled');
      return;
    }
    
    // Prevent Ctrl/Cmd combinations (copy, paste, print, etc.)
    if (e.ctrlKey || e.metaKey) {
      const blockedKeys = ['c', 'v', 'x', 'p', 'a', 'f', 's', 't', 'w', 'n', 'r'];
      if (blockedKeys.includes(e.key.toLowerCase())) {
        e.preventDefault();
        handleSecurityViolation(`Ctrl+${e.key.toUpperCase()} is disabled during exam`);
        return;
      }
    }
    
    // Prevent F-keys (F1-F12)
    if (e.key.startsWith('F') && e.key.length > 1) {
      e.preventDefault();
      handleSecurityViolation('Function keys are disabled during exam');
      return;
    }
    
    // Prevent Escape key (could exit fullscreen)
    if (e.key === 'Escape') {
      e.preventDefault();
      handleSecurityViolation('Escape key is disabled during exam');
      return;
    }
  }, [examComplete, handleSecurityViolation]);

  // Prevent context menu (right-click)
  const handleContextMenu = useCallback((e: MouseEvent) => {
    e.preventDefault();
    handleSecurityViolation('Right-click is disabled during exam');
  }, [handleSecurityViolation]);

  // Prevent copy/paste/cut via events
  const handleCopyPaste = useCallback((e: ClipboardEvent) => {
    e.preventDefault();
    handleSecurityViolation('Copy/Paste is disabled during exam');
  }, [handleSecurityViolation]);

  // Handle visibility change (tab switching, minimizing)
  const handleVisibilityChange = useCallback(() => {
    if (document.hidden && !examComplete) {
      handleSecurityViolation('Window switching is not allowed during exam');
    }
  }, [examComplete, handleSecurityViolation]);

  // Handle window blur (losing focus)
  const handleWindowBlur = useCallback(() => {
    if (!examComplete) {
      handleSecurityViolation('Window focus loss detected');
    }
  }, [examComplete, handleSecurityViolation]);

  // Handle fullscreen change
  const handleFullscreenChange = useCallback(() => {
    const isCurrentlyFullscreen = !!document.fullscreenElement;
    setIsFullscreen(isCurrentlyFullscreen);
    
    if (!isCurrentlyFullscreen && !examComplete && !showExitConfirm) {
      handleSecurityViolation('Fullscreen mode is required during exam');
      // Try to re-enter fullscreen
      setTimeout(() => {
        enterFullscreen();
      }, 100);
    }
  }, [examComplete, showExitConfirm, handleSecurityViolation, enterFullscreen]);

  // Setup security measures
  useEffect(() => {
    if (loading || isAuthLoading || examComplete) return;
    
    // Enter fullscreen when exam loads
    enterFullscreen();
    
    // Add event listeners
    document.addEventListener('keydown', handleKeyDown);
    document.addEventListener('contextmenu', handleContextMenu);
    document.addEventListener('copy', handleCopyPaste);
    document.addEventListener('cut', handleCopyPaste);
    document.addEventListener('paste', handleCopyPaste);
    document.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('blur', handleWindowBlur);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    document.addEventListener('webkitfullscreenchange', handleFullscreenChange);
    document.addEventListener('msfullscreenchange', handleFullscreenChange);
    
    // Prevent drag and drop
    const preventDragDrop = (e: DragEvent) => {
      e.preventDefault();
    };
    document.addEventListener('dragstart', preventDragDrop);
    document.addEventListener('drop', preventDragDrop);
    
    // Cleanup
    return () => {
      document.removeEventListener('keydown', handleKeyDown);
      document.removeEventListener('contextmenu', handleContextMenu);
      document.removeEventListener('copy', handleCopyPaste);
      document.removeEventListener('cut', handleCopyPaste);
      document.removeEventListener('paste', handleCopyPaste);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('blur', handleWindowBlur);
      document.removeEventListener('fullscreenchange', handleFullscreenChange);
      document.removeEventListener('webkitfullscreenchange', handleFullscreenChange);
      document.removeEventListener('msfullscreenchange', handleFullscreenChange);
      document.removeEventListener('dragstart', preventDragDrop);
      document.removeEventListener('drop', preventDragDrop);
      
      if (violationTimeoutRef.current) {
        clearTimeout(violationTimeoutRef.current);
      }
    };
  }, [loading, isAuthLoading, examComplete, enterFullscreen, handleKeyDown, handleContextMenu, handleCopyPaste, handleVisibilityChange, handleWindowBlur, handleFullscreenChange]);

  // Handle beforeunload (page refresh/close)
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      if (!examComplete) {
        e.preventDefault();
        e.returnValue = 'You are in the middle of an exam. Are you sure you want to leave?';
        return e.returnValue;
      }
    };
    
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [examComplete]);


  useEffect(() => {
    const loadExam = async () => {
      try {
        // Wait for auth to finish loading before loading exam
        if (isAuthLoading) {
          return;
        }

        // Use skillId from state, URL params, or localStorage

        let currentSkillId = initialSkillId;

        if (!currentSkillId) {
          toast({
            title: "Skill not found",
            description: "No skill ID provided. Please select a skill from the skill selection page.",
            variant: "destructive",
          });
          navigate('/skill_selection');
          return;
        }

        setSkillId(currentSkillId);

        // DEBUG: Log the values being used
        console.log('DEBUG: Loading exam with skillId:', currentSkillId);
        console.log('DEBUG: skillName:', skillName);
        console.log('DEBUG: Auth token exists:', !!localStorage.getItem('authToken'));
        console.log('DEBUG: User:', user);

        // Load quiz from new API
        const response = await fetch(`http://localhost:5000/api/assessment/start/${currentSkillId}`, {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('authToken')}`

          }
        });

        if (!response.ok) {
          const errorText = await response.text();
          console.error(`API Error ${response.status}:`, errorText);
          throw new Error(`Failed to load quiz: ${response.status} - ${errorText}`);
        }


        const data = await response.json();

        setQuestions(data.questions);
        setTimeLeft(data.time_limit);
      } catch (error) {
        console.error('Error loading exam:', error);
        toast({
          title: "Error",
          description: "Failed to load exam questions. Please try again.",
          variant: "destructive",
        });
      } finally {
        setLoading(false);
      }
    };

    loadExam();
  }, [skillName, user, isAuthLoading, navigate, toast, initialSkillId]);

  const handleAnswer = (questionId: number, answer: string) => {
    setAnswers(prev => ({
      ...prev,
      [questionId]: answer
    }));
  };

  const handleNext = () => {
    if (currentQuestion < questions.length - 1) {
      setCurrentQuestion(prev => prev + 1);
    }
  };

  const handlePrevious = () => {
    if (currentQuestion > 0) {
      setCurrentQuestion(prev => prev - 1);
    }
  };

  // Timer countdown
  useEffect(() => {
    if (examComplete || timeLeft <= 0) return;
    
    const timer = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          submitExam();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [examComplete, timeLeft]);

  const submitExam = async () => {
    // Validate skillId before submission
    if (!skillId) {
      toast({
        title: "Error",
        description: "Cannot submit exam: Skill ID is missing. Please restart the exam.",
        variant: "destructive",
      });
      return;
    }

    setIsSubmitting(true);
    try {
      // Submit to backend first if skillId exists
      let backendResult = null;

      try {
        // Format answers as expected by backend: Record<question_id, answer>
        const formattedAnswers: Record<number, string> = {};
        Object.entries(answers).forEach(([questionId, answer]) => {
          formattedAnswers[parseInt(questionId)] = answer;
        });

        const response = await skillsApi.submitQuiz({
          skill_id: skillId,
          answers: formattedAnswers,
          time_taken: 600 - timeLeft
        });

        // Use backend response if available
        if (response.data && response.data.skill_results && response.data.skill_results.length > 0) {
          backendResult = response.data.skill_results[0];
        }
      } catch (e) {
        console.log('Backend submission failed, using local calculation:', e);
      }

      // Calculate score locally as fallback

      let correctCount = 0;
      questions.forEach(q => {
        if (answers[q.id] === q.correct_answer) {
          correctCount++;
        }
      });

      const localScore = (correctCount / questions.length) * 100;

      // Use backend result if available, otherwise use local calculation
      const score = backendResult ? backendResult.percentage : localScore;
      const finalCorrectCount = backendResult ? backendResult.correct_answers : correctCount;
      
      // Determine level based on score
      let level = 'Beginner';
      if (score >= 80) level = 'Expert';
      else if (score >= 60) level = 'Advanced';
      else if (score >= 40) level = 'Intermediate';

      const result = {
        skill_id: skillId, // Include skill_id for reference
        skill_name: skillName,
        score: score,
        level,
        correct_answers: finalCorrectCount,
        total_questions: questions.length,
        written_assessment: writtenAnswer,
        time_taken: 600 - timeLeft
      };

      setResults(result);
      setExamComplete(true);

      // Trigger dashboard refresh
      window.dispatchEvent(new CustomEvent('assessmentCompleted', { 
        detail: { skillId, skillName, score: result.score } 
      }));
      localStorage.setItem('lastAssessmentCompleted', Date.now().toString());

      // Clear localStorage after successful submission
      localStorage.removeItem('currentSkillId');
      localStorage.removeItem('currentSkillName');


      // Get next skill from localStorage (set during skill selection)
      const pendingSkillsJson = localStorage.getItem('pendingSkills');
      if (pendingSkillsJson) {
        const pendingSkills = JSON.parse(pendingSkillsJson);
        // Find current skill index and get next one
        const currentIndex = pendingSkills.findIndex((s: any) => s.id === skillId);
        if (currentIndex !== -1 && currentIndex < pendingSkills.length - 1) {
          const next = pendingSkills[currentIndex + 1];
          setNextSkill({ id: next.id, name: next.name });
        }
      }

      toast({
        title: "Exam Completed!",
        description: `You scored ${score.toFixed(1)}% - ${level} level`,
      });


    } catch (error) {
      console.error('Error submitting exam:', error);
      toast({
        title: "Error",
        description: "Failed to submit exam. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };


  const handleSubmit = () => {
    submitExam();
  };

  const startNextExam = () => {
    if (!nextSkill) return;
    
    // Update localStorage to remove current skill from pending
    const pendingSkillsJson = localStorage.getItem('pendingSkills');
    if (pendingSkillsJson) {
      const pendingSkills = JSON.parse(pendingSkillsJson);
      const updatedSkills = pendingSkills.filter((s: any) => s.id !== skillId);
      localStorage.setItem('pendingSkills', JSON.stringify(updatedSkills));
    }

    // Store next skill info in localStorage before navigation
    localStorage.setItem('currentSkillId', nextSkill.id.toString());
    localStorage.setItem('currentSkillName', nextSkill.name);

    // Navigate to next exam using skill name in URL
    const encodedSkillName = encodeURIComponent(nextSkill.name.toLowerCase().replace(/\s+/g, '-'));
    navigate(`/skill_selection/assessment/${encodedSkillName}`, {
      state: { 
        skillId: nextSkill.id, 
        skillName: nextSkill.name 
      }
    });

  };


  const allAnswered = questions.length > 0 && questions.every(q => answers[q.id]);



  if (loading || isAuthLoading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="w-8 h-8 animate-spin" />
      </div>
    );
  }

  // Security warning overlay
  if (showSecurityWarning && !examComplete) {
    return (
      <div className="fixed inset-0 bg-red-900/90 z-50 flex items-center justify-center">
        <div className="bg-white dark:bg-gray-900 p-8 rounded-lg max-w-md text-center animate-pulse">
          <AlertTriangle className="w-16 h-16 text-red-500 mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-red-600 mb-2">Security Violation!</h2>
          <p className="text-lg mb-4">
            Violation {securityViolations} of {MAX_VIOLATIONS}
          </p>
          <p className="text-sm text-muted-foreground mb-4">
            Please follow exam rules. {securityViolations >= MAX_VIOLATIONS ? 'Exam will be auto-submitted!' : 'Continue the exam in fullscreen mode.'}
          </p>
          <Button 
            onClick={() => {
              setShowSecurityWarning(false);
              enterFullscreen();
            }}
            className="w-full"
          >
            <Maximize className="w-4 h-4 mr-2" />
            Return to Exam
          </Button>
        </div>
      </div>
    );
  }



  if (examComplete && results) {
    return (
      <div className="space-y-6 animate-fade-in max-w-4xl mx-auto">
        <Card>
          <CardHeader className="text-center">
            <div className="mx-auto w-16 h-16 rounded-full bg-green-100 flex items-center justify-center mb-4">
              <CheckCircle2 className="w-8 h-8 text-green-600" />
            </div>
            <CardTitle className="text-2xl">Exam Completed !</CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="text-center">
              <div className="text-5xl font-bold text-primary mb-2">
                {results.score.toFixed(1)}%
              </div>
              <div className="text-lg text-muted-foreground">
                {results.level} Level
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="p-4 bg-muted rounded-lg text-center">
                <div className="text-2xl font-bold">{results.correct_answers}</div>
                <div className="text-sm text-muted-foreground">Correct Answers</div>
              </div>
              <div className="p-4 bg-muted rounded-lg text-center">
                <div className="text-2xl font-bold">{results.total_questions}</div>
                <div className="text-sm text-muted-foreground">Total Questions</div>
              </div>
            </div>

            {results.written_assessment && (
              <div className="p-4 border rounded-lg">
                <h4 className="font-semibold mb-2">Your Written Assessment:</h4>
                <p className="text-sm text-muted-foreground">{results.written_assessment}</p>
              </div>
            )}

            <div className="flex justify-center gap-4 flex-wrap">
              <Button onClick={() => navigate('/skill_selection/assessment')} variant="outline">
                <ChevronLeft className="w-4 h-4 mr-2" />
                Back to Assessments
              </Button>
              {nextSkill && (
                <Button 
                  onClick={() => startNextExam()} 
                  className="bg-blue-600 hover:bg-blue-700"
                >
                  Next: {nextSkill.name}
                  <ChevronLeft className="w-4 h-4 ml-2 rotate-180" />
                </Button>
              )}
              <Button onClick={() => navigate('/dashboard')}>
                Go to Dashboard
              </Button>
            </div>

          </CardContent>
        </Card>
      </div>
    );
  }

  const currentQ = questions[currentQuestion];

  return (
    <div 
      ref={examContainerRef}
      className="space-y-2 animate-fade-in max-w-xl mx-auto min-h-screen bg-background p-4"
    >
      {/* Fullscreen Toggle Button */}
      {!isFullscreen && !examComplete && (
        <div className="fixed top-4 right-4 z-40">
          <Button
            onClick={enterFullscreen}
            variant="outline"
            size="sm"
            className="bg-yellow-100 border-yellow-300 text-yellow-800 hover:bg-yellow-200"
          >
            <Maximize className="w-4 h-4 mr-2" />
            Enter Fullscreen
          </Button>
        </div>
      )}

      {/* Security Status Indicator */}
      <div className="fixed top-4 left-4 z-40 flex items-center gap-2">
        <div className={cn(
          "px-3 py-1 rounded-full text-xs font-medium",
          isFullscreen ? "bg-green-100 text-green-700" : "bg-yellow-100 text-yellow-700"
        )}>
          {isFullscreen ? '≡ƒöÆ Secure Mode' : 'ΓÜá∩╕Å Not Secure'}
        </div>
        {securityViolations > 0 && (
          <div className="px-3 py-1 rounded-full text-xs font-medium bg-red-100 text-red-700">
            Violations: {securityViolations}/{MAX_VIOLATIONS}
          </div>
        )}
      </div>

      {/* Header */}
      <div className="flex items-center justify-between">
        <Button variant="ghost" onClick={() => navigate('/skill_selection')}>
          <ChevronLeft className="w-3 h-3 mr-2" />
          Back
        </Button>
        <div className="flex items-center gap-2 text-muted-foreground">
          <Timer className="w-3 h-3" />
          <span className={timeLeft < 60 ? 'text-red-500 font-bold' : ''}>
            {formatTime(timeLeft)}
          </span>
        </div>
      </div>

      {/* Progress */}
      <div className="space-y-2">
        <div className="flex justify-between text-sm">
          <span className="font-medium">Question {currentQuestion + 1} of {questions.length}</span>
          <span className="text-muted-foreground">
            {Object.keys(answers).length} answered
          </span>
        </div>
        <Progress 
          value={((currentQuestion + 1) / questions.length) * 100} 
          className="h-2" 
        />
      </div>

      {/* Question Card */}
      <Card className="select-none">
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle className="text-xl">
              {skillName} Assessment
            </CardTitle>
            <span className={cn(
              "text-xs px-2 py-1 rounded-full",
              currentQ?.difficulty === 'easy' && "bg-green-100 text-green-700",
              currentQ?.difficulty === 'medium' && "bg-yellow-100 text-yellow-700",
              currentQ?.difficulty === 'hard' && "bg-red-100 text-red-700"
            )}>
              {currentQ?.difficulty}
            </span>
          </div>
        </CardHeader>
        <CardContent className="space-y-4">
          <h3 className="text-lg font-medium select-none">
            {currentQ?.question_text}
          </h3>

          <div className="space-y-3">
            {currentQ?.options.map((option, index) => (
              <label
                key={index}
                className={cn(
                  "flex items-center space-x-3 p-5 rounded-lg border cursor-pointer transition-colors select-none",
                  answers[currentQ.id] === option
                    ? "border-primary bg-primary/5"
                    : "border-border hover:border-primary/50"
                )}
                onContextMenu={(e) => e.preventDefault()}
              >
                <input
                  type="radio"
                  name={`question-${currentQ.id}`}
                  value={option}
                  checked={answers[currentQ.id] === option}
                  onChange={() => handleAnswer(currentQ.id, option)}
                  className="text-primary w-4 h-4"
                  onCopy={(e) => e.preventDefault()}
                  onCut={(e) => e.preventDefault()}
                  onPaste={(e) => e.preventDefault()}
                />
                <span className="select-none">{option}</span>
              </label>
            ))}
          </div>
        </CardContent>
      </Card>


      {/* Written Assessment (shown after last question) */}
      {currentQuestion === questions.length - 1 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2">
              <span>Γ£ì∩╕Å</span> Written Assessment
            </CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-muted-foreground mb-4">
              Describe your experience with {skillName}. Include projects you've worked on, tools you've used, and your proficiency level.
            </p>
            <textarea
              value={writtenAnswer}
              onChange={(e) => setWrittenAnswer(e.target.value)}
              placeholder={`Write about your experience with ${skillName}...`}
              className="w-full min-h-[120px] p-3 rounded-lg border border-border bg-background resize-y focus:outline-none focus:ring-2 focus:ring-primary/50 select-none"
              onCopy={(e) => {
                e.preventDefault();
                handleSecurityViolation('Copy is disabled during exam');
              }}
              onCut={(e) => {
                e.preventDefault();
                handleSecurityViolation('Cut is disabled during exam');
              }}
              onPaste={(e) => {
                e.preventDefault();
                handleSecurityViolation('Paste is disabled during exam');
              }}
              onContextMenu={(e) => e.preventDefault()}
            />
            <div className="mt-2 text-xs text-muted-foreground text-right">
              {writtenAnswer.length} characters
            </div>
          </CardContent>
        </Card>
      )}


      {/* Navigation */}
      <div className="flex justify-between">
        <Button
          variant="outline"
          onClick={handlePrevious}
          disabled={currentQuestion === 0}
        >
          Previous
        </Button>

        {currentQuestion < questions.length - 1 ? (
          <Button
            onClick={handleNext}
            disabled={!answers[currentQ?.id]}
          >
            Next
          </Button>
        ) : (
          <Button
            onClick={handleSubmit}
            disabled={isSubmitting || !allAnswered}
            className="bg-green-600 hover:bg-green-700"
          >
            {isSubmitting ? (
              <>
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                Submitting...
              </>
            ) : (
              <>
                <CheckCircle2 className="w-4 h-4 mr-2" />
                Submit Exam
              </>
            )}
          </Button>
        )}
      </div>

      {/* Question Navigator */}
      <div className="flex flex-wrap gap-2 justify-center">
        {questions.map((q, index) => (
          <button
            key={q.id}
            onClick={() => setCurrentQuestion(index)}
            className={cn(
              "w-10 h-10 rounded-lg text-sm font-medium transition-colors",
              currentQuestion === index && "ring-2 ring-primary",
              answers[q.id] 
                ? "bg-primary text-primary-foreground"
                : "bg-muted hover:bg-muted/80"
            )}
          >
            {index + 1}
          </button>
        ))}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { 
  Shield, 
  CheckCircle, 
  XCircle, 
  AlertTriangle, 
  Download, 
  Share2, 
  ArrowLeft,
  Award,
  Calendar,
  User,
  BookOpen,
  Globe,
  Link,
  Network,
  ExternalLink,
  Lock
} from 'lucide-react';

import axiosClient from '@/api/axiosClient';
import type { Certificate } from '@/types';

interface VerificationResult {
  valid: boolean;
  certificate?: Certificate & {
    recipient_name?: string;
    course_name?: string;
    is_expired?: boolean;
    blockchain_network?: string;
    blockchain_tx_id?: string;
    blockchain_hash?: string;
    blockchain_anchored_at?: string;
    is_anchored?: boolean;
    blockchain_verified?: boolean;
    blockchain_message?: string;
    hash_algorithm?: string;
  };
  message: string;
}


// Parse skills from JSON string
const parseSkills = (skillsData: string | undefined): string[] => {
  if (!skillsData) return [];
  try {
    return JSON.parse(skillsData);
  } catch {
    return skillsData.split(',').map(s => s.trim());
  }
};

// Format date professionally
const formatDate = (dateString: string | undefined) => {
  if (!dateString) return 'N/A';
  try {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  } catch {
    return dateString;
  }
};

export default function VerifyCertificate() {
  const { certificateId } = useParams<{ certificateId: string }>();
  const navigate = useNavigate();
  const [verification, setVerification] = useState<VerificationResult | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const verifyCertificate = async () => {
      if (!certificateId) {
        setError('No certificate ID provided');
        setLoading(false);
        return;
      }

      try {
        const response = await axiosClient.get(`/certificate/verify/${certificateId}`);
        setVerification(response.data);
      } catch (err: any) {
        setError(err.response?.data?.detail || 'Failed to verify certificate');
      } finally {
        setLoading(false);
      }
    };

    verifyCertificate();
  }, [certificateId]);

  const handleShare = async () => {
    if (!verification?.certificate) return;
    const url = verification.certificate.verification_url || `https://careercompass.ai/verify/${certificateId}`;
    
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Career Compass AI Certificate Verification',
          text: `Verify my certificate: ${verification.certificate.role_title}`,
          url: url,
        });
      } catch (err) {
        // Cancelled
      }
    } else {
      await navigator.clipboard.writeText(url);
      alert('Verification URL copied to clipboard!');
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-amber-50 to-yellow-100 flex items-center justify-center p-4">
        <Card className="w-full max-w-md">
          <CardContent className="p-8 text-center">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-amber-600 mx-auto mb-4"></div>
            <p className="text-gray-600">Verifying certificate...</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (error || !verification) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-amber-50 to-yellow-100 flex items-center justify-center p-4">
        <Card className="w-full max-w-md">
          <CardContent className="p-8 text-center">
            <XCircle className="w-16 h-16 text-red-500 mx-auto mb-4" />
            <h1 className="text-2xl font-bold text-gray-800 mb-2">Verification Failed</h1>
            <p className="text-gray-600 mb-6">{error || 'An error occurred during verification'}</p>
            <Button 
              onClick={() => navigate('/')}
              className="bg-amber-500 hover:bg-amber-600 text-white"
            >
              <ArrowLeft className="w-4 h-4 mr-2" />
              Back to Home
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  const cert = verification.certificate;
  const skills = parseSkills(cert?.skills_covered);

  return (
    <div className="min-h-screen bg-gradient-to-br from-amber-50 to-yellow-100 py-12 px-4">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="text-center mb-8">
          <Button 
            variant="ghost" 
            onClick={() => navigate('/')}
            className="mb-4 text-gray-600 hover:text-gray-800"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Home
          </Button>
        </div>

        {/* Verification Status Card */}
        <Card className="mb-6">
          <CardContent className="p-6">
            <div className="flex items-center justify-center mb-4">
              {verification.valid ? (
                <div className="flex items-center justify-center w-20 h-20 bg-green-100 rounded-full">
                  <CheckCircle className="w-12 h-12 text-green-600" />
                </div>
              ) : (
                <div className="flex items-center justify-center w-20 h-20 bg-red-100 rounded-full">
                  <XCircle className="w-12 h-12 text-red-600" />
                </div>
              )}
            </div>
            
            <h1 className="text-2xl font-bold text-center mb-2">
              {verification.valid ? 'Certificate Verified' : 'Certificate Invalid'}
            </h1>
            
            <p className="text-center text-gray-600 mb-4">
              {verification.message}
            </p>

            {cert?.is_expired && (
              <div className="flex items-center justify-center gap-2 text-amber-600 bg-amber-50 p-3 rounded-lg">
                <AlertTriangle className="w-5 h-5" />
                <span className="font-medium">This certificate has expired</span>
              </div>
            )}

            {/* Blockchain Verification Status */}
            {cert?.is_anchored && (
              <div className="mt-4 p-3 rounded-lg bg-green-50 border border-green-200">
                <div className="flex items-center justify-center gap-2 text-green-700">
<Network className="w-5 h-5" />
                  <span className="font-medium flex items-center gap-2">
                    <Lock className="w-4 h-4" />
                    Secured by Blockchain
                  </span>
                </div>
                {cert?.blockchain_verified && (
                  <p className="text-center text-sm text-green-600 mt-1">
                    Γ£ô Verified on {cert?.blockchain_network || 'Blockchain'}
                  </p>
                )}
              </div>
            )}
          </CardContent>
        </Card>


        {/* Certificate Details */}
        {verification.valid && cert && (
          <Card>
            <CardContent className="p-6">
              <div className="border-b pb-4 mb-4">
                <div className="flex items-center gap-3 mb-4">
                  <Award className="w-8 h-8 text-amber-500" />
                  <div>
                    <h2 className="text-xl font-bold text-gray-800">{cert.role_title}</h2>
                    <p className="text-sm text-gray-500">Professional Certification</p>
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {/* Recipient */}
                <div className="flex items-start gap-3">
                  <User className="w-5 h-5 text-gray-400 mt-0.5" />
                  <div>
                    <p className="text-sm text-gray-500">Recipient</p>
                    <p className="font-semibold text-gray-800">{cert.user_name}</p>
                  </div>
                </div>

                {/* Issue Date */}
                <div className="flex items-start gap-3">
                  <Calendar className="w-5 h-5 text-gray-400 mt-0.5" />
                  <div>
                    <p className="text-sm text-gray-500">Issue Date</p>
                    <p className="font-semibold text-gray-800">{formatDate(cert.issued_at)}</p>
                  </div>
                </div>

                {/* Certificate ID */}
                <div className="flex items-start gap-3">
                  <Shield className="w-5 h-5 text-gray-400 mt-0.5" />
                  <div>
                    <p className="text-sm text-gray-500">Certificate ID</p>
                    <p className="font-mono font-semibold text-amber-600">{cert.certificate_unique_id}</p>
                  </div>
                </div>

                {/* Skills */}
                {skills.length > 0 && (
                  <div className="flex items-start gap-3">
                    <BookOpen className="w-5 h-5 text-gray-400 mt-0.5" />
                    <div>
                      <p className="text-sm text-gray-500 mb-2">Skills Covered</p>
                      <div className="flex flex-wrap gap-2">
                        {skills.map((skill, index) => (
                          <span 
                            key={index}
                            className="px-3 py-1 bg-amber-100 text-amber-800 text-sm rounded-full"
                          >
                            {skill}
                          </span>
                        ))}
                      </div>
                    </div>
                  </div>
                )}

                {/* Performance */}
                {cert.final_assessment_score && (
                  <div className="flex items-start gap-3">
                    <Award className="w-5 h-5 text-gray-400 mt-0.5" />
                    <div>
                      <p className="text-sm text-gray-500">Performance</p>
                      <div className="flex gap-4 mt-1">
                        <span className="font-semibold text-gray-800">
                          Score: {cert.final_assessment_score.toFixed(1)}%
                        </span>
                        {cert.performance_grade && (
                          <span className="font-semibold text-blue-800">
                            Grade: {cert.performance_grade}
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                )}
              </div>

              {/* Blockchain Info */}
              {cert?.is_anchored && (
                <div className="mt-6 pt-4 border-t">
                  <div className="flex items-center gap-2 text-sm text-gray-500 mb-3">
<Network className="w-4 h-4" />
                    <span>Blockchain Record:</span>
                  </div>
                  <div className="bg-gray-50 rounded-lg p-3 space-y-2">
                    <div className="flex justify-between text-sm">
                      <span className="text-gray-500">Network:</span>
                      <span className="font-medium text-purple-600 capitalize">
                        {cert?.blockchain_network || 'Sepolia Testnet'}
                      </span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-gray-500">Anchored:</span>
                      <span className="font-medium text-gray-800">
                        {cert?.blockchain_anchored_at ? formatDate(cert.blockchain_anchored_at) : 'N/A'}
                      </span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-gray-500">Algorithm:</span>
                      <span className="font-medium text-gray-800">
                        {cert?.hash_algorithm || 'SHA-256'}
                      </span>
                    </div>
                    {cert?.blockchain_tx_id && (
                      <div className="pt-2 border-t">
                        <p className="text-xs text-gray-500 mb-1">Transaction ID:</p>
                        <p className="font-mono text-xs text-blue-600 break-all">
                          {cert.blockchain_tx_id}
                        </p>
                        <a 
                          href={cert?.blockchain_network === 'polygon_amoy' 
                            ? `https://amoy.polygonscan.io/tx/${cert.blockchain_tx_id}`
                            : `https://sepolia.etherscan.io/tx/${cert.blockchain_tx_id}`
                          }
                          target="_blank"
                          rel="noopener noreferrer"
                          className="flex items-center gap-1 text-xs text-blue-600 hover:text-blue-800 mt-2"
                        >
                          <ExternalLink className="w-3 h-3" />
                          View on Explorer
                        </a>
                      </div>
                    )}
                  </div>
                </div>
              )}

              {/* Verification URL */}
              <div className="mt-6 pt-4 border-t">
                <div className="flex items-center gap-2 text-sm text-gray-500">
                  <Link className="w-4 h-4" />
                  <span>Verification URL:</span>
                </div>
                <p className="font-mono text-sm text-amber-600 break-all mt-1">
                  {cert.verification_url || `https://careercompass.ai/verify/${cert.certificate_unique_id}`}
                </p>
              </div>

              {/* Actions */}

              <div className="mt-6 flex gap-3">
                <Button 
                  onClick={handleShare}
                  variant="outline"
                  className="flex-1 border-amber-500 text-amber-600 hover:bg-amber-50"
                >
                  <Share2 className="w-4 h-4 mr-2" />
                  Share
                </Button>
                <Button 
                  onClick={() => window.open(cert.verification_url || `https://careercompass.ai/verify/${cert.certificate_unique_id}`, '_blank')}
                  className="flex-1 bg-amber-500 hover:bg-amber-600 text-white"
                >
                  <Globe className="w-4 h-4 mr-2" />
                  Visit Website
                </Button>
              </div>
            </CardContent>
          </Card>
        )}

        {/* Footer */}
        <div className="text-center mt-8">
          <p className="text-sm text-gray-500">
            Powered by <span className="font-semibold text-amber-600">Career Compass AI</span>
          </p>
          <p className="text-xs text-gray-400 mt-1">
            Secure Certificate Verification System
          </p>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useAuth } from "../../auth/AuthContext";
import { aiSettingsApi, AISettings, AIStatus } from "../../api/aiSettings.api";

// Available LLM models
const LLM_MODELS = [
  "gpt-3.5-turbo",
  "gpt-4",
  "gpt-4-turbo",
  "gpt-4o",
  "claude-3-opus",
  "claude-3-sonnet",
  "claude-3-haiku",
  "claude-3-5-sonnet",
  "llama-3-70b",
  "llama-3-8b",
  "mixtral-8x7b",
];

export default function AISettingsPage() {
  const { token } = useAuth();
  const [settings, setSettings] = useState<AISettings | null>(null);
  const [status, setStatus] = useState<AIStatus | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);
  const [isAdmin, setIsAdmin] = useState(false);
  
  // Local state for editable configuration values
  const [llmModel, setLlmModel] = useState<string>("");
  const [llmTemperature, setLlmTemperature] = useState<number>(0.7);
  const [ragTopK, setRagTopK] = useState<number>(5);
  const [skillInferenceThreshold, setSkillInferenceThreshold] = useState<number>(0.6);
  const [hasChanges, setHasChanges] = useState(false);

  useEffect(() => {
    loadSettings();
  }, [token]);

  const loadSettings = async () => {
    if (!token) return;
    try {
      setLoading(true);
      const [settingsResponse, statusResponse] = await Promise.all([
        aiSettingsApi.getSettings(token),
        aiSettingsApi.getStatus(),
      ]);
      // Extract data from axios response
      const settingsData = settingsResponse.data;
      const statusData = statusResponse.data;
      
setSettings(settingsData);
      setStatus(statusData);
      // Set isAdmin from settings response
      setIsAdmin(settingsData.is_admin || false);
      
      // Initialize local state with loaded values
      setLlmModel(settingsData.llm_model || "gpt-3.5-turbo");
      setLlmTemperature(settingsData.llm_temperature ?? 0.7);
      setRagTopK(settingsData.rag_top_k ?? 5);
      setSkillInferenceThreshold(settingsData.skill_inference_threshold ?? 0.6);
    } catch (error) {
      console.error("Failed to load AI settings:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleToggle = async (key: keyof AISettings, value: boolean) => {
    if (!token || !settings || !isAdmin) return;
    setSaving(true);
    setMessage(null);
    try {
      const updateData: Record<string, boolean> = {};
      if (key === "enable_llm") updateData.enable_llm = value;
      if (key === "enable_rag") updateData.enable_rag = value;
      if (key === "enable_evaluation") updateData.enable_evaluation = value;
      if (key === "enable_memory") updateData.enable_memory = value;

      const response = await aiSettingsApi.updateSettings(token, updateData);
      const result = response.data;
      
      setSettings({
        ...settings,
        enable_llm: result.current_settings.enable_llm,
        enable_rag: result.current_settings.enable_rag,
        enable_evaluation: result.current_settings.enable_evaluation,
        enable_memory: result.current_settings.enable_memory,
      });
      setStatus({
        ...status!,
        ai_enabled: result.current_settings.enable_llm || result.current_settings.enable_rag,
        llm_enabled: result.current_settings.enable_llm,
        rag_enabled: result.current_settings.enable_rag,
        features: {
          llm: result.current_settings.enable_llm,
          rag: result.current_settings.enable_rag,
          evaluation: result.current_settings.enable_evaluation,
          memory: result.current_settings.enable_memory,
        },
      });
setMessage({ type: "success", text: "Settings updated successfully!" });
    } catch (error: any) {
      const errorMsg = error.response?.data?.detail || "Failed to update settings";
      setMessage({ type: "error", text: errorMsg });
    } finally {
      setSaving(false);
    }
  };

  const handleConfigChange = (key: string, value: number | string) => {
    setHasChanges(true);
    if (key === "llm_model") {
      setLlmModel(value as string);
    } else if (key === "llm_temperature") {
      setLlmTemperature(value as number);
    } else if (key === "rag_top_k") {
      setRagTopK(value as number);
    } else if (key === "skill_inference_threshold") {
      setSkillInferenceThreshold(value as number);
    }
  };

  const handleSaveConfig = async () => {
    if (!token || !isAdmin) return;
    setSaving(true);
    setMessage(null);
    try {
      const updateData = {
        llm_model: llmModel,
        llm_temperature: llmTemperature,
        rag_top_k: ragTopK,
        skill_inference_threshold: skillInferenceThreshold,
      };

      const response = await aiSettingsApi.updateSettings(token, updateData);
      const result = response.data;
      
      setSettings({
        ...settings!,
        llm_model: result.current_settings.llm_model ?? llmModel,
        llm_temperature: result.current_settings.llm_temperature ?? llmTemperature,
        rag_top_k: result.current_settings.rag_top_k ?? ragTopK,
        skill_inference_threshold: result.current_settings.skill_inference_threshold ?? skillInferenceThreshold,
      });
      setHasChanges(false);
      setMessage({ type: "success", text: "Configuration saved successfully!" });
    } catch (error: any) {
      const errorMsg = error.response?.data?.detail || "Failed to save configuration";
      setMessage({ type: "error", text: errorMsg });
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-6">
      <h1 className="text-3xl font-bold mb-6">AI Settings</h1>

      {/* Admin Notice */}
      {!isAdmin && (
        <div className="mb-4 p-3 bg-blue-50 border border-blue-200 rounded-lg">
          <p className="text-sm text-blue-800">
            You are viewing AI settings in read-only mode. Only administrators can modify these settings.
          </p>
        </div>
      )}

      {/* Status Banner */}
      {status && (
        <div className={`mb-6 p-4 rounded-lg ${
          status.ai_enabled ? "bg-green-100 border border-green-300" : "bg-gray-100 border border-gray-300"
        }`}>
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-lg font-semibold">
                AI Status: {status.ai_enabled ? "Enabled" : "Disabled"}
              </h2>
              <p className="text-sm text-gray-600">
                {status.ai_enabled 
                  ? "AI features are currently active. Pages may load slower."
                  : "AI features are disabled for faster performance."}
              </p>
            </div>
            <div className="flex gap-2">
              {status.features.llm && (
                <span className="px-2 py-1 bg-blue-100 text-blue-800 text-xs rounded">LLM</span>
              )}
              {status.features.rag && (
                <span className="px-2 py-1 bg-purple-100 text-purple-800 text-xs rounded">RAG</span>
              )}
              {status.features.evaluation && (
                <span className="px-2 py-1 bg-yellow-100 text-yellow-800 text-xs rounded">Evaluation</span>
              )}
              {status.features.memory && (
                <span className="px-2 py-1 bg-orange-100 text-orange-800 text-xs rounded">Memory</span>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Message */}
      {message && (
        <div className={`mb-6 p-4 rounded-lg ${
          message.type === "success" ? "bg-green-100 text-green-800" : "bg-red-100 text-red-800"
        }`}>
          {message.text}
        </div>
      )}

      {/* Settings Toggle Cards */}
      <div className="grid gap-4 mb-6">
        {/* LLM Setting */}
        <div className="bg-white p-4 rounded-lg shadow border border-gray-200">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="font-semibold text-lg">LLM (Large Language Model)</h3>
              <p className="text-sm text-gray-600">
                Enable AI-powered responses and explanations
              </p>
            </div>
            {isAdmin ? (
              <button
                onClick={() => handleToggle("enable_llm", !settings?.enable_llm)}
                disabled={saving}
                className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                  settings?.enable_llm ? "bg-blue-600" : "bg-gray-300"
                }`}
              >
                <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                  settings?.enable_llm ? "translate-x-6" : "translate-x-1"
                }`} />
              </button>
            ) : (
              <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                settings?.enable_llm ? "bg-green-100 text-green-800" : "bg-gray-200 text-gray-600"
              }`}>
                {settings?.enable_llm ? "Enabled" : "Disabled"}
              </span>
            )}
          </div>
        </div>

        {/* RAG Setting */}
        <div className="bg-white p-4 rounded-lg shadow border border-gray-200">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="font-semibold text-lg">RAG (Retrieval Augmented Generation)</h3>
              <p className="text-sm text-gray-600">
                Enable semantic search and knowledge retrieval
              </p>
            </div>
            {isAdmin ? (
              <button
                onClick={() => handleToggle("enable_rag", !settings?.enable_rag)}
                disabled={saving}
                className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                  settings?.enable_rag ? "bg-blue-600" : "bg-gray-300"
                }`}
              >
                <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                  settings?.enable_rag ? "translate-x-6" : "translate-x-1"
                }`} />
              </button>
            ) : (
              <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                settings?.enable_rag ? "bg-green-100 text-green-800" : "bg-gray-200 text-gray-600"
              }`}>
                {settings?.enable_rag ? "Enabled" : "Disabled"}
              </span>
            )}
          </div>
        </div>

        {/* Evaluation Setting */}
        <div className="bg-white p-4 rounded-lg shadow border border-gray-200">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="font-semibold text-lg">AI Evaluation</h3>
              <p className="text-sm text-gray-600">
                Enable AI quality checks and metrics
              </p>
            </div>
            {isAdmin ? (
              <button
                onClick={() => handleToggle("enable_evaluation", !settings?.enable_evaluation)}
                disabled={saving}
                className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                  settings?.enable_evaluation ? "bg-blue-600" : "bg-gray-300"
                }`}
              >
                <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                  settings?.enable_evaluation ? "translate-x-6" : "translate-x-1"
                }`} />
              </button>
            ) : (
              <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                settings?.enable_evaluation ? "bg-green-100 text-green-800" : "bg-gray-200 text-gray-600"
              }`}>
                {settings?.enable_evaluation ? "Enabled" : "Disabled"}
              </span>
            )}
          </div>
        </div>

        {/* Memory Setting */}
        <div className="bg-white p-4 rounded-lg shadow border border-gray-200">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="font-semibold text-lg">Conversation Memory</h3>
              <p className="text-sm text-gray-600">
                Enable learning from conversations
              </p>
            </div>
            {isAdmin ? (
              <button
                onClick={() => handleToggle("enable_memory", !settings?.enable_memory)}
                disabled={saving}
                className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                  settings?.enable_memory ? "bg-blue-600" : "bg-gray-300"
                }`}
              >
                <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                  settings?.enable_memory ? "translate-x-6" : "translate-x-1"
                }`} />
              </button>
            ) : (
              <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                settings?.enable_memory ? "bg-green-100 text-green-800" : "bg-gray-200 text-gray-600"
              }`}>
                {settings?.enable_memory ? "Enabled" : "Disabled"}
              </span>
            )}
          </div>
        </div>
      </div>

{/* Advanced Configuration Section */}
      <div className="bg-gradient-to-br from-gray-50 to-gray-100 p-6 rounded-xl border border-gray-200 shadow-sm">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <div className="p-2 bg-blue-100 rounded-lg">
              <svg className="w-5 h-5 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </div>
            <h3 className="font-bold text-lg text-gray-800">Advanced Configuration</h3>
          </div>
          {isAdmin && hasChanges && (
            <button
              onClick={handleSaveConfig}
              disabled={saving}
              className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 text-sm font-medium transition-colors"
            >
              {saving ? (
                <>
                  <svg className="animate-spin h-4 w-4" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Saving...
                </>
              ) : (
                <>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                  Save Changes
                </>
              )}
            </button>
          )}
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {/* LLM Model - Dropdown */}
          <div className="bg-white p-4 rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow">
            <div className="flex items-center gap-2 mb-3">
              <div className="w-8 h-8 bg-purple-100 rounded-full flex items-center justify-center">
                <svg className="w-4 h-4 text-purple-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.75 17L9 20l-1 1h8l-1-1-.75-3M3 13h18M5 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
                </svg>
              </div>
              <div>
                <p className="text-xs text-gray-500 uppercase tracking-wide">LLM Model</p>
              </div>
            </div>
            {isAdmin ? (
              <select
                value={llmModel}
                onChange={(e) => handleConfigChange("llm_model", e.target.value)}
                className="w-full p-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:border-purple-500 bg-white"
              >
                {LLM_MODELS.map((model) => (
                  <option key={model} value={model}>{model}</option>
                ))}
              </select>
            ) : (
              <p className="font-semibold text-gray-800 text-sm">{llmModel}</p>
            )}
          </div>

          {/* Temperature - Range Slider */}
          <div className="bg-white p-4 rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow">
            <div className="flex items-center gap-2 mb-3">
              <div className="w-8 h-8 bg-orange-100 rounded-full flex items-center justify-center">
                <svg className="w-4 h-4 text-orange-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                </svg>
              </div>
              <div className="flex-1">
                <p className="text-xs text-gray-500 uppercase tracking-wide">Temperature</p>
              </div>
              <span className="text-sm font-bold text-orange-600">{llmTemperature.toFixed(1)}</span>
            </div>
            {isAdmin ? (
              <div className="space-y-2">
                <input
                  type="range"
                  min="0"
                  max="2"
                  step="0.1"
                  value={llmTemperature}
                  onChange={(e) => handleConfigChange("llm_temperature", parseFloat(e.target.value))}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-orange-500"
                />
                <div className="flex justify-between text-xs text-gray-400">
                  <span>0.0</span>
                  <span>2.0</span>
                </div>
              </div>
            ) : (
              <div className="mt-2">
                <div className="w-full bg-gray-200 rounded-full h-1.5">
                  <div 
                    className="bg-orange-500 h-1.5 rounded-full" 
                    style={{ width: `${(llmTemperature / 2) * 100}%` }}
                  ></div>
                </div>
              </div>
            )}
          </div>

          {/* RAG Top K - Range Slider */}
          <div className="bg-white p-4 rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow">
            <div className="flex items-center gap-2 mb-3">
              <div className="w-8 h-8 bg-green-100 rounded-full flex items-center justify-center">
                <svg className="w-4 h-4 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
              </div>
              <div>
                <p className="text-xs text-gray-500 uppercase tracking-wide">RAG Top K</p>
              </div>
            </div>
            {isAdmin ? (
              <div className="space-y-2">
                <input
                  type="range"
                  min="1"
                  max="20"
                  step="1"
                  value={ragTopK}
                  onChange={(e) => handleConfigChange("rag_top_k", parseInt(e.target.value))}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-green-500"
                />
                <div className="flex justify-between items-center">
                  <span className="text-sm font-bold text-green-600">{ragTopK}</span>
                  <span className="text-xs text-gray-400">results</span>
                </div>
              </div>
            ) : (
              <p className="font-semibold text-gray-800">{ragTopK}</p>
            )}
          </div>

          {/* Skill Inference Threshold - Range Slider */}
          <div className="bg-white p-4 rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow">
            <div className="flex items-center gap-2 mb-3">
              <div className="w-8 h-8 bg-red-100 rounded-full flex items-center justify-center">
                <svg className="w-4 h-4 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <div className="flex-1">
                <p className="text-xs text-gray-500 uppercase tracking-wide">Skill Inference Threshold</p>
              </div>
              <span className="text-sm font-bold text-red-600">{skillInferenceThreshold.toFixed(1)}</span>
            </div>
            {isAdmin ? (
              <div className="space-y-2">
                <input
                  type="range"
                  min="0"
                  max="1"
                  step="0.1"
                  value={skillInferenceThreshold}
                  onChange={(e) => handleConfigChange("skill_inference_threshold", parseFloat(e.target.value))}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-red-500"
                />
                <div className="flex justify-between text-xs text-gray-400">
                  <span>0.0</span>
                  <span>1.0</span>
                </div>
              </div>
            ) : (
              <div className="mt-2">
                <div className="w-full bg-gray-200 rounded-full h-1.5">
                  <div 
                    className="bg-red-500 h-1.5 rounded-full" 
                    style={{ width: `${skillInferenceThreshold * 100}%` }}
                  ></div>
                </div>
              </div>
            )}
          </div>

          {/* Embedding Model - Read Only */}
          <div className="bg-white p-4 rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow md:col-span-2">
            <div className="flex items-center gap-2 mb-3">
              <div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center">
                <svg className="w-4 h-4 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 7v10c0 2.21 3.582 4 8 4s8-1.79 8-4V7M4 7c0 2.21 3.582 4 8 4s8-1.79 8-4M4 7c0-2.21 3.582-4 8-4s8 1.79 8 4" />
                </svg>
              </div>
              <div>
                <p className="text-xs text-gray-500 uppercase tracking-wide">Embedding Model</p>
              </div>
            </div>
            <p className="font-semibold text-gray-800 text-sm">{settings?.embedding_model || 'Not configured'}</p>
            <p className="text-xs text-gray-400 mt-2">Model used for semantic embeddings and vector search</p>
          </div>
        </div>

        {/* Additional Info */}
        <div className="mt-4 pt-4 border-t border-gray-200">
          <div className="flex items-center gap-2 text-xs text-gray-500">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            <span>These settings control the AI behavior and performance. Modify with caution.</span>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { 
  Table, 
  TableBody, 
  TableCell, 
  TableHead, 
  TableHeader, 
  TableRow 
} from '@/components/ui/table';
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogTrigger,
  DialogFooter
} from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { 
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Separator } from '@/components/ui/separator';
import { ScrollArea } from '@/components/ui/scroll-area';
import { 
  Loader2, 
  Search, 
  Trash2, 
  Eye, 
  Edit3, 
  BookOpen,
  Video,
  FileQuestion,
  Save,
  X,
  CheckCircle2,
  Target,
  Clock,
  User,
  TrendingUp,
  Filter,
  Download,
  Plus,
  LayoutGrid,
  List,
  PlayCircle,
  Calendar,
  BarChart3
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { adminApi } from '@/api/admin.api';
import { cn } from '@/lib/utils';

interface LearningPath {
  id: number;
  user_id: number;
  target_role_id: number;
  target_role?: {
    id: number;
    title: string;
    description: string;
  };
  progress: number;
  total_duration: string;
  created_at: string;
  updated_at: string;
  steps?: LearningStep[];
}

interface LearningStep {
  id: number;
  skill_id: number;
  skill?: {
    id: number;
    name: string;
    description: string;
  };
  target_level: string;
  order: number;
  estimated_duration: string;
  is_completed: boolean;
  resources?: any[];
  assessment_questions?: any[];
}

interface StepFormData {
  target_level: string;
  estimated_duration: string;
  resources: string;
  assessment_questions: string;
  skill_name: string;
}

export default function AdminLearningPaths() {
  const { toast } = useToast();
  
  const [paths, setPaths] = useState<LearningPath[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedPath, setSelectedPath] = useState<LearningPath | null>(null);
  const [pathDetails, setPathDetails] = useState<LearningPath | null>(null);
  const [detailsLoading, setDetailsLoading] = useState(false);
  const [editingStep, setEditingStep] = useState<LearningStep | null>(null);
  const [isEditStepDialogOpen, setIsEditStepDialogOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [filterStatus, setFilterStatus] = useState<'all' | 'in-progress' | 'completed' | 'not-started'>('all');
  const [isAddingNewStep, setIsAddingNewStep] = useState(false);
  
  const [stepFormData, setStepFormData] = useState<StepFormData>({
    target_level: 'beginner',
    estimated_duration: '',
    resources: '',
    assessment_questions: '',
    skill_name: ''
  });

  useEffect(() => {
    fetchLearningPaths();
  }, []);

  const fetchLearningPaths = async () => {
    try {
      setLoading(true);
      const response = await adminApi.getLearningPaths();
      setPaths(response.paths || []);
    } catch (error) {
      console.error('Error fetching learning paths:', error);
      toast({
        title: 'Error',
        description: 'Failed to fetch learning paths',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const fetchPathDetails = async (pathId: number) => {
    try {
      setDetailsLoading(true);
      const response = await adminApi.getLearningPathDetails(pathId);
      setPathDetails(response);
    } catch (error) {
      console.error('Error fetching path details:', error);
      toast({
        title: 'Error',
        description: 'Failed to fetch path details',
        variant: 'destructive',
      });
    } finally {
      setDetailsLoading(false);
    }
  };

  const handleDeletePath = async (pathId: number) => {
    if (!confirm('Are you sure you want to delete this learning path?')) {
      return;
    }

    try {
      await adminApi.deleteLearningPath(pathId);
      toast({
        title: 'Success',
        description: 'Learning path deleted successfully',
      });
      fetchLearningPaths();
    } catch (error) {
      console.error('Error deleting path:', error);
      toast({
        title: 'Error',
        description: 'Failed to delete learning path',
        variant: 'destructive',
      });
    }
  };

  const handleUpdateStep = async () => {
    if (!selectedPath || !editingStep) return;

    try {
      const resources = stepFormData.resources ? JSON.parse(stepFormData.resources) : [];
      const assessmentQuestions = stepFormData.assessment_questions ? JSON.parse(stepFormData.assessment_questions) : [];
      
      if (isAddingNewStep) {
        // Create new step using POST endpoint
        const createData: any = {
          skill_name: stepFormData.skill_name,
          target_level: stepFormData.target_level,
          estimated_duration: stepFormData.estimated_duration,
          resources: resources,
          assessment_questions: assessmentQuestions
        };
        
        await adminApi.createLearningStep(selectedPath.id, createData);
      } else {
        // Update existing step using PUT endpoint
        const updateData: any = {
          target_level: stepFormData.target_level,
          estimated_duration: stepFormData.estimated_duration,
          resources: resources,
          assessment_questions: assessmentQuestions
        };
        
        await adminApi.updateLearningStep(selectedPath.id, editingStep.id, updateData);
      }
      
      toast({
        title: 'Success',
        description: isAddingNewStep ? 'Learning step added successfully' : 'Learning step updated successfully',
      });
      
      setIsEditStepDialogOpen(false);
      setEditingStep(null);
      setIsAddingNewStep(false);
      fetchPathDetails(selectedPath.id);
    } catch (error) {
      console.error('Error updating step:', error);
      toast({
        title: 'Error',
        description: 'Failed to update learning step. Check JSON format.',
        variant: 'destructive',
      });
    }
  };

  const handleDeleteStep = async (stepId: number) => {
    if (!selectedPath) return;
    
    if (!confirm('Are you sure you want to delete this learning step?')) {
      return;
    }

    try {
      await adminApi.deleteLearningStep(selectedPath.id, stepId);
      toast({
        title: 'Success',
        description: 'Learning step deleted successfully',
      });
      fetchPathDetails(selectedPath.id);
    } catch (error) {
      console.error('Error deleting step:', error);
      toast({
        title: 'Error',
        description: 'Failed to delete learning step',
        variant: 'destructive',
      });
    }
  };

  const openEditStepDialog = (step: LearningStep) => {
    setIsAddingNewStep(false);
    setEditingStep(step);
    setStepFormData({
      target_level: step.target_level || 'beginner',
      estimated_duration: step.estimated_duration || '',
      resources: step.resources ? JSON.stringify(step.resources, null, 2) : '[]',
      assessment_questions: step.assessment_questions ? JSON.stringify(step.assessment_questions, null, 2) : '[]',
      skill_name: step.skill?.name || ''
    });
    setIsEditStepDialogOpen(true);
  };

  const openAddStepDialog = () => {
    setIsAddingNewStep(true);
    const newStep: LearningStep = {
      id: 0,
      skill_id: 0,
      target_level: 'beginner',
      order: (pathDetails?.steps?.length || 0) + 1,
      estimated_duration: '',
      is_completed: false,
      resources: [],
      assessment_questions: []
    };
    setEditingStep(newStep);
    setStepFormData({
      target_level: 'beginner',
      estimated_duration: '',
      resources: '[]',
      assessment_questions: '[]',
      skill_name: ''
    });
    setIsEditStepDialogOpen(true);
  };

  const getStatusColor = (progress: number) => {
    if (progress === 0) return 'bg-slate-500';
    if (progress === 100) return 'bg-green-500';
    return 'bg-blue-500';
  };

  const getStatusBadge = (progress: number): { label: string; variant: 'secondary' | 'default' | 'outline' } => {
    if (progress === 0) {
      return { label: 'Not Started', variant: 'secondary' };
    }
    if (progress === 100) {
      return { label: 'Completed', variant: 'default' };
    }
    return { label: 'In Progress', variant: 'outline' };
  };


  const filteredPaths = paths.filter(path => {
    const matchesSearch = path.target_role?.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      path.user_id?.toString().includes(searchTerm);
    
    const matchesFilter = filterStatus === 'all' ||
      (filterStatus === 'completed' && path.progress === 100) ||
      (filterStatus === 'in-progress' && path.progress > 0 && path.progress < 100) ||
      (filterStatus === 'not-started' && path.progress === 0);
    
    return matchesSearch && matchesFilter;
  });

  const totalCount = paths.length;
  const completedCount = paths.filter(p => p.progress === 100).length;
  const inProgressCount = paths.filter(p => p.progress > 0 && p.progress < 100).length;
  const notStartedCount = paths.filter(p => p.progress === 0).length;

  const stats = {
    total: totalCount,
    completed: completedCount,
    inProgress: inProgressCount,
    notStarted: notStartedCount,
  };


  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-900 dark:to-slate-800 p-8">
        <div className="flex items-center justify-center h-64">
          <div className="text-center">
            <Loader2 className="w-12 h-12 animate-spin text-primary mx-auto mb-4" />
            <p className="text-muted-foreground text-lg">Loading learning paths...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-900 dark:to-slate-800 p-8">
      {/* Header */}
      <div className="mb-8">
        <div className="flex items-center justify-between mb-2">
          <div>
            <h1 className="text-4xl font-bold bg-gradient-to-r from-primary to-purple-600 bg-clip-text text-transparent">
              Learning Path Management
            </h1>
            <p className="text-muted-foreground mt-2 text-lg">
              Advanced roadmap configuration and progress tracking
            </p>
          </div>
          <div className="flex items-center gap-3">
            <Button variant="outline" className="gap-2">
              <Download className="w-4 h-4" />
              Export
            </Button>
            <Button className="gap-2">
              <Plus className="w-4 h-4" />
              Create Path
            </Button>
          </div>
        </div>
      </div>

      {/* Stats - Simplified to 2 cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
        <Card className="bg-white/80 backdrop-blur-sm border-0 shadow-lg">
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Total Paths</p>
                <p className="text-3xl font-bold">{stats.total}</p>
              </div>
              <div className="w-12 h-12 bg-primary/10 rounded-full flex items-center justify-center">
                <Target className="w-6 h-6 text-primary" />
              </div>
            </div>
          </CardContent>
        </Card>
        <Card className="bg-white/80 backdrop-blur-sm border-0 shadow-lg">
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Total Users</p>
                <p className="text-3xl font-bold text-blue-600">
                  {new Set(paths.map(p => p.user_id)).size}
                </p>
              </div>
              <div className="w-12 h-12 bg-blue-100 rounded-full flex items-center justify-center">
                <User className="w-6 h-6 text-blue-600" />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Filters */}
      <Card className="mb-6 border-0 shadow-lg bg-white/80 backdrop-blur-sm">
        <CardContent className="p-6">
          <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
            <div className="flex items-center gap-4 flex-1 w-full">
              <div className="relative flex-1 max-w-md">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-5 h-5" />
                <Input
                  placeholder="Search by role title or user ID..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10 h-12 text-lg"
                />
              </div>
              <Select value={filterStatus} onValueChange={(v: any) => setFilterStatus(v)}>
                <SelectTrigger className="w-[180px] h-12">
                  <Filter className="w-4 h-4 mr-2" />
                  <SelectValue placeholder="Filter by status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Status</SelectItem>
                  <SelectItem value="in-progress">In Progress</SelectItem>
                  <SelectItem value="completed">Completed</SelectItem>
                  <SelectItem value="not-started">Not Started</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="flex items-center gap-3">
              <div className="flex items-center bg-muted rounded-lg p-1">
                <Button
                  variant={viewMode === 'grid' ? 'secondary' : 'ghost'}
                  size="sm"
                  onClick={() => setViewMode('grid')}
                  className="gap-2"
                >
                  <LayoutGrid className="w-4 h-4" />
                  Grid
                </Button>
                <Button
                  variant={viewMode === 'list' ? 'secondary' : 'ghost'}
                  size="sm"
                  onClick={() => setViewMode('list')}
                  className="gap-2"
                >
                  <List className="w-4 h-4" />
                  List
                </Button>
              </div>
              <Button onClick={fetchLearningPaths} variant="outline" className="h-12 px-6">
                Refresh
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Grid View */}
      {viewMode === 'grid' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredPaths.map((path) => {
            const status = getStatusBadge(path.progress);
            return (
              <Card key={path.id} className="group border-0 shadow-lg bg-white/80 backdrop-blur-sm hover:shadow-xl transition-all duration-300 overflow-hidden">
                <div className={cn("h-2", getStatusColor(path.progress))} />
                <CardContent className="p-6">
                  <div className="flex items-start justify-between mb-4">
                    <div>
                      <Badge variant={status.variant} className="mb-2">
                        {status.label}
                      </Badge>
                      <h3 className="text-xl font-bold mb-1">
                        {path.target_role?.title || `Role ${path.target_role_id}`}
                      </h3>
                      <p className="text-sm text-muted-foreground flex items-center gap-2">
                        <User className="w-4 h-4" />
                        User ID: {path.user_id}
                      </p>
                    </div>
                    <div className="flex gap-2">
                      <Dialog>
                        <DialogTrigger asChild>
                          <Button 
                            variant="ghost" 
                            size="icon"
                            onClick={() => {
                              setSelectedPath(path);
                              fetchPathDetails(path.id);
                            }}
                            className="hover:bg-primary/10"
                          >
                            <Eye className="w-5 h-5" />
                          </Button>
                        </DialogTrigger>
                        <DialogContent className="max-w-4xl max-h-[85vh] overflow-hidden p-0">
                          <div className="bg-gradient-to-r from-primary/5 to-purple-500/5 p-6 border-b">
                            <DialogHeader>
                              <DialogTitle className="text-2xl flex items-center gap-3">
                                <Target className="w-8 h-8 text-primary" />
                                {path.target_role?.title || `Role ${path.target_role_id}`}
                              </DialogTitle>
                            </DialogHeader>
                          </div>
                          
                          <ScrollArea className="max-h-[60vh]">
                            <div className="p-6">
                              {detailsLoading ? (
                                <div className="flex items-center justify-center py-12">
                                  <Loader2 className="w-8 h-8 animate-spin text-primary" />
                                </div>
                              ) : pathDetails ? (
                                <div className="space-y-6">
                                  {/* Simplified stats - removed progress and completed count */}
                                  <div className="grid grid-cols-2 gap-4">
                                    <Card className="bg-blue-50 border-0">
                                      <CardContent className="p-4 text-center">
                                        <p className="text-2xl font-bold text-blue-600">{pathDetails.steps?.length || 0}</p>
                                        <p className="text-xs text-muted-foreground">Total Steps</p>
                                      </CardContent>
                                    </Card>
                                    <Card className="bg-purple-50 border-0">
                                      <CardContent className="p-4 text-center">
                                        <p className="text-2xl font-bold text-purple-600">{pathDetails.total_duration}</p>
                                        <p className="text-xs text-muted-foreground">Duration</p>
                                      </CardContent>
                                    </Card>
                                  </div>

                                  <Separator />

                                  <div>
                                    <div className="flex items-center justify-between mb-4">
                                      <h3 className="text-lg font-semibold flex items-center gap-2">
                                        <BarChart3 className="w-5 h-5" />
                                        Learning Steps
                                      </h3>
                                      <Button 
                                        variant="outline" 
                                        size="sm"
                                        className="gap-2"
                                        onClick={openAddStepDialog}
                                      >
                                        <Plus className="w-4 h-4" />
                                        Add Step
                                      </Button>
                                    </div>

                                    <div className="space-y-3">
                                      {pathDetails.steps?.map((step, index) => (
                                        <Card key={step.id} className="border-l-4 border-l-primary">
                                          <CardContent className="p-4">
                                            <div className="flex items-center justify-between">
                                              <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold bg-primary/10 text-primary">
                                                  {index + 1}
                                                </div>
                                                <div>
                                                  <p className="font-semibold">{step.skill?.name || `Skill ${step.skill_id}`}</p>
                                                  <p className="text-sm text-muted-foreground">
                                                    {step.estimated_duration} ΓÇó Target: {step.target_level}
                                                  </p>
                                                </div>
                                              </div>
                                              <div className="flex items-center gap-2">
                                                <Button
                                                  variant="outline"
                                                  size="sm"
                                                  onClick={() => openEditStepDialog(step)}
                                                >
                                                  <Edit3 className="w-4 h-4 mr-1" />
                                                  Edit
                                                </Button>
                                                <Button
                                                  variant="outline"
                                                  size="sm"
                                                  onClick={() => handleDeleteStep(step.id)}
                                                  className="text-destructive hover:bg-destructive/10"
                                                >
                                                  <Trash2 className="w-4 h-4 mr-1" />
                                                  Delete
                                                </Button>
                                              </div>
                                            </div>
                                          </CardContent>
                                        </Card>
                                      ))}
                                    </div>
                                  </div>
                                </div>
                              ) : (
                                <p className="text-muted-foreground text-center py-8">No details available</p>
                              )}
                            </div>
                          </ScrollArea>
                        </DialogContent>
                      </Dialog>
                      <Button 
                        variant="ghost" 
                        size="icon"
                        onClick={() => handleDeletePath(path.id)}
                        className="text-destructive hover:bg-destructive/10"
                      >
                        <Trash2 className="w-5 h-5" />
                      </Button>
                    </div>
                  </div>

                  <div className="flex items-center justify-between pt-4 border-t">
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <Clock className="w-4 h-4" />
                      {path.total_duration}
                    </div>
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <Calendar className="w-4 h-4" />
                      {new Date(path.created_at).toLocaleDateString()}
                    </div>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      ) : (
        /* List View */
        <Card className="border-0 shadow-lg bg-white/80 backdrop-blur-sm">
          <CardContent className="p-0">
            <Table>
              <TableHeader>
                <TableRow className="hover:bg-transparent">
                  <TableHead className="font-semibold">ID</TableHead>
                  <TableHead className="font-semibold">User</TableHead>
                  <TableHead className="font-semibold">Target Role</TableHead>
                  <TableHead className="font-semibold">Status</TableHead>
                  <TableHead className="font-semibold">Duration</TableHead>
                  <TableHead className="font-semibold">Created</TableHead>
                  <TableHead className="font-semibold text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredPaths.map((path) => {
                  const status = getStatusBadge(path.progress);
                  return (
                    <TableRow key={path.id} className="group">
                      <TableCell className="font-medium">#{path.id}</TableCell>
                      <TableCell>
                        <div className="flex items-center gap-2">
                          <div className="w-8 h-8 bg-primary/10 rounded-full flex items-center justify-center">
                            <User className="w-4 h-4 text-primary" />
                          </div>
                          <span>User {path.user_id}</span>
                        </div>
                      </TableCell>
                      <TableCell>
                        <Badge variant="outline" className="font-medium">
                          {path.target_role?.title || `Role ${path.target_role_id}`}
                        </Badge>
                      </TableCell>
                      <TableCell>
                        <Badge variant={status.variant} className="text-xs">
                          {status.label}
                        </Badge>
                      </TableCell>
                      <TableCell>{path.total_duration}</TableCell>
                      <TableCell>{new Date(path.created_at).toLocaleDateString()}</TableCell>
                      <TableCell className="text-right">
                        <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <Dialog>
                            <DialogTrigger asChild>
                              <Button 
                                variant="ghost" 
                                size="sm"
                                onClick={() => {
                                  setSelectedPath(path);
                                  fetchPathDetails(path.id);
                                }}
                              >
                                <Eye className="w-4 h-4 mr-1" />
                                View
                              </Button>
                            </DialogTrigger>
                            <DialogContent className="max-w-4xl max-h-[85vh] overflow-hidden p-0">
                              <div className="bg-gradient-to-r from-primary/5 to-purple-500/5 p-6 border-b">
                                <DialogHeader>
                                  <DialogTitle className="text-2xl flex items-center gap-3">
                                    <Target className="w-8 h-8 text-primary" />
                                    {path.target_role?.title || `Role ${path.target_role_id}`}
                                  </DialogTitle>
                                </DialogHeader>
                              </div>
                              
                              <ScrollArea className="max-h-[60vh]">
                                <div className="p-6">
                                  {detailsLoading ? (
                                    <div className="flex items-center justify-center py-12">
                                      <Loader2 className="w-8 h-8 animate-spin text-primary" />
                                    </div>
                                  ) : pathDetails ? (
                                    <div className="space-y-6">
                                      {/* Simplified stats - removed progress and completed count */}
                                      <div className="grid grid-cols-2 gap-4">
                                        <Card className="bg-blue-50 border-0">
                                          <CardContent className="p-4 text-center">
                                            <p className="text-2xl font-bold text-blue-600">{pathDetails.steps?.length || 0}</p>
                                            <p className="text-xs text-muted-foreground">Total Steps</p>
                                          </CardContent>
                                        </Card>
                                        <Card className="bg-purple-50 border-0">
                                          <CardContent className="p-4 text-center">
                                            <p className="text-2xl font-bold text-purple-600">{pathDetails.total_duration}</p>
                                            <p className="text-xs text-muted-foreground">Duration</p>
                                          </CardContent>
                                        </Card>
                                      </div>

                                      <Separator />

                                      <div>
                                        <div className="flex items-center justify-between mb-4">
                                          <h3 className="text-lg font-semibold">Learning Steps</h3>
                                          <Button 
                                            variant="outline" 
                                            size="sm"
                                            className="gap-2"
                                            onClick={openAddStepDialog}
                                          >
                                            <Plus className="w-4 h-4" />
                                            Add Step
                                          </Button>
                                        </div>

                                        <div className="space-y-3">
                                          {pathDetails.steps?.map((step, index) => (
                                            <Card key={step.id} className="border-l-4 border-l-primary">
                                              <CardContent className="p-4">
                                                <div className="flex items-center justify-between">
                                                  <div className="flex items-center gap-3">
                                                    <div className="w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold bg-primary/10 text-primary">
                                                      {index + 1}
                                                    </div>
                                                    <div>
                                                      <p className="font-semibold">{step.skill?.name || `Skill ${step.skill_id}`}</p>
                                                      <p className="text-sm text-muted-foreground">
                                                        {step.estimated_duration} ΓÇó Target: {step.target_level}
                                                      </p>
                                                    </div>
                                                  </div>
                                                  <div className="flex items-center gap-2">
                                                    <Button
                                                      variant="outline"
                                                      size="sm"
                                                      onClick={() => openEditStepDialog(step)}
                                                    >
                                                      <Edit3 className="w-4 h-4 mr-1" />
                                                      Edit
                                                    </Button>
                                                    <Button
                                                      variant="outline"
                                                      size="sm"
                                                      onClick={() => handleDeleteStep(step.id)}
                                                      className="text-destructive hover:bg-destructive/10"
                                                    >
                                                      <Trash2 className="w-4 h-4 mr-1" />
                                                      Delete
                                                    </Button>
                                                  </div>
                                                </div>
                                              </CardContent>
                                            </Card>
                                          ))}
                                        </div>
                                      </div>
                                    </div>
                                  ) : (
                                    <p className="text-muted-foreground text-center py-8">No details available</p>
                                  )}
                                </div>
                              </ScrollArea>
                            </DialogContent>
                          </Dialog>
                          <Button 
                            variant="ghost" 
                            size="sm"
                            onClick={() => handleDeletePath(path.id)}
                            className="text-destructive hover:bg-destructive/10"
                          >
                            <Trash2 className="w-4 h-4 mr-1" />
                            Delete
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      )}

      {filteredPaths.length === 0 && (
        <Card className="border-0 shadow-lg bg-white/80 backdrop-blur-sm">
          <CardContent className="p-12 text-center">
            <div className="w-20 h-20 bg-muted rounded-full flex items-center justify-center mx-auto mb-4">
              <Target className="w-10 h-10 text-muted-foreground" />
            </div>
            <h3 className="text-xl font-semibold mb-2">No learning paths found</h3>
            <p className="text-muted-foreground mb-4">Try adjusting your search or create a new learning path</p>
            <Button onClick={() => setSearchTerm('')} variant="outline">
              Clear Filters
            </Button>
          </CardContent>
        </Card>
      )}

      {/* Edit/Add Step Dialog */}
      <Dialog 
        open={isEditStepDialogOpen} 
        onOpenChange={(open) => {
          if (!open) {
            setIsEditStepDialogOpen(false);
            setEditingStep(null);
            setIsAddingNewStep(false);
          }
        }}
      >
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader className="border-b pb-4">
            <DialogTitle className="text-2xl flex items-center gap-3">
              <Edit3 className="w-6 h-6 text-primary" />
              {isAddingNewStep ? 'Add New Step' : 'Edit Learning Step'}
            </DialogTitle>
            <p className="text-muted-foreground">
              {isAddingNewStep ? 'Create a new learning step' : (editingStep?.skill?.name || `Skill ${editingStep?.skill_id}`)}
            </p>
          </DialogHeader>
          
          <form 
            onSubmit={(e) => {
              e.preventDefault();
              handleUpdateStep();
            }}
            className="space-y-6 py-4"
          >
            {/* Skill Name Input - Only for new steps */}
            {isAddingNewStep && (
              <div className="space-y-2">
                <Label htmlFor="skill_name">Skill Name *</Label>
                <Input
                  id="skill_name"
                  type="text"
                  value={stepFormData.skill_name}
                  onChange={(e) => setStepFormData({ ...stepFormData, skill_name: e.target.value })}
                  placeholder="e.g., Python, CSS, Docker, React..."
                  className="w-full"
                  required
                />
                <p className="text-xs text-muted-foreground">Enter the skill name (e.g., Python, CSS, JavaScript)</p>
              </div>
            )}

            <div className="space-y-2">
              <Label htmlFor="target_level">Target Level *</Label>
              <Select
                value={stepFormData.target_level}
                onValueChange={(value) => setStepFormData({ ...stepFormData, target_level: value })}
              >
                <SelectTrigger id="target_level" className="w-full">
                  <SelectValue placeholder="Select target level" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="beginner">Beginner</SelectItem>
                  <SelectItem value="intermediate">Intermediate</SelectItem>
                  <SelectItem value="advanced">Advanced</SelectItem>
                  <SelectItem value="expert">Expert</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="estimated_duration">Estimated Duration *</Label>
              <Input
                id="estimated_duration"
                type="text"
                value={stepFormData.estimated_duration}
                onChange={(e) => setStepFormData({ ...stepFormData, estimated_duration: e.target.value })}
                placeholder="e.g., 2 hours, 3 days, 1 week"
                className="w-full"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="resources">
                Resources (JSON format)
                <span className="text-xs text-muted-foreground ml-2">Array of objects with title, url, type</span>
              </Label>
              <Textarea
                id="resources"
                value={stepFormData.resources}
                onChange={(e) => setStepFormData({ ...stepFormData, resources: e.target.value })}
                placeholder={`[
  {
    "title": "Introduction Video",
    "url": "https://example.com/video",
    "type": "video"
  }
]`}
                rows={6}
                className="font-mono text-sm w-full"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="assessment_questions">
                Assessment Questions (JSON format)
                <span className="text-xs text-muted-foreground ml-2">Array of objects with question, options, correct_answer</span>
              </Label>
              <Textarea
                id="assessment_questions"
                value={stepFormData.assessment_questions}
                onChange={(e) => setStepFormData({ ...stepFormData, assessment_questions: e.target.value })}
                placeholder={`[
  {
    "question": "What is...?",
    "options": ["A", "B", "C", "D"],
    "correct_answer": "A"
  }
]`}
                rows={8}
                className="font-mono text-sm w-full"
              />
            </div>

            <DialogFooter className="gap-2">
              <Button 
                type="button"
                variant="outline" 
                onClick={() => {
                  setIsEditStepDialogOpen(false);
                  setEditingStep(null);
                  setIsAddingNewStep(false);
                }}
              >
                <X className="w-4 h-4 mr-2" />
                Cancel
              </Button>
              <Button type="submit">
                <Save className="w-4 h-4 mr-2" />
                {isAddingNewStep ? 'Add Step' : 'Save Changes'}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { 
  Table, 
  TableBody, 
  TableCell, 
  TableHead, 
  TableHeader, 
  TableRow 
} from '@/components/ui/table';
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogFooter
} from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { Label } from '@/components/ui/label';
import { 
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { 
  Loader2, 
  Search, 
  Trash2, 
  Edit3, 
  Plus,
  BookOpen,
  Video,
  FileText,
  ExternalLink,
  X,
  Save
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { adminApi } from '@/api/admin.api';

interface LearningResource {
  id: number;
  title: string;
  description: string;
  type: 'article' | 'video' | 'course' | 'tutorial' | 'documentation';
  url: string;
  skill_id: number;
  skill?: {
    id: number;
    name: string;
  };
  difficulty: 'beginner' | 'intermediate' | 'advanced';
  duration: string;
  provider: string;
  cost: 'free' | 'paid';
  rating: number;
  created_at: string;
}

const resourceTypeIcons = {
  article: FileText,
  video: Video,
  course: BookOpen,
  tutorial: BookOpen,
  documentation: FileText,
};

export default function AdminLearningResources() {
  const { toast } = useToast();
  const [resources, setResources] = useState<LearningResource[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedResource, setSelectedResource] = useState<LearningResource | null>(null);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);

  // Form state for create/edit
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    type: 'article',
    url: '',
    skill_id: '',
    difficulty: 'beginner',
    duration: '',
    provider: '',
    cost: 'free',
    rating: 0,
  });

  useEffect(() => {
    fetchResources();
  }, []);

  const fetchResources = async () => {
    try {
      setLoading(true);
      const response = await adminApi.getLearningResources();
      setResources(response.resources || []);
    } catch (error) {
      console.error('Error fetching resources:', error);
      toast({
        title: 'Error',
        description: 'Failed to fetch learning resources',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  };

  const handleCreateResource = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await adminApi.createLearningResource({
        ...formData,
        skill_id: parseInt(formData.skill_id) || 0,
      });
      toast({
        title: 'Success',
        description: 'Learning resource created successfully',
      });
      setIsCreateDialogOpen(false);
      resetForm();
      fetchResources();
    } catch (error) {
      console.error('Error creating resource:', error);
      toast({
        title: 'Error',
        description: 'Failed to create learning resource',
        variant: 'destructive',
      });
    }
  };

  const handleUpdateResource = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedResource) return;

    try {
      await adminApi.updateLearningResource(selectedResource.id, {
        ...formData,
        skill_id: parseInt(formData.skill_id) || 0,
      });
      toast({
        title: 'Success',
        description: 'Learning resource updated successfully',
      });
      setIsEditDialogOpen(false);
      setSelectedResource(null);
      resetForm();
      fetchResources();
    } catch (error) {
      console.error('Error updating resource:', error);
      toast({
        title: 'Error',
        description: 'Failed to update learning resource',
        variant: 'destructive',
      });
    }
  };

  const handleDeleteResource = async (resourceId: number) => {
    if (!confirm('Are you sure you want to delete this resource?')) {
      return;
    }

    try {
      await adminApi.deleteLearningResource(resourceId);
      toast({
        title: 'Success',
        description: 'Learning resource deleted successfully',
      });
      fetchResources();
    } catch (error) {
      console.error('Error deleting resource:', error);
      toast({
        title: 'Error',
        description: 'Failed to delete learning resource',
        variant: 'destructive',
      });
    }
  };

  const openEditDialog = (resource: LearningResource) => {
    setSelectedResource(resource);
    setFormData({
      title: resource.title || '',
      description: resource.description || '',
      type: resource.type || 'article',
      url: resource.url || '',
      skill_id: resource.skill_id?.toString() || '',
      difficulty: resource.difficulty || 'beginner',
      duration: resource.duration || '',
      provider: resource.provider || '',
      cost: resource.cost || 'free',
      rating: resource.rating || 0,
    });
    setIsEditDialogOpen(true);
  };

  const openCreateDialog = () => {
    resetForm();
    setIsCreateDialogOpen(true);
  };

  const resetForm = () => {
    setFormData({
      title: '',
      description: '',
      type: 'article',
      url: '',
      skill_id: '',
      difficulty: 'beginner',
      duration: '',
      provider: '',
      cost: 'free',
      rating: 0,
    });
  };

  const filteredResources = resources.filter(resource => 
    resource.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    resource.description?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    resource.skill?.name?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="w-8 h-8 animate-spin text-primary" />
          <span className="ml-2 text-muted-foreground">Loading resources...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold mb-2">Learning Resources Management</h1>
        <p className="text-muted-foreground">
          Manage videos, articles, courses, and assessments for learning paths
        </p>
      </div>

      {/* Search and Actions */}
      <Card className="mb-6">
        <CardContent className="p-4">
          <div className="flex items-center gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
              <Input
                placeholder="Search by title, description, or skill..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
              />
            </div>
            <Button onClick={fetchResources} variant="outline">
              Refresh
            </Button>
            <Button onClick={openCreateDialog}>
              <Plus className="w-4 h-4 mr-2" />
              Add Resource
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Resources Table */}
      <Card>
        <CardHeader>
          <CardTitle>All Learning Resources ({filteredResources.length})</CardTitle>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Type</TableHead>
                <TableHead>Title</TableHead>
                <TableHead>Skill</TableHead>
                <TableHead>Difficulty</TableHead>
                <TableHead>Duration</TableHead>
                <TableHead>Cost</TableHead>
                <TableHead>Rating</TableHead>
                <TableHead>Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredResources.map((resource) => {
                const Icon = resourceTypeIcons[resource.type] || BookOpen;
                return (
                  <TableRow key={resource.id}>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        <Icon className="w-4 h-4" />
                        <Badge variant="outline">{resource.type}</Badge>
                      </div>
                    </TableCell>
                    <TableCell>
                      <div>
                        <p className="font-medium">{resource.title}</p>
                        <p className="text-sm text-muted-foreground">{resource.provider}</p>
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge variant="secondary">
                        {resource.skill?.name || `Skill ${resource.skill_id}`}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <Badge variant="outline">{resource.difficulty}</Badge>
                    </TableCell>
                    <TableCell>{resource.duration}</TableCell>
                    <TableCell>
                      <Badge variant="outline" className={resource.cost === 'free' ? 'bg-green-100 text-green-800 border-green-200' : ''}>
                        {resource.cost}
                      </Badge>
                    </TableCell>

                    <TableCell>
                      <div className="flex items-center gap-1">
                        <span>Γ¡É</span>
                        <span>{resource.rating}</span>
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => window.open(resource.url, '_blank')}
                        >
                          <ExternalLink className="w-4 h-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => openEditDialog(resource)}
                        >
                          <Edit3 className="w-4 h-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleDeleteResource(resource.id)}
                          className="text-destructive hover:text-destructive"
                        >
                          <Trash2 className="w-4 h-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>

          {filteredResources.length === 0 && (
            <div className="text-center py-8 text-muted-foreground">
              <BookOpen className="w-12 h-12 mx-auto mb-4 opacity-50" />
              <p>No learning resources found</p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Create Dialog */}
      <Dialog 
        open={isCreateDialogOpen} 
        onOpenChange={(open) => {
          setIsCreateDialogOpen(open);
          if (!open) resetForm();
        }}
      >
        <DialogContent 
          className="max-w-2xl max-h-[90vh] overflow-y-auto"
        >

          <DialogHeader>
            <DialogTitle>Create Learning Resource</DialogTitle>
          </DialogHeader>
          
          <form onSubmit={handleCreateResource} className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="create-title">Title *</Label>
              <Input
                id="create-title"
                type="text"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                placeholder="Enter resource title"
                className="w-full"
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="create-description">Description</Label>
              <Input
                id="create-description"
                type="text"
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                placeholder="Enter resource description"
                className="w-full"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="create-type">Type</Label>
                <Select
                  value={formData.type}
                  onValueChange={(value) => setFormData({ ...formData, type: value })}
                >
                  <SelectTrigger id="create-type" className="w-full">
                    <SelectValue placeholder="Select type" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="article">Article</SelectItem>
                    <SelectItem value="video">Video</SelectItem>
                    <SelectItem value="course">Course</SelectItem>
                    <SelectItem value="tutorial">Tutorial</SelectItem>
                    <SelectItem value="documentation">Documentation</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="create-difficulty">Difficulty</Label>
                <Select
                  value={formData.difficulty}
                  onValueChange={(value) => setFormData({ ...formData, difficulty: value })}
                >
                  <SelectTrigger id="create-difficulty" className="w-full">
                    <SelectValue placeholder="Select difficulty" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="beginner">Beginner</SelectItem>
                    <SelectItem value="intermediate">Intermediate</SelectItem>
                    <SelectItem value="advanced">Advanced</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="create-url">URL *</Label>
              <Input
                id="create-url"
                type="url"
                value={formData.url}
                onChange={(e) => setFormData({ ...formData, url: e.target.value })}
                placeholder="https://example.com/resource"
                className="w-full"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="create-skill_id">Skill ID *</Label>
                <Input
                  id="create-skill_id"
                  type="number"
                  value={formData.skill_id}
                  onChange={(e) => setFormData({ ...formData, skill_id: e.target.value })}
                  placeholder="Enter skill ID"
                  className="w-full"
                  required
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="create-duration">Duration</Label>
                <Input
                  id="create-duration"
                  type="text"
                  value={formData.duration}
                  onChange={(e) => setFormData({ ...formData, duration: e.target.value })}
                  placeholder="e.g., 2 hours, 4 weeks"
                  className="w-full"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="create-provider">Provider</Label>
                <Input
                  id="create-provider"
                  type="text"
                  value={formData.provider}
                  onChange={(e) => setFormData({ ...formData, provider: e.target.value })}
                  placeholder="e.g., Udemy, Coursera"
                  className="w-full"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="create-cost">Cost</Label>
                <Select
                  value={formData.cost}
                  onValueChange={(value) => setFormData({ ...formData, cost: value })}
                >
                  <SelectTrigger id="create-cost" className="w-full">
                    <SelectValue placeholder="Select cost" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="free">Free</SelectItem>
                    <SelectItem value="paid">Paid</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="create-rating">Rating (0-5)</Label>
              <Input
                id="create-rating"
                type="number"
                min="0"
                max="5"
                step="0.1"
                value={formData.rating}
                onChange={(e) => setFormData({ ...formData, rating: parseFloat(e.target.value) || 0 })}
                className="w-full"
              />
            </div>

            <DialogFooter className="gap-2 pt-4">
              <Button 
                type="button"
                variant="outline" 
                onClick={() => {
                  setIsCreateDialogOpen(false);
                  resetForm();
                }}
              >
                <X className="w-4 h-4 mr-2" />
                Cancel
              </Button>
              <Button type="submit">
                <Save className="w-4 h-4 mr-2" />
                Create Resource
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>

      {/* Edit Dialog */}
      <Dialog 
        open={isEditDialogOpen} 
        onOpenChange={(open) => {
          setIsEditDialogOpen(open);
          if (!open) {
            setSelectedResource(null);
            resetForm();
          }
        }}
      >
        <DialogContent 
          className="max-w-2xl max-h-[90vh] overflow-y-auto"
        >

          <DialogHeader>
            <DialogTitle>Edit Learning Resource</DialogTitle>
          </DialogHeader>
          
          <form onSubmit={handleUpdateResource} className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="edit-title">Title *</Label>
              <Input
                id="edit-title"
                type="text"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                placeholder="Enter resource title"
                className="w-full"
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="edit-description">Description</Label>
              <Input
                id="edit-description"
                type="text"
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                placeholder="Enter resource description"
                className="w-full"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="edit-type">Type</Label>
                <Select
                  value={formData.type}
                  onValueChange={(value) => setFormData({ ...formData, type: value })}
                >
                  <SelectTrigger id="edit-type" className="w-full">
                    <SelectValue placeholder="Select type" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="article">Article</SelectItem>
                    <SelectItem value="video">Video</SelectItem>
                    <SelectItem value="course">Course</SelectItem>
                    <SelectItem value="tutorial">Tutorial</SelectItem>
                    <SelectItem value="documentation">Documentation</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="edit-difficulty">Difficulty</Label>
                <Select
                  value={formData.difficulty}
                  onValueChange={(value) => setFormData({ ...formData, difficulty: value })}
                >
                  <SelectTrigger id="edit-difficulty" className="w-full">
                    <SelectValue placeholder="Select difficulty" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="beginner">Beginner</SelectItem>
                    <SelectItem value="intermediate">Intermediate</SelectItem>
                    <SelectItem value="advanced">Advanced</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="edit-url">URL *</Label>
              <Input
                id="edit-url"
                type="url"
                value={formData.url}
                onChange={(e) => setFormData({ ...formData, url: e.target.value })}
                placeholder="https://example.com/resource"
                className="w-full"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="edit-skill_id">Skill ID *</Label>
                <Input
                  id="edit-skill_id"
                  type="number"
                  value={formData.skill_id}
                  onChange={(e) => setFormData({ ...formData, skill_id: e.target.value })}
                  placeholder="Enter skill ID"
                  className="w-full"
                  required
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="edit-duration">Duration</Label>
                <Input
                  id="edit-duration"
                  type="text"
                  value={formData.duration}
                  onChange={(e) => setFormData({ ...formData, duration: e.target.value })}
                  placeholder="e.g., 2 hours, 4 weeks"
                  className="w-full"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="edit-provider">Provider</Label>
                <Input
                  id="edit-provider"
                  type="text"
                  value={formData.provider}
                  onChange={(e) => setFormData({ ...formData, provider: e.target.value })}
                  placeholder="e.g., Udemy, Coursera"
                  className="w-full"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="edit-cost">Cost</Label>
                <Select
                  value={formData.cost}
                  onValueChange={(value) => setFormData({ ...formData, cost: value })}
                >
                  <SelectTrigger id="edit-cost" className="w-full">
                    <SelectValue placeholder="Select cost" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="free">Free</SelectItem>
                    <SelectItem value="paid">Paid</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="edit-rating">Rating (0-5)</Label>
              <Input
                id="edit-rating"
                type="number"
                min="0"
                max="5"
                step="0.1"
                value={formData.rating}
                onChange={(e) => setFormData({ ...formData, rating: parseFloat(e.target.value) || 0 })}
                className="w-full"
              />
            </div>

            <DialogFooter className="gap-2 pt-4">
              <Button 
                type="button"
                variant="outline" 
                onClick={() => {
                  setIsEditDialogOpen(false);
                  setSelectedResource(null);
                  resetForm();
                }}
              >
                <X className="w-4 h-4 mr-2" />
                Cancel
              </Button>
              <Button type="submit">
                <Save className="w-4 h-4 mr-2" />
                Update Resource
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}
